INSERT INTO public.photos VALUES (25750, 'Cementera Miraflores 1947', 'Imagen de las instalaciones de la fв”ңГӯbrica de "Cementos Portland Zaragoza S. A." sita en el antiguo barrio de Montemolв”ңВЎn, donde la piedra caliza y la arcilla eran industrialmente tratadas para convertirse en cemento. A la derecha, las oficinas de la direcciв”ңв”Ӯn de la empresa. A la izquierda, vista parcial del complejo cementero, del que destacan sus gemelas chimeneas. Fuente visual: Revista "Aragв”ңв”Ӯn", nв”¬в•‘ 203.', 1947, 1947, 1947, 'Anos 40', 'SAN JOSв”ңГ«', 41.63145000, -0.86343500, '0101000020E6100000A818E76F42A1EBBF9487855AD3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20520086585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20520086585.webp', 'https://www.flickr.com/photos/zaragozaantigua/20520086585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24950, 'Avenida de los Bearneses 1971', 'Mesa del jurado, presidido por el concejal Alfonso Solв”ңГӯns Serrano, del "II Concurso nacional de elegancia automovilв”ңВЎstica", organizado por la Escuela de Turismo de Zaragoza y patrocinado por Almacenes Gay. Este certamen, celebrado en mayo de 1971 durante las Fiestas de Primavera, tuvo una tercera ediciв”ңв”Ӯn al aв”ңв–’o siguiente, quedando suspendido en 1973 por motivo del fallecimiento de su principal organizador. En la imagen, el pв”ңв•‘blico congregado en la grada colocada en la avenida de los Bearneses del parque de Primo de Rivera, celebra la presencia de un histriв”ңв”Ӯnico grupo participante, al que no le falta el botijo. Mientras, los jurados beben cerveza, fuman y sonrв”ңВЎen.', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.63390100, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBF6BF3FFAA23D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33829068698.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33829068698.webp', 'https://www.flickr.com/photos/zaragozaantigua/33829068698/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26044, 'Cementos Portland 1955', 'Imagen en altura centrada en las instalaciones de Miraflores de la empresa "Cementos Portland Zaragoza, S.A.", que permite un interesante panorama del sureste de la ciudad. La captura se ha realizado desde la vertical de la carretera de Castellв”ңв”Ӯn, y la enorme cementera aparece flanqueada por dos lв”ңВЎneas ferroviarias: inmediata, la de Utrillas, con su correspondiente apeadero "Cementos"; hacia la izquierda, la lв”ңВЎnea hacia Barcelona, con la estaciв”ңв”Ӯn de Miraflores, y la recta zanja que se introduce despejada hasta el cruce con el camino de las Torres y la huerta de Miraflores. Un poco antes, pasa cerca de los pabellones de la Granja Agrв”ңВЎcola, el Grupo Agustв”ңВЎn Gericв”ңв”Ӯ, y el Grupo Puente Virrey-Rosellв”ңв”Ӯn. A la derecha, la chimenea y la fв”ңГӯbrica de briquetas de MFU, entre los campos de la Granja. A la izquierda, el camino de Miraflores y sus alabeados aterrazamientos en descenso hasta las vв”ңВЎas del tren, y al fondo, clarea la gran mole de la Residencia Josв”ңВ® Antonio, como si de un zigurat mesopotв”ңГӯmico se tratara. Fuente visual: Arxiu Nacional de Catalunya.', 1955, 1955, 1955, 'Anos 50', 'SAN JOSв”ңГ«', 41.63145000, -0.86343500, '0101000020E6100000A818E76F42A1EBBF9487855AD3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31595612412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31595612412.webp', 'https://www.flickr.com/photos/zaragozaantigua/31595612412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24000, 'Santiago Auserв”ңв”Ӯn 1987', 'Foto: Rodolfo Alonso. El cantante, compositor y guitarrista Santiago Auserв”ңв”Ӯn (Zaragoza, 1954), segundo por la izquierda, actuando entre los miembros del grupo Mв”ңГӯs Birras Mauricio Aznar y Miguel Mata, en el bar Paradв”ңВЎs de Zaragoza, durante las fiestas del Pilar de 1987. Este mв”ңв•‘sico formв”ңв”Ӯ parte del grupo Radio Futura y continuв”ңв”Ӯ su carrera con el nombre de Juan Perro. En 2015 presentв”ңв”Ӯ su tesis doctoral "Mв”ңв•‘sica en los fundamentos del logos", sobre la mв”ңв•‘sica y el pensamiento griego antiguo. Fuente visual: www.facebook.com/zgz80s/photos/a.127459403989874.22917.12...', 1987, 1987, 1987, 'Anos 80', 'SAN JOSв”ңГ«', 41.64187300, -0.88434600, '0101000020E610000039268BFB8F4CECBFBB97FBE428D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21696092939.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21696092939.webp', 'https://www.flickr.com/photos/zaragozaantigua/21696092939/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24403, 'C.в”¬в•‘ de las Torres 1976', 'Imagen donde domina la achaflanada fachada del convento de nueva planta de la "Congregaciв”ңв”Ӯn de las Hermanas Oblatas del Santв”ңВЎsimo Redentor", construido en los aв”ңв–’os 60 en la esquina de la plaza del doctor Albert Schweitzer con el camino de las Torres. A la derecha, la acequia de las Adulas del Huerva, y la chimenea de la fв”ңГӯbrica textil "Lanera Aragonesa". Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSв”ңГ«', 41.64255700, -0.88212300, '0101000020E6100000C09481035A3AECBF6E68CA4E3FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29545286474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29545286474.webp', 'https://www.flickr.com/photos/zaragozaantigua/29545286474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24424, 'PP. Agustinos y cв”ңГӯnidos c.1945', 'Curiosa imagen centrada en un recoleto espacio de la zona mв”ңГӯs norteв”ңв–’a del convento-colegio de los PP. Agustinos en el camino de las Torres, capturada desde donde estaba proyectado erigir la gran agustina iglesia, cosa que finalmente no se realizarв”ңВЎa. El muro perimetral en ladrillo del convento-colegio aparece interrumpido bruscamente junto a una pequeв”ңв–’a y feraz zona ajardinada que incluв”ңВЎa una antigua "torre" que fue de Mercadal, con espadaв”ңв–’a propia, y que quedв”ңв”Ӯ incluida en el moderno recinto agustino, como muestra el padre agustino que posa entre dos perros guardianes. Junto a esta torre fluв”ңВЎa un ramal derivado de la inmediata gran acequia de las Adulas, o de San Josв”ңВ®, para riego de los cultivos de Miraflores. A la derecha sobresale la chimenea de la antigua fв”ңГӯbrica de hilados denominada "Lanera Aragonesa", en el cercano camino de las Torres. Al fondo, de enfre la foresta emerge perfilado el remate de la fachada del antiguo convento de las MM. Oblatas en el paseo de las Damas. Fuente visual: foto Juan Mora Insa, en Archivo Josв”ңВ® Marв”ңВЎa Ballestв”ңВЎn Miguel.', 1945, 1945, 1945, 'Anos 40', 'SAN JOSв”ңГ«', 41.64222100, -0.88124300, '0101000020E610000094861A852433ECBFF7E6374C34D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40316980895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40316980895.webp', 'https://www.flickr.com/photos/zaragozaantigua/40316980895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21161, 'Apeadero Miraflores 1894', 'Apeadero de Miraflores al poco de ser inaugurado en el mes de julio de ese aв”ңв–’o, con posado de sus primeros habitantes. Esta infraestructura ferroviaria acortaba y agilizaba notablemente el trв”ңГӯfico de trenes entre Madrid y Barcelona, y unos aв”ңв–’os despuв”ңВ®s permitirв”ңГӯ tambiв”ңВ®n el enlace con la lв”ңВЎnea de Utrillas. Este original y pequeв”ңв–’o edificio serв”ңГӯ luego ampliado, y otros edificios e instalaciones surgirв”ңГӯn en el lugar, conforme la lв”ңВЎnea fuera desarrollando servicios. Fuente visual: AVV. San Josв”ңВ®.', 1894, 1894, 1894, 'Siglo XIX', 'SAN JOSв”ңГ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20355205536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20355205536.webp', 'https://www.flickr.com/photos/zaragozaantigua/20355205536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21331, 'Estaciв”ңв”Ӯn de Utrillas 1908', 'En la estaciв”ңв”Ӯn de Zaragoza de la sociedad Minas y Ferrocarril de Utrillas, antigua de Cappa, unos operarios posan junto a uno de los cinco coches de viajeros de 1в”¬В¬ y 2в”¬В¬ clase construidos en los talleres de Carde y Escoriaza, en servicio para viajeros en la lв”ңВЎnea que habв”ңВЎa sido (re) inaugurada en 1904. Al fondo y a la izquierda, el cocherв”ңв”Ӯn donde estos coches eran guardados. Los edificios principales de la estaciв”ңв”Ӯn quedaban justo a la derecha, fuera de plano. Hacia el fondo, muros que delimitaban la vecina huerta de Izuzquiza incrustada entre el camino de Cabaldв”ңв”Ӯs (izquierda) y la calle de Miguel Servet (derecha) en el tramo entre las calles de la Mina, la Higuera, y Belchite.', 1908, 1908, 1908, 'Anos 1900', 'SAN JOSв”ңГ«', 41.64081600, -0.86843400, '0101000020E6100000BB80971936CAEBBF7460394206D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50805924853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50805924853.webp', 'https://www.flickr.com/photos/zaragozaantigua/50805924853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21367, 'La Granja c.1910', 'Foto Antonio Arguas Perdiguer. Vista desde dentro de la puerta de entrada a la Granja Agrв”ңВЎcola en el camino del Bajo Aragв”ңв”Ӯn. Al fondo, "Villa Asunciв”ңв”Ӯn" de Miguel Larrinaga, con su original apariencia diseв”ңв–’ada por Fв”ңВ®lix Navarro, que muriв”ңв”Ӯ en 1911 y fue sustituido por el arquitecto Fernando de Escondrillas, que le dio su propio toque en el acabado final.', 1910, 1910, 1910, 'Anos 10', 'SAN JOSв”ңГ«', 41.63810900, -0.86501200, '0101000020E6100000BFB854A52DAEEBBF4224438EADD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14994220090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14994220090.webp', 'https://www.flickr.com/photos/zaragozaantigua/14994220090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24953, 'Cabezo de Buenavista 1909', 'Imagen centrada parcialmente en la puerta de ingreso a la casa del guarda del Cabezo de Buenavista, donde una singular rondalla posa, junto a la guardesa e hijos, y un par de seв”ңв–’oras con llamativas bufandas, durante una costumbrista visita a este lejano paraje de la ciudad que se convirtiв”ңв”Ӯ con el tiempo en un antropolв”ңв”Ӯgico reportaje fotogrв”ңГӯfico. Al fondo y a la derecha, despejado entorno ascendente hacia el Cabezo, tradicionalmente despoblado de vegetaciв”ңв”Ӯn hasta la transformaciв”ңв”Ӯn acometida aв”ңв–’os despuв”ңВ®s durante la configuraciв”ңв”Ӯn del parque de Buenavista.', 1909, 1909, 1909, 'Anos 1900', 'UNIVERSIDAD', 41.63287700, -0.89263900, '0101000020E6100000E84A04AA7F90ECBFFFB1101D02D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48528884276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48528884276.webp', 'https://www.flickr.com/photos/zaragozaantigua/48528884276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21387, 'Estaciв”ңв”Ӯn de Utrillas 1917', 'La Europa continental sigue en guerra, y el crisol que la alimenta es abastecido hasta por el ferrocarril de Utrillas, que transporta carbв”ңв”Ӯn, abonos minerales, cementos, madera, y otros materiales estratв”ңВ®gicos hacia los paв”ңВЎses en conflicto bв”ңВ®lico, porque la guerra es, fundamentalmente, otra forma de hacer negocios. Por ello, el personal de la lв”ңВЎnea aumenta en nв”ңв•‘mero, y en la terminal de Zaragoza, ante la boca de entrada a uno de los depв”ңв”Ӯsitos de locomotoras, posan en un antropolв”ңв”Ӯgico retrato colectivo. La mayorв”ңВЎa de ellos vivв”ңВЎan en las inmediaciones de la Estaciв”ңв”Ӯn. De estos monumentales Depв”ңв”Ӯsitos de Locomotoras, sin mediar una guerra, sв”ңв”Ӯlo quedaron en pie los arcos de entrada hasta mediados de los aв”ңв–’os 90. Luego, fuese, y no hubo nada. En esta misma ubicaciв”ңв”Ӯn hoy queda su etв”ңВ®reo recuerdo en el "Parque de los Arcos", al lado de la trasplantada Chimenea de la Estaciв”ңв”Ӯn. Este parque conserva la planta semicircular del Depв”ңв”Ӯsito, y ya estв”ңГӯ. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/10799465686/in...', 1917, 1917, 1917, 'Anos 10', 'SAN JOSв”ңГ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19646874703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19646874703.webp', 'https://www.flickr.com/photos/zaragozaantigua/19646874703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21438, 'Ctra. de Castellв”ңв”Ӯn c.1910', 'Imagen centrada en la novв”ңВЎsima "Villa Asunciв”ңв”Ӯn", o vivienda unifamiliar impulsada por el vizcaв”ңВЎno Miguel Larrinaga y diseв”ңв–’ada por el arquitecto Fв”ңВ®lix Navarro Pв”ңВ®rez con aires neorrenacentistas expresados en formas eclв”ңВ®cticas y simbolistas. Esta gran casa fue construida en una parcela dentro de los extensos terrenos que este naviero poseв”ңВЎa en la carretera de Zaragoza a Castellв”ңв”Ӯn, confrontando desde la estaciв”ңв”Ӯn de Cappa y hasta la Granja Agrв”ңВЎcola, y con la direcciв”ңв”Ӯn postal de Montemolв”ңВЎn nв”¬в•‘ 95. La original cв”ңв•‘pula central que remata en la imagen la caja de la escalera serв”ңВЎa pocos aв”ңв–’os despuв”ңВ®s sustituida por un cimborrio de planta octogonal diseв”ңв–’ado por el arquitecto Fernando de Escondrillas, La denominaciв”ңв”Ӯn de esta villa respondв”ңВЎa al nombre de Asunciв”ңв”Ӯn Clavero, la turolense esposa de Larrinaga, cuya muerte en 1939 determinв”ңв”Ӯ que esta casa nunca fuera ocupada por la familia Larrinaga-Clavero. Sin habitar durante muchos aв”ңв–’os, durante la guerra civil de 1936-39 fue habilitada ocasionalmente como residencia militar por los nacionalistas. Al principio de los aв”ңв–’os 40 la propiedad recayв”ңв”Ӯ en las manos de la empresa Guiral Industrias Elв”ңВ®ctricas SA (GIESA), que en 1942 se la vendiв”ңв”Ӯ a la Compaв”ңв–’в”ңВЎa de Marв”ңВЎa, que pocos aв”ңв–’os despuв”ңВ®s abrieron aquв”ңВЎ el marianista Colegio de Santa Marв”ңВЎa del Pilar de Zaragoza, luego reconvertido en Casa de Formaciв”ңв”Ӯn. Fuente visual: AMZ.', 1910, 1910, 1910, 'Anos 10', 'SAN JOSв”ңГ«', 41.63841500, -0.86449700, '0101000020E6100000FFAECF9CF5A9EBBF4F232D95B7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44503596502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44503596502.webp', 'https://www.flickr.com/photos/zaragozaantigua/44503596502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21464, 'Miguel Servet c.1912', 'Imagen de una de las jardineras en servicio en los tranvв”ңВЎas de Zaragoza, estacionada en las vв”ңВЎas de acceso al "cocherв”ңв”Ӯn" de la empresa sito en la antigua carretera de Zaragoza a Castellв”ңв”Ӯn o moderna calle de Miguel Servet. Tras el coche, edificio de la zona de talleres, oficinas y almacenes de la empresa. Estas unidades jardineras tenв”ңВЎan un uso estacional, en funciв”ңв”Ӯn del singular clima zaragozano, que en principio podrв”ңВЎa abarcar desde la primavera hasta el otoв”ңв–’o. Este carв”ңГӯcter estacional fue lo que determinв”ңв”Ӯ que aв”ңв–’os mв”ңГӯs tarde los vehв”ңВЎculos jardinera (tanto los remolques como las motoras) fueran remodelados para hacerlos cerrados, в”ңв•‘tiles asв”ңВЎ durante todo el aв”ңв–’o.', 1912, 1912, 1912, 'Anos 10', 'SAN JOSв”ңГ«', 41.63954900, -0.86676100, '0101000020E61000001D588E9081BCEBBF4298DBBDDCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53453925922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53453925922.webp', 'https://www.flickr.com/photos/zaragozaantigua/53453925922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21542, 'Estaciв”ңв”Ӯn de Utrillas c.1925', 'Posado de directivos y empeados en torno a la locomotora nв”ңв•‘mero 51, bautizada "Baselga" en homenaje al local prв”ңв”Ӯcer Mariano Baselga, fundador de la sociedad Minas y Ferrocarriles de Utrillas. Este pedazo de cacharro habв”ңВЎa venido de Philadelphia (Estados Unidos de Norteamв”ңВ®rica), y tenв”ңВЎa como nombre de fв”ңГӯbrica "Mallet 030+030 T Baldwin 1917-45631". Podв”ңВЎa remolcar composiciones (convoyes) de hasta 25 unidades. En el Depв”ңв”Ӯsito de Locomotoras de la Terminal de Zaragoza de aquellos aв”ңв–’os cabв”ңВЎan 12 como в”ңВ®sta, o similares. Menudo espectв”ңГӯculo sonoro. Todo esto sucedв”ңВЎa muy cerca de donde hoy se puede escuchar el estacional crotoreo, o claqueteo, de los picos de las cigв”ңв•қeв”ңв–’as de la trasplantada chimenea de la antigua Utrillas.', 1925, 1925, 1925, 'Anos 20', 'SAN JOSв”ңГ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20078055910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20078055910.webp', 'https://www.flickr.com/photos/zaragozaantigua/20078055910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21545, 'Fв”ңГӯbrica Briquetas Utrillas 1923', 'Imagen de la fв”ңГӯbrica de briquetas, o aglomerados de carbв”ңв”Ӯn en forma de pastillas utilizadas como combustible de locomotoras, prв”ңв”Ӯxima a la Estaciв”ңв”Ӯn de Utrillas. La instalaciв”ңв”Ӯn estв”ңГӯ funcional, a plena actividad. Fuente visual: "Memoria de prв”ңГӯcticas de 1923 del alumno Santiago Baselga, de la Escuela Especial de Minas de Madrid", Hemeroteca de la Escuela Tв”ңВ®cnica Superior de Ingenieros de Minas de la Universidad Politв”ңВ®cnica de Madrid.', 1923, 1923, 1923, 'Anos 20', 'SAN JOSв”ңГ«', 41.63586000, -0.86688900, '0101000020E61000007C6308008EBDEBBFD36A48DC63D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20131353328.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20131353328.webp', 'https://www.flickr.com/photos/zaragozaantigua/20131353328/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21878, 'Calle de Miguel Servet 1936', 'Imagen de la "Villa Asunciв”ңв”Ӯn" que fuera construida a principios de siglo para ser la definitiva casa de la pudiente familia Larrinaga-Clavero, residente en Liverpool por motivos empresariales. Diseв”ңв–’ada por el arquitecto Fв”ңВ®lix Navarro Pв”ңВ®rez, tras su muerte y a requerimiento del propietario la casa fue modificada sustancialmente por el arquitecto Fernando de Escondrillas: por ejemplo, las torrecillas angulares fueron recrecidas en altura y redefinidas sus lв”ңВЎneas y remate, y la original cв”ңв•‘pula central sobre la caja de la escalera fue sustituida por un cimborrio de planta octogonal. Este es el aspecto que presenta en esta fotografв”ңВЎa. Tras el fallido golpe de Estado de julio de 1936 y el comienzo de la subsiguiente guerra civil, una iniciativa del alcalde Miguel Lв”ңв”Ӯpez de Gera proyectв”ңв”Ӯ establecer en esta gran casa una "escuela de reeducaciв”ңв”Ӯn profesional para los mutilados de la guerra", si bien esta idea no cuajв”ңв”Ӯ. Durante la guerra esta casa fue militarizada al ser ocupada por el ejв”ңВ®rcito nacionalista como residencia temporal de tropas fascistas italianas que transitaban por la ciudad, como sucediв”ңв”Ӯ tambiв”ңВ®n con otros destacados espacios y edificios de Zaragoza. En 1939 falleciв”ңв”Ӯ Asunciв”ңв”Ӯn Clavero, y Miguel Larrinaga ya no regresarв”ңВЎa nunca a la ciudad. Por ello, poco despuв”ңВ®s venderв”ңВЎa la casa a la empresa GIESA, que estableciв”ңв”Ӯ en esa zona su nueva y gran factorв”ңВЎa. Fuente visual: "Aragв”ңв”Ӯn: revista grв”ңГӯfica de cultura aragonesa" (1936).', 1936, 1936, 1936, 'Anos 30', 'SAN JOSв”ңГ«', 41.63841500, -0.86449700, '0101000020E6100000FFAECF9CF5A9EBBF4F232D95B7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44578007961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44578007961.webp', 'https://www.flickr.com/photos/zaragozaantigua/44578007961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21927, 'Vista aв”ңВ®rea (Este) c.1949', 'Finales aв”ңв–’os 40 (s. XX). Posible aв”ңВ®rea vista viniendo volando desde la Cartuja Baja, y observando un pedazo de la Zaragoza del momento. Mil y un detalles sobre los que hablar. Por ejemplo, en el extremo inferior izquierdo queda el quesito que forman Miguel Servet con la Av. San Josв”ңВ®. Tras la aguja de las Hermanitas de los Pobres, los campos de Miraflores. En Miguel Servet, la enorme estructura del Macelo municipal sigue siendo extraordinaria. Enfrente, la calle Matadero. Y cerca, el Frontв”ңв”Ӯn Zaragozano. El Camino rural que hoy es Compromiso de Caspe conduce a eso, a los campos de lo que poco despuв”ңВ®s comenzarв”ңГӯ a ser identificado como Las Fuentes. Junto al Huerva, insв”ңв”Ӯlita visiв”ңв”Ӯn del Cuartel de Intendencia que antes fue Penal, y que aв”ңв•‘n antes fue Convento de S. Josв”ңВ®. Al fondo, tras cruzar el Ebro, la Zaragoza del otro lado, bastante mв”ңГӯs lejos de los montes de Juslibol que en la actualidad. Et cetera.', 1949, 1949, 1949, 'Anos 40', 'SAN JOSв”ңГ«', 41.64201800, -0.86778000, '0101000020E6100000A2EE0390DAC4EBBFBFB854A52DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14860286855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14860286855.webp', 'https://www.flickr.com/photos/zaragozaantigua/14860286855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21944, 'Colegio Marianistas 1946', 'El 7 de octubre de 1946 comenzв”ңв”Ӯ el primer curso del Colegio de Santa Marв”ңВЎa del Pilar (Marianistas) en el palacio de Larrinaga, anterior propiedad de GIESA, que se las vendiв”ңв”Ӯ por 2.195.000 de pesetas a pagar en cinco aв”ңв–’os. Los muebles y enseres fueron trasladados desde la anterior residencia de estos religiosos, sito en la calle de San Pablo. En la imagen, capturada en la zona trasera del palacio, con las nuevas instalaciones fabriles de GIESA asomando por la derecha, posado del original equipo de docentes, encabezado por el director Esteban Ichaso: Jesв”ңв•‘s Arcauz, Eugenio salazar, Josв”ңВ® Marв”ңВЎa Santamarв”ңВЎa y Josв”ңВ® Antonio Fernв”ңГӯndez; el capellв”ңГӯn, Fв”ңВ®lix Fernв”ңГӯndez; y 8 de los 17 alumnos inscritos, presentes a la hora de tomarla fotografв”ңВЎa.', 1946, 1946, 1946, 'Anos 40', 'SAN JOSв”ңГ«', 41.63834300, -0.86441300, '0101000020E61000008997A77345A9EBBFB5503239B5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15740889556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15740889556.webp', 'https://www.flickr.com/photos/zaragozaantigua/15740889556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22014, 'Calle de Miguel Servet c.1946', 'Imagen de Villa Asunciв”ңв”Ӯn que fuera construida a principios de siglo para la pudiente familia Larrinaga-Clavero. Diseв”ңв–’ada originalmente por el arquitecto Fв”ңВ®lix Navarro, tras su muerte y a requerimiento del propietario la casa fue modificada sustancialmente por el arquitecto Fernando de Escondrillas. Tras el fallido golpe de Estado de julio de 1936 y el comienzo de la subsiguiente guerra civil, el alcalde Miguel Lв”ңв”Ӯpez de Gera proyectв”ңв”Ӯ establecer aquв”ңВЎ una "escuela de reeducaciв”ңв”Ӯn profesional para los mutilados de la guerra", que no cuajв”ңв”Ӯ. Durante la guerra la casa fue militarizada por el ejв”ңВ®rcito nacionalista para dar cabida a altos mandos en su temporal paso por la ciudad, incluyendo fascistas italianos. En 1939 falleciв”ңв”Ӯ Asunciв”ңв”Ӯn Clavero, y en 1942 Miguel Larrinaga vendiв”ңв”Ӯ la casa a la empresa GIESA, que la habilitв”ңв”Ӯ como dependencias administrativas y oficinas. En 1946, fue nuevamente vendida, en esta ocasiв”ңв”Ӯn a los Padres Marianistas para ubicar en sus dependencias el colegio Santa Marв”ңВЎa del Pilar. En la imagen, vista de la fachada e ingreso principal a la casa desde la calle de Miguel Servet, en un entorno bien despejado y luminoso.', 1946, 1946, 1946, 'Anos 40', 'SAN JOSв”ңГ«', 41.63831400, -0.86451800, '0101000020E6100000DDB419A721AAEBBF1B4AED45B4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48430429356.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48430429356.webp', 'https://www.flickr.com/photos/zaragozaantigua/48430429356/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22022, 'Casa de Larrinaga c.1942', 'Imagen capturada en la parte trasera de Villa Asunciв”ңв”Ӯn o casa de Miguel Larrinaga, con una incursiв”ңв”Ӯn visual, a la derecha, de las obras de construcciв”ңв”Ӯn de la nueva fв”ңГӯbrica de Guiral Industrias Elв”ңВ®ctricas S.A., cuya conclusiв”ңв”Ӯn se prolongв”ңв”Ӯ hasta 1945. Entre la casa y las obras, al fondo y al otro lado de la calle de Miguel Servet, las cocheras de los tranvв”ңВЎas. En primer tв”ңВ®rmino, la sombra del retratador y su artefacto, parcialmente retratados.', 1942, 1942, 1942, 'Anos 40', 'SAN JOSв”ңГ«', 41.63861100, -0.86396000, '0101000020E61000004BAB21718FA5EBBFD4EE5701BED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50018662068.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50018662068.webp', 'https://www.flickr.com/photos/zaragozaantigua/50018662068/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22093, 'Estaciв”ңв”Ӯn de Utrillas c.1959', 'Estaciв”ңв”Ӯn terminal de Zaragoza de la compaв”ңв–’в”ңВЎa Minas y Ferrocarriles de Utrillas. Vista desde el andв”ңВ®n principal, el mar de vв”ңВЎas, sus almacenes y edificios auxiliares. Aв”ңв–’os despuв”ңВ®s, tras su clausura como lв”ңВЎnea todo este patrimonio ferroviario rodante serв”ңГӯ vendido a precio de chatarra, o directamente desguazado, y la estaciв”ңв”Ӯn quedarв”ңГӯ varada en el tiempo por un cuarto de siglo, y luego urbanizada para otros usos. Es muy de nuestra ciudad que en cualquier memoria de la historia ferroviaria espaв”ңв–’ola y europea aparezcan decenas de referencias a locomotoras que dieron servicio en la humilde lв”ңВЎnea Utrillas-Zaragoza, y que no quede ni rastro de ellas en el lugar que fue terminal y estaciв”ңв”Ӯn mв”ңГӯs grande de la lв”ңВЎnea. Ni siquiera ha habido ocurrencias del tipo "parque temв”ңГӯtico del tren". Nada. Cero. Al fondo, en el centro de la imagen, y sobre la lв”ңВЎnea del horizonte, sobresale la aguja del Hogar San Josв”ңВ® de las HH. de los Ancianos Desamparados. Fuente visual: Foto Christian Schnabel.', 1959, 1959, 1959, 'Anos 50', 'SAN JOSв”ңГ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19694146654.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19694146654.webp', 'https://www.flickr.com/photos/zaragozaantigua/19694146654/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22096, 'Estaciв”ңв”Ӯn de Miraflores c.1959', 'Imagen de la estaciв”ңв”Ӯn de Miraflores en sus activos aв”ңв–’os como empalme con la lв”ңВЎnea Madrid-Barcelona para los trenes carboneros de la lв”ңВЎnea Utrillas-Zaragoza. Fuente visual: AVV. San Josв”ңВ®.', 1959, 1959, 1959, 'Anos 50', 'SAN JOSв”ңГ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20134934869.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20134934869.webp', 'https://www.flickr.com/photos/zaragozaantigua/20134934869/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22097, 'Estaciв”ңв”Ӯn de Utrillas c.1959', 'Estaciв”ңв”Ӯn terminal de Zaragoza de la compaв”ңв–’в”ңВЎa Minas y Ferrocarriles de Utrillas. En el centro, el edificio principal de la estaciв”ңв”Ӯn. A la izquierda, acceso al mar de vв”ңВЎas y a los depв”ңв”Ӯsitos donde se guardaban las locomotoras. Fuente visual: Foto Christian Schnabel.', 1959, 1959, 1959, 'Anos 50', 'SAN JOSв”ңГ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20318902021.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20318902021.webp', 'https://www.flickr.com/photos/zaragozaantigua/20318902021/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22108, 'Torre Ramona 1958', '"Torre Ramona. Parcelas del Catastro de Rв”ңв•‘stica del Tв”ңВ®rmino Municipal de Zaragoza", abril de 1958. Plano de la zona conocida como Torre Ramona, en la barriada de Las Fuentes. Abajo, la Facultad de Veterinaria.', 1958, 1958, 1958, 'Anos 50', 'SAN JOSв”ңГ«', 41.64198500, -0.86553900, '0101000020E61000008F334DD87EB2EBBFE3C281902CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21457276382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21457276382.webp', 'https://www.flickr.com/photos/zaragozaantigua/21457276382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23371, 'Almenara de La Sagrada 1929', 'Imagen de la almenara de riego de Nuestra Seв”ңв–’ora de La Sagrada en el Canal Imperial de Aragв”ңв”Ӯn a su paso por Garrapinillos. Fuente visual: revista de la Confederaciв”ңв”Ӯn Sindical Hidrogrв”ңГӯfica del Ebro.', 1929, 1929, 1929, 'Anos 20', NULL, 41.67502600, -1.03376700, '0101000020E6100000CCF10A444F8AF0BF90F9804067D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19527238324.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19527238324.webp', 'https://www.flickr.com/photos/zaragozaantigua/19527238324/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22156, 'Calle Miguel Servet 1954', 'Vista aв”ңВ®rea de la calle de Miguel Servet (arriba a la izquierda) y su entorno. Al fondo a la izquierda, la plaza de ingreso a la estaciв”ңв”Ӯn de ferrocarril de Utrillas. A la derecha, el reformatorio del Buen Pastor en Torre Ramona. Junto al palacio de Larrinaga, la factorв”ңВЎa GIESA. En primer plano, construcciв”ңв”Ӯn de la nueva fв”ңГӯbrica CEFA. Fuente visual: Arxiu Nacional de Catalunya.', 1954, 1954, 1954, 'Anos 50', 'SAN JOSв”ңГ«', 41.63954500, -0.86504600, '0101000020E6100000C423F1F274AEEBBF00A94D9CDCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30291244463.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30291244463.webp', 'https://www.flickr.com/photos/zaragozaantigua/30291244463/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22158, 'Calle de Guiral 1958', 'Imagen del trolebв”ңв•‘s nв”¬в•‘ 39, construido en Zaragoza para dar servicio a la lв”ңВЎnea del Barrio de Jesв”ңв•‘s. La captura se ha realizado en la calle de Joaquв”ңВЎn Guiral, al poco de salir de las cocheras de los trolebuses, que quedan a la izquierda, fuera de plano. Al fondo, la fachada principal de la fв”ңГӯbrica GIESA. Fuente visual: TUZSA.', 1958, 1958, 1958, 'Anos 50', 'SAN JOSв”ңГ«', 41.63948300, -0.86508800, '0101000020E61000007F2F8507CDAEEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30499112050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30499112050.webp', 'https://www.flickr.com/photos/zaragozaantigua/30499112050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22162, 'Calle Miguel Servet 1954', 'Vista aв”ңВ®rea de la calle de Miguel Servet, con la huerta de Las Fuentes al fondo. En el centro, la factorв”ңВЎa GIESA. A su derecha, vista parcial del palacio de Larrinaga. Abajo a la izquierda, las cocheras de los Tranvв”ңВЎas de Zaragoza. A la derecha, las carboneras de la estaciв”ңв”Ӯn de ferrocarril de Utrillas, cuyas vв”ңВЎas se ven abajo. Fuente visual: Arxiu Nacional de Catalunya.', 1954, 1954, 1954, 'Anos 50', 'SAN JOSв”ңГ«', 41.63948300, -0.86508800, '0101000020E61000007F2F8507CDAEEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30730817080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30730817080.webp', 'https://www.flickr.com/photos/zaragozaantigua/30730817080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22184, 'Miguel Servet 1953', 'Imagen capturada sobrevolando el entorno de la calle Miguel Servet con vistas de las instalaciones de Guiral Industrias Elв”ңВ®ctricas S.A. (GIESA), aв”ңв•‘n sin su referencial atalaya en el extremo noroccidental del largo pabellв”ңв”Ӯn de su fachada principal. A su derecha, tampoco figura la Harinera de Azв”ңв”Ӯn. Al fondo, el edificio del Reformatorio del Buen Pastor. Al otro lado de Miguel Servet, el depв”ңв”Ӯsito de carbв”ңв”Ӯn de la estaciв”ңв”Ӯn de ferrocarril de Utrillas aв”ңв•‘n no ha sido ampliado con nuevos reservorios. A su izquierda, el perв”ңВЎmetro averjado anuncia el ingreso principal a la antigua Granja Agrв”ңВЎcola, ya despojada de sus funciones experimentales; tal vez por eso la puerta estв”ңГӯ abierta. Por la portaza principal de GIESA, un camino de hierro comunicaba por ferrocarril con la estaciв”ңв”Ӯn de Utrillas para dar salida a las mercaderв”ңВЎas producidas. Una unidad tranviaria de la lв”ңВЎnea "Bajo Aragв”ңв”Ӯn" se encamina hacia la plaza de San Miguel, junto al hotelito de Larrinaga reconvertido en Colegio de Santa Marв”ңВЎa del Pilar de los marianistas, pendiente de construir los traseros pabellones, y el cerrado que lo salvaguarde de ingresos no deseados. Fuente visual: Arxiu Nacional de Catalunya', 1953, 1953, 1953, 'Anos 50', 'SAN JOSв”ңГ«', 41.63915200, -0.86484900, '0101000020E6100000444E5FCFD7ACEBBF259694BBCFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32003698102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32003698102.webp', 'https://www.flickr.com/photos/zaragozaantigua/32003698102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22340, 'Estaciв”ңв”Ӯn de Utrillas 1965', 'Imagen capturada un aв”ңв–’o antes del cierre decretado de la lв”ңВЎnea de Zaragoza a Utrillas. La capacidad del Depв”ңв”Ӯsito de locomotoras de la Estaciв”ңв”Ӯn de Zaragoza, de las 12 unidades del principio, fue ampliada hasta las 16 de la imagen, junto a la placa giratoria del Depв”ңв”Ӯsito. La locomotora nв”¬в•‘ 207, descansando al lado de los operarios, a la derecha, fue la que protagonizв”ңв”Ӯ el viaje de clausura de la lв”ңВЎnea. A las 8 de la maв”ңв–’ana del sв”ңГӯbado dв”ңВЎa 15 de enero de 1966 el jefe de la estaciв”ңв”Ӯn de Utrillas-Montalbв”ңГӯn dio la salida oficial a la в”ңв•‘ltima composiciв”ңв”Ӯn, mixta con vagones cargados de carbв”ңв”Ӯn, coche de viajeros, furgones y otros carruajes. Posteriormente, circulв”ңв”Ӯ la locomotora nв”¬в•‘ 7 (en primer plano), con furgв”ңв”Ӯn y plataformas, para ultimar facturaciones que todavв”ңВЎa llegaban desde Miraflores para los pueblos de la lв”ңВЎnea, y para ir retirando materiales de las estaciones de la lв”ңВЎnea. El 31 de marzo de 1966 FEVE (Ferrocarriles Espaв”ңв–’oles de Vв”ңВЎa Estrecha) colgв”ңв”Ӯ el cartel del cierre total. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9305907744/in/...', 1965, 1965, 1965, 'Anos 60', 'SAN JOSв”ңГ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20077268210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20077268210.webp', 'https://www.flickr.com/photos/zaragozaantigua/20077268210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22539, 'Miguel Servet 1972', 'Vehв”ңВЎculo-grв”ңв•‘a para asistencia a unidades de Tranvв”ңВЎa averiadas, en el entorno de las cocheras ubicadas en Miguel Servet. La inequв”ңВЎvoca presencia del Palacio de Larrinaga, al fondo, nos sitв”ңв•‘a perfectamente. En la actualidad esta zona es una gran calle peatonal entre las calles Bubierca y Principado de Morea, la Plaza Sanz Briz y Miguel Servet. Fuente visual: www.flickr.com/photos/jhm0284/5813100892/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'SAN JOSв”ңГ«', 41.63794500, -0.86537700, '0101000020E61000002BBD361B2BB1EBBFC8D2872EA8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14892217061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14892217061.webp', 'https://www.flickr.com/photos/zaragozaantigua/14892217061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22625, 'Camino de Cabaldв”ңв”Ӯs 1971', 'Imagen tomada desde altura en el Camino de Cabaldв”ңв”Ӯs del notable impacto de la nueva urbanizaciв”ңв”Ӯn que la "Inmobiliaria Rв”ңВЎo Ebro" habв”ңВЎa promovido al final de la calle Castelar. A la izquierda, aspecto de las abandonadas instalaciones de la estaciв”ңв”Ӯn de Utrillas, con una interesante visual del semicircular depв”ңв”Ӯsito de locomotoras aв”ңв•‘n con el tejado casi intacto. Hacia la derecha, el Camino de Cabaldв”ңв”Ӯs parece terminar, pero sв”ңв”Ӯlo se convierte en una pista que se aventura entre campos de cultivo de herbв”ңГӯceas. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1971, 1971, 1971, 'Anos 70', 'SAN JOSв”ңГ«', 41.63978100, -0.86881000, '0101000020E610000021020EA14ACDEBBF14CD0358E4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19921982094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19921982094.webp', 'https://www.flickr.com/photos/zaragozaantigua/19921982094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24954, 'Parque Grande 1976', 'Curiosa postal publicitaria de Residencial "Parque Ciudad", la gran manzana de nuevos bloques de viviendas construidas donde estuviera el gran complejo de la Editorial Luis Vives, entre el paseo de Fernando el Catв”ңв”Ӯlico nв”¬в•‘ 59-71 y la calle de Luis Vives (la nueva calle abierta ante el rв”ңВЎo todavв”ңВЎa no tenв”ңВЎa nombre). Se trata de una tв”ңВЎpica vista del parque tomada desde la altura del Cabezo de Buenavista, a los pies del Monumento al Rey Alfonso I el Batallador, a la que se le ha impostado un dibujo de la nueva residencial de forma un poco gruesa, tanto por altura como por anchura, pues eclipsa a los bloques del в”ңв•‘ltimo tramo de los pares del paseo. Para remarcar la ubicaciв”ңв”Ӯn, una indicativa mano "pop" seв”ңв–’ala el objeto de promociв”ңв”Ӯn.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63456900, -0.89453800, '0101000020E61000009AEFE0270EA0ECBF1807978E39D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50803178642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50803178642.webp', 'https://www.flickr.com/photos/zaragozaantigua/50803178642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22626, 'Camino de Cabaldв”ңв”Ӯs 1975', 'Un Seat 124 y una moto no-GP transitan por un terroso Camino de Cabaldв”ңв”Ӯs, mientras un raso rebaв”ңв–’o se abastece de agua y ramonea en terrenos de la antigua Granja Agrв”ңВЎcola Experimental, abandonada desde 1943. El pastor y un vecino, como Tip y Coll, hablando del Gobierno. A la derecha, un campo panizo. Al fondo, los bloques de edificios del final de la calle Cartagena, y los mв”ңГӯs recientes del final de la calle Castelar. A la derecha, las traseras de la antigua estaciв”ңв”Ӯn de ferrocarril de Utrillas, algunos bloques de Miguel Servet, las cocheras de los tranvв”ңВЎas, ya muy menguadas de efectivos (justo un aв”ңв–’o despuв”ңВ®s serв”ңВЎa piqueteada la в”ңв•‘ltima lв”ңВЎnea en activo, la 11 "Parque-San Josв”ңВ®") , y la torre de la fв”ңГӯbrica GIESA- Schindler. Hoy, donde los abrevaderos, estв”ңГӯ la esquina del Parque de la Granja con Josв”ңВ® Galiay; a la derecha queda el CDM La Granja; el Camino Cabaldв”ңв”Ӯs estв”ңГӯ asfaltado, y hasta pasa un bus; y la Prolongaciв”ңв”Ӯn de Cesв”ңГӯreo Alierta, que cruza de derecha a izquierda, ha hecho que esa zona sea muy transitada por trв”ңГӯfico rodado, y cuando hay baloncesto, incluso parece el Paseo de la Independencia durante la segunda semana de octubre. Cuando la imagen, esto estaba a diez minutos del "centro", aunque la sensaciв”ңв”Ӯn era como de aв”ңв–’os luz, y ademв”ңГӯs de los bisiestos. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSв”ңГ«', 41.63736800, -0.86907800, '0101000020E6100000F08975AA7CCFEBBF2BC24D4695D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20051716740.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20051716740.webp', 'https://www.flickr.com/photos/zaragozaantigua/20051716740/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22630, 'Trolebв”ңв•‘s 1972', 'Imagen del trolebв”ңв•‘s nв”¬в•‘ 53 en el acceso a las cocheras de los tranvв”ңВЎas de la ciudad en Miguel Servet. Adquiridos de segunda mano y con procedencia londinense, estos vehв”ңВЎculos se incorporaron a las tres lв”ңВЎneas de trolebв”ңв•‘s urbano (Terminillo/Delicias en 1949, Gв”ңГӯllego en 1954, Barrio de Jesв”ңв•‘s en 1955). Nacida de forma peculiar como respuesta a los embates comerciales del sector privado, esta innovadora forma de transporte, mucho mв”ңГӯs "flexible" que el "rв”ңВЎgido" tranvв”ңВЎa, apenas llegв”ңв”Ӯ a su edad madura: en octubre de 1974 fueron desmantelados, fueran o fuesen rв”ңВЎgidos, flexibles, o ambas cosas a la vez. En esta ciudad, el transporte pв”ңв•‘blico que no fuese puro vehв”ңВЎculo con motor a explosiв”ңв”Ӯn, tenв”ңВЎa las horas contadas. Fuente visual: www.flickr.com/photos/jhm0284/5813101264/in/album-7215763...', 1972, 1972, 1972, 'Anos 70', 'SAN JOSв”ңГ«', 41.63794500, -0.86537700, '0101000020E61000002BBD361B2BB1EBBFC8D2872EA8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20177613248.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20177613248.webp', 'https://www.flickr.com/photos/zaragozaantigua/20177613248/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22633, 'Ferrocarril de Utrillas 1975', 'Nueve aв”ңв–’os despuв”ңВ®s del desmantelamiento de la lв”ңВЎnea minera de Utrillas a Zaragoza, este era el panorama donde la antigua lв”ңВЎnea se bifurcaba en la fв”ңГӯbrica de briquetas MFU (Minas y Ferrocarriles de Utrillas). Hacia la derecha, las vв”ңВЎas conducв”ңВЎan a la Estaciв”ңв”Ӯn de Miraflores, cuyo edificio de viviendas en blanco es parcialmente visible, y a los muelles de la fв”ңГӯbrica de cementos Portland. Hacia la izquierda, por donde los trenes iban-venв”ңВЎan de las cuencas de lignitos de Teruel. En el centro, los restos fosilizados de la fв”ңГӯbrica de briquetas o aglomerados, con las "piscinas" o depв”ңв”Ӯsitos de carbв”ңв”Ӯn en primer plano, y luego el complejo de la fв”ңГӯbrica, el muelle de descarga, y la representativa chimenea que, a diferencia de su vecina gemela de la Estaciв”ңв”Ӯn de Utrillas, fue piqueteada con el resto de la instalaciв”ңв”Ӯn. Al fondo, la mole de la antigua fв”ңГӯbrica de cementos Portland, un patrimonio, en este caso industrial, que fue dinamitado para habilitar el solar donde las Ferias de octubre primero, ahora aparcadero de coches al otro lado del Tercer Cinturв”ңв”Ӯn. En la actualidad, a la derecha se abre la calle Ducado de Atenas que conduce a la Estaciв”ңв”Ӯn de Cercanв”ңВЎas de Miraflores; a la izquierda el prolongado Cesв”ңГӯreo Alierta lleva a la carretera de Castellв”ңв”Ӯn; en el centro se levanta el municipal pabellв”ңв”Ӯn de deportes donde juega el Club Baloncesto Zaragoza; y al fondo, el Tercer Cinturв”ңв”Ӯn de Ronda. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSв”ңГ«', 41.63674200, -0.86723300, '0101000020E61000000B62A06B5FC0EBBFACFE08C380D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20231133642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20231133642.webp', 'https://www.flickr.com/photos/zaragozaantigua/20231133642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22639, 'Vista San Josв”ңВ® 1975', 'Imagen capturada desde las alturas de un edificio del Camino de Cabaldв”ңв”Ӯs, que ofrece una panorв”ңГӯmica irrepetible de la desmantelada lв”ңВЎnea ferroviaria Utrillas-Zaragoza, y el empalme de Miraflores. Los restos de la carbonilla permiten identificar lo que ya no es sino dos oscuros caminos en "y" que contrastan con la claridad de los otros senderos. En la conexiв”ңв”Ӯn de las dos rutas, restos de la fв”ңГӯbrica de briquetas MFU con los vacв”ңВЎos depв”ңв”Ӯsitos de carbв”ңв”Ӯn a modo de piscinas. Los verdes campos formaban parte de los terrenos de la antigua Granja Experimental. A la derecha, edificios de la Estaciв”ңв”Ӯn de Miraflores, y altas higueras junto a la acequia del Camino del Junco. A la izquierda, la empresa Viguetas PITAY, S.A., materiales de construcciв”ңв”Ӯn. Un poco mв”ңГӯs al fondo, el monumental conjunto de la fв”ңГӯbrica de cemento Portland-Miraflores, y su extensa colecciв”ңв”Ӯn de chimeneas. Fuente visual: Foto Hermв”ңв”Ӯgenes Pardo, AVV. San Josв”ңВ®.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSв”ңГ«', 41.63674200, -0.86723300, '0101000020E61000000B62A06B5FC0EBBFACFE08C380D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20355998456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20355998456.webp', 'https://www.flickr.com/photos/zaragozaantigua/20355998456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22642, 'Estaciв”ңв”Ӯn de Utrillas 1979', 'Decembrina y nevada imagen en altura del entorno de la antigua estaciв”ңв”Ӯn de Utrillas. Inmediatas, las antiguas cocheras de los tranvв”ңВЎas habilitadas como primeras cocheras de los autobuses urbanos. A su derecha, exoesqueleto de la estaciв”ңв”Ӯn y traseras de los bloques de la calle Castelar. Al fondo, entre brumas, la abandonada fв”ңГӯbrica de briquetas de MFU y campos de La Granja. La fresca neblina no deja ver mв”ңГӯs. La imagen estв”ңГӯ capturada desde el bloque de viviendas con entrada por la plaza de Utrillas, construido sobre uno de los antiguos edificios para vivienda de trabajadores de la estaciв”ңв”Ӯn de Cappa-Utrillas. Fuente visual: www.facebook.com/photo.php?fbid=10203363958714839&set...', 1979, 1979, 1979, 'Anos 70', 'SAN JOSв”ңГ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20489827995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20489827995.webp', 'https://www.flickr.com/photos/zaragozaantigua/20489827995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22883, 'Estaciв”ңв”Ӯn de Utrillas 1985', 'La Estaciв”ңв”Ӯn de Cappa-Utrillas comenzв”ңв”Ӯ a ser construida en 1863, y los tres edificios que conformaban la entrada desde el Camino del Bajo Aragв”ңв”Ӯn (Miguel Servet) fueron terminados en 1865. El central y mв”ңГӯs ornado de ellos tenв”ңВЎa un luminoso letrero en forja y cristal que, un poco disonante con el estilo sobrio y academicista del conjunto, indicaba la salida de la estaciв”ңв”Ӯn al pasaje que llegaba del sureste de la provincia de Zaragoza y el noreste de Teruel. El desmantelamiento de la lв”ңВЎnea en 1966 y su venta a una inmobiliaria iniciв”ңв”Ӯ una degradante etapa hasta que en 1986 el edificio fue catalogado. Luego vino lo que vino. La imagen recuerda la existencia de este letrero que ni la catalogaciв”ңв”Ӯn, ni la mв”ңГӯs posterior restauraciв”ңв”Ӯn, preservaron. Hoy estarв”ңВЎa dando un poco de alegrв”ңВЎa al frв”ңВЎo, seco (por mв”ңГӯs que llueva) y duro callejв”ңв”Ӯn de losas y cemento en que han convertido el andв”ңВ®n principal de la antigua Estaciв”ңв”Ӯn.', 1985, 1985, 1985, 'Anos 80', 'SAN JOSв”ңГ«', 41.64036700, -0.86774800, '0101000020E6100000CA6B257497C4EBBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19673543923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19673543923.webp', 'https://www.flickr.com/photos/zaragozaantigua/19673543923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22887, 'Estaciв”ңв”Ӯn de Utrillas 1985', '1985. Las Mentes Sencillas y su "Don''t You (Forget About Me)" saturaban los diales comerciales de Radio, mientras la Estaciв”ңв”Ӯn de Utrillas caminaba hacia su aniversario 20 de olvido promovido. En la imagen, captura desde uno de los dos hormigonados muelles del Depв”ңв”Ӯsito de Locomotoras. Tras el levantamiento de vв”ңВЎas, la naturaleza estepв”ңГӯrea va reapropiв”ңГӯndose de lo que era suyo, mientras los 16 arcos de los 16 Depв”ңв”Ӯsitos mantienen el tipo, aun sin cobertura protectora. Al fondo, de izquierda a derecha, el telв”ңв”Ӯn de fondo de los bloques de Castelar y Camino Cabaldв”ңв”Ӯs. El primero, el gran bloque del 81-91 de Castelar/37-39 de Camino Cabaldв”ңв”Ӯs. Luego, el 72 del Camino Cabaldв”ңв”Ӯs, esquina con Martв”ңВЎn Abanto. Despuв”ңВ®s, el pequeв”ңв–’ito 72. Le sigue el 68-70, con el Cafв”ңВ®-Bar "Mikado" en los bajos de su chaflв”ңГӯn. Despuв”ңВ®s, el 62-64, esquina con Luis Braille. Por detrв”ңГӯs vemos asomar la gigantez del 54-56 de Privilegio de la Uniв”ңв”Ӯn/15 de Luis Braille. Llegamos al 60 de Camino Cabaldв”ңв”Ӯs y sus 10 alturas, justo donde emerge la chimenea MFU de la Estaciв”ңв”Ӯn. Finalmente, el 58 de Privilegio de la Uniв”ңв”Ӯn. Las enormes diferencias entre alturas ilustran cв”ңв”Ӯmo se juega al Monopoly en esta ciudad. Si esto era asв”ңВЎ en un humilde barrio de la periferia, cв”ңв”Ӯmo no habrв”ңГӯ sido en el "centro". Los terrenos de la antigua Estaciв”ңв”Ӯn no serв”ңГӯn ajenos al juego, ni mucho menos. Fuente visual: AVV San Josв”ңВ®.', 1985, 1985, 1985, 'Anos 80', 'SAN JOSв”ңГ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20075589438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20075589438.webp', 'https://www.flickr.com/photos/zaragozaantigua/20075589438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22889, 'Estaciв”ңв”Ӯn de Utrillas 1985', 'Del 23 al 25 de marzo de 1984 tuvo lugar la "I Muestra de Pop-Rock y otros rollos de Zaragoza" en el Pabellв”ңв”Ӯn Francв”ңВ®s de la Feria de Muestras. Patrocinado por Ayuntamiento, DPZ y DGA, pasaron por в”ңВ®l 52 grupos de la ciudad, entre ellos Ferrobв”ңв”Ӯs, Zumo de Vidrio, Golden Zippers, Doctor Simв”ңв”Ӯn y los Enfermos Mentales, Boda de Rubias, Pedro Botero... y una banda punk-rock denominada "Parkinson". El 21 de junio de 1985, en el Cine Venecia, este mismo grupo tocв”ңв”Ӯ junto a IV Reich, Mas Birras, y Gastos Aparte, en el "Concierto desde el III Mundo por el hambre en Nueva York" (в”¬ВҪWe Are the Worldв”¬в•— local y somarda), cuya crв”ңв”Ӯnica de Mariano Gistaв”ңВЎn publicada en el periв”ңв”Ӯdico "El Dв”ңВЎa" un par de dв”ңВЎas despuв”ңВ®s, refleja cв”ңв”Ӯmo de loco estaba el movido medio ambiente zaragozano de aquellos elв”ңВ®ctricos aв”ңв–’os ochenta. Igualico al de ahora. En la imagen, un antisistв”ңВ®mico posado fotogrв”ңГӯfico del grupo Parkinson cerca de los arcos de entrada de los abandonados Depв”ңв”Ӯsitos de Locomotoras de la antigua Estaciв”ңв”Ӯn de Utrillas. La fotв”ңв”Ӯgrafa, a la izquierda, es Virginia Espa, y el fotв”ңв”Ӯgrafo que los re-retrata, Mariano Alfonso. Por los huecos de los derrumbados tejados de los Depв”ңв”Ӯsitos, hay visual de las ventanas de los bloques de la calle Castelar-Valentв”ңВЎn Zabala. Lo que de estos arcos no cayв”ңв”Ӯ por el paso del tiempo y la dejadez, fue activamente derribado unos aв”ңв–’os despuв”ңВ®s. Fuente visual: Imagen amablemente aportada por Oskarskroten Bazofia-Records.', 1985, 1985, 1985, 'Anos 80', 'SAN JOSв”ңГ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20274515091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20274515091.webp', 'https://www.flickr.com/photos/zaragozaantigua/20274515091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22890, 'Estaciв”ңв”Ӯn de Utrillas 1985', 'Vista de la Estaciв”ңв”Ӯn de Utrillas desde el seco mar de vв”ңВЎas, sin balasto, raв”ңВЎles, travesaв”ңв–’os, ni unidades. Abandonada desde 1966, era propiedad privada que la mantenв”ңВЎa en barbecho espectante al albur de las fluctuaciones del mercado inmobiliario. Inmediatamente a la izquierda queda el edificio principal de la Estaciв”ңв”Ӯn. A continuaciв”ңв”Ӯn, las naves aв”ңв•‘n en pie de las antiguas cocheras principales de los tranvв”ңВЎas, a las que se entraba por Miguel Servet, reutilizadas por los autobuses urbanos. En el centro, el mar de vв”ңВЎas poblado ahora de la vegetaciв”ңв”Ӯn esteparia de la zona. A la derecha, restos de edificios e instalaciones auxiliares, como la aguada, la carbonera, el depв”ңв”Ӯsito de locomotoras, la chimenea. Al fondo a la derecha, los bloques de viviendas del final de la calle Castelar. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9313326358/in/...', 1985, 1985, 1985, 'Anos 80', 'SAN JOSв”ңГ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20301579942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20301579942.webp', 'https://www.flickr.com/photos/zaragozaantigua/20301579942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22891, 'Estaciв”ңв”Ӯn de Utrillas 1989', 'Imagen tomada desde la altura de uno de los bloques de viviendas del Camino de Cabaldв”ңв”Ӯs, con panorв”ңГӯmica visiв”ңв”Ӯn del espacio urbano configurado por la Estaciв”ңв”Ӯn de Utrillas, algo mв”ңГӯs de veinte aв”ңв–’os despuв”ңВ®s del desmantelamiento de la lв”ңВЎnea ferroviaria. En primer plano, los edificios e instalaciones de la estaciв”ңв”Ӯn: el edificio principal, los andenes, el mar (seco) de vв”ңВЎas, los muelles, la carbonera, la aguada, la chimenea (en su original ubicaciв”ңв”Ӯn), los arcos del depв”ңв”Ӯsito de locomotoras... A continuaciв”ңв”Ӯn, las enormes cocheras de los tranvв”ңВЎas, desmantelados doce aв”ңв–’os antes, ya sin tejados. Luego, los enormes bloques de viviendas que daban a Miguel Servet, el palacio de Larrinaga, los bloques de Castelar... Pasado, presente, y un futuro pendiente. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9613999377/in/...', 1989, 1989, 1989, 'Anos 80', 'SAN JOSв”ңГ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20335566161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20335566161.webp', 'https://www.flickr.com/photos/zaragozaantigua/20335566161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22894, 'Estaciв”ңв”Ӯn de Utrillas 1985', 'Imagen capturada desde las alturas del Camino Cabaldв”ңв”Ӯs del entorno de la antigua estaciв”ңв”Ӯn de Utrillas, destacando la estructura del arqueado depв”ңв”Ӯsito de locomotoras. A la derecha, los bloques de viviendas del final de la calle Castelar. Al fondo, los dos bloques gemelos de Miguel Servet-calle Puebla de Hв”ңВЎjar. En el centro, la mole de Miguel Servet 174-178. A la izquierda, Giesa, y las cocheras de los autobuses urbanos. Fuente visual: www.facebook.com/photo.php?fbid=10202317028127396&set...', 1985, 1985, 1985, 'Anos 80', 'SAN JOSв”ңГ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20490273125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20490273125.webp', 'https://www.flickr.com/photos/zaragozaantigua/20490273125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22899, 'Centro Deportivo La Granja 1989', 'Centro Deportivo Municipal La Granja en el camino de Cabaldв”ңв”Ӯs, sobre terrenos de la antigua Granja Agrв”ңВЎcola, en una vista aв”ңВ®rea que en el centro muestra sus diversos equipamientos (campo de fв”ңв•‘tbol de hierba, pista de atletismo, pabellв”ңв”Ӯn cubierto, piscinasГ”ГҮВӘ). Hacia el fondo, parque de la Granja y viviendas del barrio de san Josв”ңВ®. En primer tв”ңВ®rmino, obras de construcciв”ңв”Ӯn del nuevo pabellв”ңв”Ӯn municipal de deportes, y a la derecha zona donde luego se prolongarв”ңВЎa la avenida de Cesв”ңГӯreo Alierta.', 1989, 1989, 1989, 'Anos 80', 'SAN JOSв”ңГ«', 41.63574600, -0.86809300, '0101000020E6100000705E9CF86AC7EBBF0A48FB1F60D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21002428748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21002428748.webp', 'https://www.flickr.com/photos/zaragozaantigua/21002428748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22980, 'Miguel Servet 1992', 'Imagen de la fachada principal del antiguo edificio de Direcciв”ңв”Ӯn y Oficinas Generales de la empresa "Tranvв”ңВЎas de Zaragoza S. A.", edificada en el nв”¬в•‘ 113-115 de la calle de Miguel Servet, en la manzana entre Yolanda de Bar y Guiral. A su derecha se habilitв”ңв”Ӯ un taller para trolebuses y autobuses, y el resto de la manzana fue destinado a cocheras de trolebuses y autobuses. La entrada principal estaba en la parte central del edificio, en la zona delimitada por los pilares. En el friso superior estaba el rв”ңв”Ӯtulo que lo identificaba "Los Tranvв”ңВЎas de Zaragoza S. A.". Tras la fulminaciв”ңв”Ӯn de los tranvв”ңВЎas, el edificio quedв”ңв”Ӯ sin uso, luego fue piqueteado y sustituido por recientes bloques de viviendas. Fuente: "Zaragoza barrio a barrio"', 1992, 1992, 1992, 'Anos 90', 'SAN JOSв”ңГ«', 41.63969300, -0.86589200, '0101000020E6100000EBC6BB2363B5EBBF753DD175E1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15768101778.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15768101778.webp', 'https://www.flickr.com/photos/zaragozaantigua/15768101778/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22986, 'Estaciв”ңв”Ӯn de Miraflores 1994', 'Imagen de la Estaciв”ңв”Ӯn de Miraflores con el sol a la espalda, de buena maв”ңв–’ana, y encima de la metв”ңГӯlica pasarela peatonal sobre cuyos restos arqueolв”ңв”Ӯgicos hoy descansa el terraplв”ңВ®n del Tercer Cinturв”ңв”Ӯn de Ronda. Buena idea esa de tomar una foto con el sol de espaldas. Es una de las cosas buenas del sureste de la ciudad: los primeros rayos de Sol de una maв”ңв–’ana fresca y tranquila invitan a echar un vistazo panorв”ңГӯmico como este. A la izquierda, la doble vв”ңВЎa del ferrocarril a Barcelona, el puente del Camino de Cabaldв”ңв”Ӯs, y las moles del literal final de Tenor Fleta. En el centro de la imagen, la veterana Estaciв”ңв”Ӯn de Miraflores, levemente ensuciada por autoproclamados "escritores". Detrв”ңГӯs, edificios auxiliares de la Estaciв”ңв”Ӯn, incluyendo el de vivienda de operarios, y el reciente de la subestaciв”ңв”Ӯn elв”ңВ®ctrica en sobrio estilo bв”ңв•‘nker post-nuclear (de hecho, hoy es la в”ңв•‘nica estructura superviviente, al lado del fв”ңВ®retro de cemento). A la derecha, un viejo ramal de vв”ңВЎa recuerda la clausurada conexiв”ңв”Ӯn con la Estaciв”ңв”Ӯn de Utrillas, por donde los lignitos turolenses se encaminaban al Mediterrв”ңГӯneo. A la derecha y al fondo, entre mecanos y altas tensiones, los veteranos bloques de Josв”ңВ® Galiay y los mв”ңГӯs modernos de Pablo Remacha, y el primer bloque de Luis Aula. Mira que se ven cosas sin el Sol cegв”ңГӯndote. Fuente visual: AVV "La Granja" barrio de San Josв”ңВ®.', 1994, 1994, 1994, 'Anos 90', 'SAN JOSв”ңГ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19676569993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19676569993.webp', 'https://www.flickr.com/photos/zaragozaantigua/19676569993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24958, 'Parque de Primo de Rivera 1970', 'Imagen capturada en el Parque Primo de Rivera y centrada en una seв”ңв–’orita observando en proximidad el pв”ңВ®treo bulto redondo que singularizaba la pequeв”ңв–’a fuente ornamental denominada de forma no oficial como el "Manneken Pis de Zaragoza" por estar inspirada en la simpв”ңГӯtica y broncв”ңВЎnea figurita bruselense que representa un "hombrecito que orina" en cueros vivos. Otros mв”ңГӯs castizos y llanos lo bautizaron como "La Fuente del Meoncico". Fuese Manneken o fuese Meoncico, los indв”ңВЎgenas zaragozanos a los que les molestan mucho las inspiraciones inmigrantes o no patrias como esta se encargaron a conciencia en el marco de una canicular noche del verano de ese mismo aв”ңв–’o, de arrancar al Manneken-Meoncico de su base y hacerlo desaparecer para siempre. Quedaron apenas en el lugar sus piececitos y la parte inferior del soporte por el que ascendв”ңВЎa el chorrito de agua-"orina". El servicio de Parques y Jardines no enmendв”ңв”Ӯ esta destrucciв”ңв”Ӯn y fuese y no hubo nada.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63158000, -0.89784500, '0101000020E61000005E11FC6F25BBECBF62670A9DD7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54673325400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54673325400.webp', 'https://www.flickr.com/photos/zaragozaantigua/54673325400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22989, 'Estaciв”ңв”Ӯn de Utrillas 1997', 'Desde altura, en el nв”¬в•‘ 3 de la Plaza de Utrillas, un vistazo al estado del entorno de la antigua Estaciв”ңв”Ӯn cuando ya estaba bastante avanzado el proceso de urbanizaciв”ңв”Ӯn de los terrenos que la rodeaban. Ya casi terminada, a la izquierda, la gran pastilla de viviendas alabeada por Camino de Cabaldв”ңв”Ӯs, Valentв”ңВЎn Zabala-Castelar, в”ңГјngel Sanz Briz y Cesв”ңГӯreo Alierta. Quedaba el enorme terraplв”ңВ®n interior, en medio, que soportarв”ңВЎa a duras penas luego a una nueva gran superficie comercial metida con calzador, por decirlo de alguna forma. Poco despuв”ңВ®s se produjo el traslado de la molesta chimenea estacionaria, que edificaron antiguamente sin pensar en las medidas de los bloques que se habrв”ңВЎan de construir despuв”ңВ®s. De no ser porque tenв”ңВЎa (y mantiene) ocupas de la familia Ciconiidae, esta chimenea hubiera sido trasladada donde el resto de estructuras y edificios de la antigua Estaciв”ңв”Ӯn, incluido su irrepetible Depв”ңв”Ӯsito de locomotoras ("los Arcos"). Quedaba por darle una nueva vida a los dos edificios supervivientes de la Estaciв”ңв”Ӯn, previa recuperaciв”ңв”Ӯn-dignificaciв”ңв”Ӯn. Sobre si esto asв”ңВЎ ha sido, hay diferentes opiniones. En que el resultado global es manifiestamente mejorable, hasta las cigв”ңв•қeв”ңв–’as lo ven claro, desde su aireada y despejada atalaya. Fuente visual: Imв”ңГӯgenes Antiguas de Zaragoza.', 1997, 1997, 1997, 'Anos 90', 'SAN JOSв”ңГ«', 41.64036700, -0.86774800, '0101000020E6100000CA6B257497C4EBBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20285640332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20285640332.webp', 'https://www.flickr.com/photos/zaragozaantigua/20285640332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22990, 'Estaciв”ңв”Ӯn de Utrillas 1997', 'Instantв”ңГӯnea capturada durante el invernal traslado de la chimenea de la antigua compaв”ңв–’в”ңВЎa Minas y Ferrocarriles de Utrillas, construida en 1925, desde su emplazamiento original en la carbonera de la Estaciв”ңв”Ӯn de Utrillas, a 80 m. al SE, para no agobiar a la nueva Gran Superficie Comercial que se iba a construir. Se salvв”ңв”Ӯ por una pluma: por ser hogar de cigв”ңв•қeв”ңв–’as. Fuente visual: Foto Pilar Delgado, en AVV. San Josв”ңВ®.', 1997, 1997, 1997, 'Anos 90', 'SAN JOSв”ңГ«', 41.63995000, -0.86791900, '0101000020E6100000FB761211FEC5EBBFA089B0E1E9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20299917216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20299917216.webp', 'https://www.flickr.com/photos/zaragozaantigua/20299917216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23103, 'Carlos Santana 2000', 'Actuaciв”ңв”Ӯn del guitarrista mexicano Carlos Santana en el Pabellв”ңв”Ӯn Prв”ңВЎncipe Felipe, el 19 de mayo de 2000. Fuente: Agencia EFE.', 2000, 2000, 2000, 'Siglo XXI', 'SAN JOSв”ңГ«', 41.63532000, -0.86619800, '0101000020E61000001A8A3BDEE4B7EBBF533F6F2A52D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24277090439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24277090439.webp', 'https://www.flickr.com/photos/zaragozaantigua/24277090439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23138, 'Rastro 2006', 'Foto: Marв”ңВЎa Torres-Solanot. Vista del rastro instalado en el aparcamiento del pabellв”ңв”Ӯn Prв”ңВЎncipe Felipe (al fondo), el miв”ңВ®rcoles 19 de abril de 2006. Es su primer dв”ңВЎa en esa ubicaciв”ңв”Ӯn, y todavв”ңВЎa tiene pocos puestos, debido a la oposiciв”ңв”Ӯn por parte de algunos de sus comerciantes a trastadarse allв”ңВЎ, desde el entorno de La Romareda. El domingo 30 de abril ya estarв”ңГӯn todos. En 2008 serв”ңГӯ trasladado a La Almozara; tambiв”ңВ®n el de la plaza de Toros. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', 'SAN JOSв”ңГ«', 41.63668300, -0.86605500, '0101000020E61000006631B1F9B8B6EBBFA7751BD47ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31819809201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31819809201.webp', 'https://www.flickr.com/photos/zaragozaantigua/31819809201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23152, 'Miraflores 2009', 'Imagen virtual del "Nuevo campo municipal de fв”ңв•‘tbol de Zaragoza", proyectado en la pastilla delimitada por el cinturв”ңв”Ӯn de Ronda (N), la acequia del Ojo del Gallo (O), y el tendido ferroviario proveniente de la estaciв”ңв”Ӯn de Miraflores (E). Segв”ңв•‘n las bases del concurso internacional, el nuevo campo deberв”ңВЎa tener capacidad hasta las 50000 plazas, en un entorno de actividades complementarias como restaurantes, comercios y recreativos, y flanqueado por dos edificios de 26 plantas de VPO, otro de 21 plantas, dos mв”ңГӯs de 16, uno de 14, y varios de 4. Completaban el panorama 12 bloques de 9 plantas con viviendas libres, para alcanzar los 3.422 pisos nuevos (2.530 libres y 892 VPO), ademв”ңГӯs de 2.500 plazas de aparcamiento. El proyecto ganador, el de la imagen, introducв”ңВЎa alguna variante en las torres de monopoly previstas, si bien el devenir de las cosas dejв”ңв”Ӯ el asunto, que deberв”ңВЎa haber estado finalizado en 2011, en suspenso. Aunque sв”ңв”Ӯlo sea una recreaciв”ңв”Ӯn virtual, nunca se habв”ңВЎa visto este entorno tan ferazmente verde desde los tiempos de la antigua Granja Agrв”ңВЎcola. Desde la atalaya de 26 pisos seguro que se verв”ңВЎa bien el camino de Miraflores. Fuente visual: siciliayasociados.com/', 2009, 2009, 2009, 'Siglo XXI', 'SAN JOSв”ңГ«', 41.63046000, -0.86622200, '0101000020E61000003C6C223317B8EBBFD4B7CCE9B2D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32281056915.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32281056915.webp', 'https://www.flickr.com/photos/zaragozaantigua/32281056915/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23178, 'Talleres Diв”ңВ®sel 2000', 'Aspecto del edificio de Talleres Diв”ңВ®sel S.A., en la calle de Miguel Servet 216. Factorв”ңВЎa de bombas inyectoras para motores diв”ңВ®sel fundada por Pedro Esteban como Transformaciones Diв”ңВ®sel S.A. en 1939. Se demoliв”ңв”Ӯ en 2006. Fuente: Foto de Jacob Gragera.', 2000, 2000, 2000, 'Siglo XXI', 'SAN JOSв”ңГ«', 41.63685900, -0.86415400, '0101000020E610000087A4164A26A7EBBFE694809884D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36914919355.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36914919355.webp', 'https://www.flickr.com/photos/zaragozaantigua/36914919355/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23183, 'Miraflores c.2000', 'Imagen capturada desde la metв”ңГӯlica pasarela peatonal que salvaba las vв”ңВЎas del ferrocarril junto a la estaciв”ңв”Ӯn de Miraflores, y permitв”ңВЎa el acceso a sus andenes. Raudo y a в”ңв•‘ltima hora de la tarde pasa el tren de media distancia o servicio Regional con destino a Binв”ңВ®far servido por un automotor ligero de la serie 596 de los conocidos como "Tamagochis" por su pequeв”ңв–’o tamaв”ңв–’o. A la derecha y tras el tren, la antigua estaciв”ңв”Ӯn de Miraflores, y algo detrв”ңГӯs el tradicional edificio de viviendas de la estaciв”ңв”Ӯn. Poco despuв”ңВ®s, la pasarela metв”ңГӯlica serв”ңВЎa retirada con motivo de las obras de construcciв”ңв”Ӯn del tercer cinturв”ңв”Ӯn de ronda, y unos aв”ңв–’os despuв”ңВ®s este entorno serв”ңВЎa radicalmente remodelado durante el soterramiento de las vв”ңВЎas, que supusieron el derribo de los edificios del entorno, salvo la moderna estaciв”ңв”Ӯn transformadora que se deja ver tras el pintarrajeado edificio de la antigua estaciв”ңв”Ӯn.', 2000, 2000, 2000, 'Siglo XXI', 'SAN JOSв”ңГ«', 41.63238000, -0.86676100, '0101000020E61000001D588E9081BCEBBF7E52EDD3F1D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51035209446.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51035209446.webp', 'https://www.flickr.com/photos/zaragozaantigua/51035209446/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23235, 'Giesa 2023', 'Vista de la nueva plaza inaugurada por el alcalde Jorge Azcв”ңв”Ӯn en 2023, fruto de acondicionar el solar del derribo de las naves norte y central de la antigua factorв”ңВЎa Giesa, luego Schindler, entre las calles del Padre Chaminade, a la izquierda, y de Yolanda de Bar, a la derecha. Al fondo se ve el palacio de Larrinaga, en la calle de Miguel Servet, y la torre de pruebas de ascensores de la fв”ңГӯbrica, a la derecha. A esta plaza se le llamв”ңв”Ӯ "plaza de Giesa" y "plaza de Vicente Cazcarra", por ser el punto donde termina el paseo homв”ңв”Ӯnimo. De 4.200 metros cuadrados, estaba equipada con zona de juegos infantiles, gimnasio al aire libre, pista multideporte, toldos, papeleras y alcorques para в”ңГӯrboles. Fue derribada en 2025 para la construcciв”ңв”Ӯn de una "ciudad del cine" llamada Distrito 7.', 2023, 2023, 2023, 'Siglo XXI', 'SAN JOSв”ңГ«', 41.63979100, -0.86481100, '0101000020E6100000E412471E88ACEBBF38A3E6ABE4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54452473437.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54452473437.webp', 'https://www.flickr.com/photos/zaragozaantigua/54452473437/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23444, 'Palacio de Larrinaga 1974', 'Tranvв”ңВЎa de la lв”ңВЎnea 1 recorre Miguel Servet junto al palacio de Larrinaga. Fuente: "Los tranvв”ңВЎas de Zaragoza", J. Peв”ңв–’a/J. M. Valero, DPZ, 1985.', 1974, 1974, 1974, 'Anos 70', 'SAN JOSв”ңГ«', 41.63834300, -0.86441300, '0101000020E61000008997A77345A9EBBFB5503239B5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14953901031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14953901031.webp', 'https://www.flickr.com/photos/zaragozaantigua/14953901031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23448, 'La Granja 1974', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Mayo 1974. Imagen desde el interior de los terrenos de la antigua Granja Agrв”ңВЎcola. Los muros y la verja se corresponden con la entrada principal, que estaba en el Camino del Bajo Aragв”ңв”Ӯn, luego Miguel Servet. Tras el abandono del proyecto de la Granja en 1943, los campos de herbв”ңГӯceas y maв”ңВЎz continuaron siendo productivos hasta la urbanizaciв”ңв”Ӯn de la zona, en la segunda mitad de los setenta. Al fondo, el abandonado Palacio de Larrinaga, que no levantaba cabeza desde el expolio y saqueo al que fue objeto durante y tras la guerra de 1936-1939.', 1974, 1974, 1974, 'Anos 70', 'SAN JOSв”ңГ«', 41.63810900, -0.86501200, '0101000020E6100000BFB854A52DAEEBBF4224438EADD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15062084399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15062084399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15062084399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23479, 'Palacio de Larrinaga 1938', 'En octubre de 1937 fue creado el Cuerpo de Ejв”ңВ®rcito de Galicia, con soldados rebeldes, a las в”ңв”Ӯrdenes de Franco. A inicios de 1938 se establecieron en el palacio de Larrinaga de Zaragoza, desde donde se dirigieron a participar en la batalla de Teruel. En la imagen, sus miembros posando en la escalinata de acceso al edificio de la calle de Miguel Servet. Fuente: Fondo Documental Mario Blanco Fuentes. Museo Manuel Reimв”ңв”Ӯndez Portela.', 1938, 1938, 1938, 'Anos 30', 'SAN JOSв”ңГ«', 41.63841500, -0.86449700, '0101000020E6100000FFAECF9CF5A9EBBF4F232D95B7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36351692682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36351692682.webp', 'https://www.flickr.com/photos/zaragozaantigua/36351692682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23489, 'Ctra. de Castellв”ңв”Ӯn c.1912', 'Imagen centrada en la original Villa Asunciв”ңв”Ӯn o vivienda unifamiliar del vizcaв”ңВЎno Miguel Larrinaga diseв”ңв–’ada por el arquitecto Fв”ңВ®lix Navarro Pв”ңВ®rez en los extensos terrenos que este naviero poseв”ңВЎa en este tramo de la carretera de Zaragoza a Castellв”ңв”Ӯn. La cв”ңв•‘pula central que remata la caja de la escalera serв”ңВЎa poco despuв”ңВ®s sustituida por un cimborrio de planta octogonal diseв”ңв–’ado por el arquitecto Fernando de Escondrillas, En primer tв”ңВ®rmino, dos caballerв”ңВЎas tiran de un carro ante la verja y pв”ңВ®rgola que delimita el ingreso a la villa. Al otro lado de la carretera y confrontando con ella, fuera de plano, se encontraba el acceso a la Granja Agrв”ңВЎcola de Zaragoza.', 1912, 1912, 1912, 'Anos 10', 'SAN JOSв”ңГ«', 41.63833800, -0.86501200, '0101000020E6100000BFB854A52DAEEBBFA3E5400FB5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49990273208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49990273208.webp', 'https://www.flickr.com/photos/zaragozaantigua/49990273208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24088, 'Giesa 1966', 'Imagen tomada en el gran patio central de la fв”ңГӯbrica Giesa durante una reuniв”ңв”Ӯn informativa previa a las elecciones sindicales convocadas ese aв”ңв–’o, en este caso para la renovaciв”ңв”Ӯn reglamentaria de Enlaces Sindicales y Vocales del Jurado de este centro de trabajo. Giesa contaba con una activa presencia del clandestino sindicato Comisiones Obreras, militantes del Partido Comunista, tan hв”ңГӯbilmente mimetizados, que en la imagen no se pueden distinguir de los demв”ңГӯs trabajadores. Destaca el busto sobre pedestal de Joaquв”ңВЎn Guiral Palacio, fundador de la empresa y fallecido en 1950. Muchos aв”ңв–’os despuв”ңВ®s, tras el cierre de esta factorв”ңВЎa, el busto pasв”ңв”Ӯ a dependencias municipales, donde fue tomado prestado por los amigos de lo ajeno, hasta la fecha. Tras las altas naves del fondo, la calle de Yolanda de Bar. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'SAN JOSв”ңГ«', 41.63998400, -0.86430300, '0101000020E6100000C4B5DAC35EA8EBBF4CFBE6FEEAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45499042765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45499042765.webp', 'https://www.flickr.com/photos/zaragozaantigua/45499042765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24090, 'CDM La Granja 1984', 'Imagen capturada con motivo de la visita del alcalde Ramв”ңв”Ӯn Sainz de Varanda y Jimв”ңВ®nez de la Iglesia a las reciв”ңВ®n inauguradas instalaciones de las piscinas de La Granja, dentro del Centro Deportivo Municipal del mismo nombre. La estampa recuerda a alguna de las mв”ңГӯs celebradas escenas corales cinematogrв”ңГӯficas de Fellini, o de Berlanga, que queda mв”ңГӯs cerca, con una turbamulta sin soluciв”ңв”Ӯn de continuidad conformada por policв”ңВЎas municipales, cargos institucionales, vecinos mayores, vecinos en paв”ңв–’os menores, tancredos puros y duros, chavales y chavalas... La desolaciв”ңв”Ӯn del entorno, como las montaв”ңв–’as de ruinas que enmarcan la escena, producto del derribo de la antigua fв”ңГӯbrica de briquetas y conglomerados de Minas y Ferrocarriles de Utrillas, pasan a un plano secundario, contingente, porque ya habв”ңВЎa piscinas, que era lo importante. Al fondo, en la calle de Miguel Servet se destaca la torre de la empresa Transformaciones Diesel S.A., Zaragoza, mв”ңГӯs tarde Talleres Diesel S.A., Zaragoza, que luego se trasladв”ңв”Ӯ a un polв”ңВЎgono industrial. En 2006 esta torre fue demolida.', 1984, 1984, 1984, 'Anos 80', 'SAN JOSв”ңГ«', 41.63659800, -0.86831600, '0101000020E61000003FFED2A23EC9EBBF7959130B7CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46573118155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46573118155.webp', 'https://www.flickr.com/photos/zaragozaantigua/46573118155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24187, 'Estaciв”ңв”Ӯn de Cappa 1894', 'Imagen de la Estaciв”ңв”Ӯn de Zaragoza de la compaв”ңв–’в”ңВЎa MZA, que conservaba la antigua denominaciв”ңв”Ӯn de "Cappa", por haber sido fundada por Leв”ңв”Ӯn Cappa. En el momento de capturar la imagen, esta estaciв”ңв”Ӯn era el punto de salida de la lв”ңВЎnea Zaragoza-Barcelona. Unos meses despuв”ңВ®s, con la apertura del apeadero de Miraflores, esta estaciв”ңв”Ӯn quedв”ңв”Ӯ unida a la de Campo Sepulcro mediante un provisional enlace. Cuando desde Miraflores fueron tendidos directamente los rieles en direcciв”ңв”Ӯn a Barcelona, la Estaciв”ңв”Ӯn de Cappa quedв”ңв”Ӯ sin servicio, hasta que en 1901, la concesiв”ңв”Ӯn de uso pasв”ңв”Ӯ a la compaв”ңв–’в”ңВЎa Minas y Ferrocarrilles de Utrillas, que la volviв”ңв”Ӯ a activar en septiembre de 1904 como terminal carbonera, hasta 1966. En la imagen, a la izquierda el primitivo depв”ңв”Ӯsito de locomotoras. A la derecha, el edificio principal de la estaciв”ңв”Ӯn. Fuente visual: www.plouteruel.com', 1894, 1894, 1894, 'Siglo XIX', 'SAN JOSв”ңГ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20206672749.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20206672749.webp', 'https://www.flickr.com/photos/zaragozaantigua/20206672749/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24189, 'Estaciв”ңв”Ӯn de Utrillas 1904', 'Impulsada por el prв”ңв”Ӯcer local Leв”ңв”Ӯn Cappa, en 1865 comenzв”ңв”Ӯ a funcionar la "Compaв”ңв–’в”ңВЎa del Ferrocarril de Zaragoza a Escatrв”ңв”Ӯn", y в”ңВ®l mismo diseв”ңв–’в”ңв”Ӯ el edificio principal de la estaciв”ңв”Ӯn terminal en Zaragoza, denominada "De Escatrв”ңв”Ӯn", y levantada en la carretera de Alcaв”ңв–’iz, mв”ңГӯs allв”ңГӯ del Molino del Seminario, entre la Torre de Ponte, y la de Mazas. En 1894 funcionв”ңв”Ӯ provisionalmente como estaciв”ңв”Ӯn de Zaragoza-Barcelona, hasta que se construyв”ңв”Ӯ el empalme de Miraflores para conectar con la lв”ңВЎnea MZA. Ya tenв”ңВЎa como vecinas, al lado, las Dependencias de los Tranvв”ңВЎas, y cerca, la Granja Experimental, y el Matadero Municipal. En 1904 fue adquirida por la compaв”ңв–’в”ңВЎa "Minas y Ferrocarriles de Utrillas", que la habilitв”ңв”Ӯ como terminal carbonera del ferrocarril de Utrillas-Montalbв”ңГӯn, y nueva sede social de la empresa. En la imagen, la fachada del edificio Central de la Estaciв”ңв”Ӯn aв”ңв•‘n denominada de "Cappa", aunque pronto serв”ңГӯ ya conocida por su nombre definitivo, "Utrillas", poco despuв”ңВ®s de su reinauguraciв”ңв”Ӯn a finales de octubre. Vehв”ңВЎculos a propulsiв”ңв”Ӯn de sangre, estacionados en la plaza de acceso junto a la carretera de Zaragoza a Castellв”ңв”Ӯn. Fuente visual: Revista "Nuevo Mundo", 1904.', 1904, 1904, 1904, 'Anos 1900', 'SAN JOSв”ңГ«', 41.64036700, -0.86774800, '0101000020E6100000CA6B257497C4EBBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20454299225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20454299225.webp', 'https://www.flickr.com/photos/zaragozaantigua/20454299225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24466, 'C.в”¬в•‘ de la Granja 1977', 'Esta brumosa toma estв”ңГӯ hecha desde uno de los riegos que alimentaban los campos experimentales de la antigua Granja Agrв”ңВЎcola, al lado del Camino que desde Miguel Servet daba entrada principal a la Granja. En primer tв”ңВ®rmino, el cauce de riego. Detrв”ңГӯs, campos de cultivo de herbв”ңГӯceos de "La Granja". Inmediatamente, los restos el terraplв”ңВ®n del ferrocarril a Utrillas, bifurcado en torno a las ruinas de la fв”ңГӯbrica de aglomerados-briquetas MFU, con su chimenea de 1920, a la derecha. A la izquierda, las instalaciones de Viguetas PITAY, S.A., materiales de construcciв”ңв”Ӯn. Al fondo, como entre la bruma de las ensoв”ңв–’aciones, las chimeneas y silos de la abandonada fв”ңГӯbrica de cementos Portland de Miraflores. Tras el Camino del Junco y el riego Ribazo del Junco, los postes elв”ңВ®ctricos de la desmantelada lв”ңВЎnea a Utrillas se pierden en el horizonte, y las sombras de la Estaciв”ңв”Ӯn de Miraflores parecen desvanecerse. En la actualidad esto serв”ңВЎa aproximadamente la calle Principado de Morea, dando a esos descampados asfaltados donde estuviera el Rastro de la ciudad, que luego fue ocasional aparcamiento multitudinario, y ahora estв”ңГӯ siendo edificado por una inmobiliaria. No deja de ser muy de esta ciudad que tengamos en esta zona una calle dedicada a un medieval pedazo de la Grecia bizantina llamada "Principado de Morea", otra al "Ducado de Atenas", y no haya una calle que recuerde algo de importancia tan capital, como La Granja Agrв”ңВЎcola. Magnificar las glorias del Imperio, sea del color o tamaв”ңв–’o que sea, tiran mucho. Fuente visual: AVV San Josв”ңВ®.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSв”ңГ«', 41.63749600, -0.86563400, '0101000020E610000000C8091346B3EBBF58AA0B7899D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20073564448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20073564448.webp', 'https://www.flickr.com/photos/zaragozaantigua/20073564448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24955, 'Cabezo de Buenavista 1925', 'Imagen capturada en el "restaurant Las Palmeras" sito en el Cabezo de Buenavista, con un posado donde destaca el tenor Miguel Burro Fleta acompaв”ңв–’ado por su secretario Casaseca, Gayarce, el empresario Casali y su esposa la soprano Marв”ңВЎa Llв”ңГӯcer, la tiple Matilde Revenga y su madre, ademв”ңГӯs de algunos periodistas, amigos y parientes. Este grupo subiв”ңв”Ӯ al cabezo a celebrar el в”ңВ®xito de la actuaciв”ңв”Ӯn que el tenor realizв”ңв”Ӯ ante el icono de la Virgen del Pilar en el homв”ңв”Ӯnimo templo.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63366300, -0.89300300, '0101000020E61000003E5B07077B93ECBFB6D782DE1BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51339041238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51339041238.webp', 'https://www.flickr.com/photos/zaragozaantigua/51339041238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24467, 'MFU Utrillas 1980', 'Chimenea de la Fв”ңГӯbrica de briquetas levantada en 1920 por la compaв”ңв–’в”ңВЎa "Minas y Ferrocarril de Utrillas, S.A.", para el aprovechamiento integral de los carbones menudos, que aglomerados con breas y alquitranes, se convertв”ңВЎan aquв”ңВЎ en bloques de "briqueta", el alimento de las locomotoras de la lв”ңВЎnea. Al fondo, los bloques del 1-3 de la calle Puebla de Hв”ңВЎjar, entre Miguel Servet y el luego prolongado Cesв”ңГӯreo Alierta. A esas alturas de la pelв”ңВЎcula, con la lв”ңВЎnea de Utrillas desmantelada, y la actividad fabril cesada, el entorno quedв”ңв”Ӯ para poco mв”ңГӯs que desolaciв”ңв”Ӯn, ruina y abandono. La chimenea sobreviviв”ңв”Ӯ hasta que fue derribada cuando en 1990 se levantв”ңв”Ӯ en esa misma ubicaciв”ңв”Ӯn el nuevo Pabellв”ңв”Ӯn Municipal de Deportes. La chimenea en sв”ңВЎ no molestaba, porque hubiera quedado en uno de los despejados y anchos accesos peatonales. Pero quedaba fea y poco moderna, descontextualizada, justo al lado de uno de los emblemas de la modernidad urbana. Y ya se sabe cв”ңв”Ӯmo las gastamos en esta ciudad con lo "viejo" cuando vamos de "modernos". Ademв”ңГӯs, como no tenв”ңВЎa inquilinas cigв”ңв•қeв”ңв–’as, que fue lo que salvв”ңв”Ӯ a su prima pequeв”ңв–’a de la Estaciв”ңв”Ӯn de Utrillas, pues ni por esas. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9247284691/in/...', 1980, 1980, 1980, 'Anos 80', 'SAN JOSв”ңГ«', 41.63488200, -0.86691100, '0101000020E6100000705D3123BCBDEBBFD76839D043D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20082307189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20082307189.webp', 'https://www.flickr.com/photos/zaragozaantigua/20082307189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24472, 'Calle de Miguel Servet 1984', 'Varias generaciones edilicias capturadas en altura desde el bloque del nв”¬в•‘ 88 del camino de Cabaldв”ңв”Ӯs. De izquierda a derecha: la fв”ңГӯbrica Giesa y su acceso por la calle de Joaquв”ңВЎn Guiral; el singular bloque del nв”¬в•‘ 174-178 de la calle de Miguel Servet, precedido de restos de los antiguos depв”ңв”Ӯsitos o estanques de carbв”ңв”Ӯn de la Estaciв”ңв”Ӯn de Utrillas, levemente sombreados por los bloques del final de la calle de Emilio Castelar, esquina con la de Valentв”ңВЎn Zabala; y el Palacio de Larrinaga.', 1984, 1984, 1984, 'Anos 80', 'SAN JOSв”ңГ«', 41.63745600, -0.86701800, '0101000020E6100000F16261889CBEEBBFCA51802898D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20372082875.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20372082875.webp', 'https://www.flickr.com/photos/zaragozaantigua/20372082875/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24473, 'Briquetas 1976', 'Imagen de las ruinas de la antigua fв”ңГӯbrica de briquetas de la lв”ңВЎnea de ferrocarril de Utrillas, como uno de los lugares de "chabolismo" para personas excluidas, "outsiders". Al fondo, los nuevos bloques de viviendas para gente "incluida". Fuente visual: Archivo Pв”ңв•‘blico Municipal, Gerardo Sancho Ramo.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSв”ңГ«', 41.63586000, -0.86688900, '0101000020E61000007C6308008EBDEBBFD36A48DC63D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20428563241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20428563241.webp', 'https://www.flickr.com/photos/zaragozaantigua/20428563241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24488, 'GIESA c.1984', 'Edificio de la fв”ңГӯbrica GIESA en la calle de San Joaquв”ңВЎn, visto desde Miguel Servet. A su puerta accede la vв”ңВЎa ferroviaria que lo comunicaba con la estaciв”ңв”Ӯn de Utrillas. A la izquierda, vв”ңВЎa del tranvв”ңВЎa. En 2006, la empresa trasladв”ңв”Ӯ sus instalaciones al polв”ңВЎgono Empresarium de La Cartuja Baja. Fuente visual: foto de Mariano Rodrв”ңВЎguez Gonzalvo, en www.facebook.com/photo.php?fbid=478965102268159&set=p...', 1984, 1984, 1984, 'Anos 80', 'SAN JOSв”ңГ«', 41.63948300, -0.86508800, '0101000020E61000007F2F8507CDAEEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24786828766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24786828766.webp', 'https://www.flickr.com/photos/zaragozaantigua/24786828766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24490, 'GIESA 1942', 'Dibujo realizado por los arquitectos Miguel в”ңГјngel Navarro y Josв”ңВ® Luis Navarro Anguela en el proyecto de edificaciв”ңв”Ӯn de la nueva fв”ңГӯbrica de ascensores GIESA (Guiral Industrias Elв”ңВ®ctricas S.A.) Para ubicarla en este emplazamiento, en el km. 2 de la carretera de Castellв”ңв”Ӯn, tuvo mucha importancia la inmediatez de la estaciв”ңв”Ӯn de ferrocarril de Utrillas, ademв”ңГӯs de las cocheras de los tranvв”ңВЎas de la calle Miguel Servet. Aunque el fin de obra estaba previsto para 1943 (ver alusiв”ңв”Ӯn en la puerta, tal y como aparecв”ңВЎa en el proyecto), no se concluyв”ңв”Ӯ hasta 1945.', 1942, 1942, 1942, 'Anos 40', 'SAN JOSв”ңГ«', 41.63948300, -0.86488400, '0101000020E610000060ADDA3521ADEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24812903205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24812903205.webp', 'https://www.flickr.com/photos/zaragozaantigua/24812903205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24532, 'Giesa 1942', 'Dibujo del proyecto de Miguel в”ңГјngel Navarro Pв”ңВ®rez y Josв”ңВ® Luis Navarro Anguela para las "fв”ңГӯbricas de Giesa" a construir en buena parte de la propiedad de Villa Asunciв”ңв”Ӯn, en la carretera de Castellв”ңв”Ӯn. Destaca las vв”ңВЎas que por la puerta principal de la factorв”ңВЎa conectarв”ңВЎa con el ferrocarril, y que en el proyecto original no se contemplaba la torre luego aв”ңв–’adida en el extremo noroeste del gran edificio de acceso.', 1942, 1942, 1942, 'Anos 40', 'SAN JOSв”ңГ«', 41.63922800, -0.86446500, '0101000020E6100000282CF180B2A9EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49500953467.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49500953467.webp', 'https://www.flickr.com/photos/zaragozaantigua/49500953467/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24566, 'La Granja 1930', 'Imagen centrada en tres ejemplares de ganado vacuno lechero de la raza Schwyz guipuzcoana, con sus respectivos cuidadores, ante los establos de la Granja Agrв”ңВЎcola de Zaragoza. Esta raza habв”ңВЎa sido resultado del cruzamiento de la raza indв”ңВЎgena Pirenaica con toros de la suiza raza Schwyz a finales del siglo XIX. Tras varias generaciones, el resultado en tв”ңВ®rminos de trabajo, carne y leche, era mв”ңГӯs que satisfactorio. Este edificio de establos para ganado vacuno estaba situado junto al pabellв”ңв”Ӯn de laboratorios. A la derecha, caseta de peones y в”ңГӯrboles inmediatos al camino que conectaba con el camino del Puente del Virrey (hacia a la izquierda), y el camino de Cabaldв”ңв”Ӯs (hacia la derecha). Fuente visual: exposiciв”ңв”Ӯn Г”ГҮВЈLa investigaciв”ңв”Ӯn agroalimentaria en Aragв”ңв”Ӯn. Sus inicios con Rodrв”ңВЎguez AyusoГ”ГҮГҳ. Centro de Investigaciв”ңв”Ӯn y Tecnologв”ңВЎa Agroalimentaria de Aragв”ңв”Ӯn (CITA).', 1930, 1930, 1930, 'Anos 30', 'SAN JOSв”ңГ«', 41.63758400, -0.86530200, '0101000020E6100000823AE5D18DB0EBBFF7393E5A9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15065422956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15065422956.webp', 'https://www.flickr.com/photos/zaragozaantigua/15065422956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24569, 'La Granja 1930', 'Imagen centrada en la enseв”ңв–’anza prв”ңГӯctica a un grupo de alumnos de la Granja Agrв”ңВЎcola del tratamiento al hongo de la Cercospora beticola, parв”ңГӯsito de la remolacha azucarera, mediante aplicaciones fungicidas con acciв”ңв”Ӯn sistв”ңВ®mica. La lecciв”ңв”Ӯn estв”ңГӯ siendo impartida en un campo experimental inmediato, al fondo, al camino de Herederos que provenв”ңВЎa del "Despartidero" entre el camino de San Josв”ңВ® y el del Puente del Virrey. Mв”ңГӯs al fondo, el depв”ңв”Ӯsito de locomotoras cubierto, chimenea, y otras instalaciones de la estaciв”ңв”Ӯn de ferrocarril de Utrillas. Fuente visual: exposiciв”ңв”Ӯn Г”ГҮВЈLa investigaciв”ңв”Ӯn agroalimentaria en Aragв”ңв”Ӯn. Sus inicios con Rodrв”ңВЎguez AyusoГ”ГҮГҳ/Panel "Los inicios de la Granja Agrв”ңВЎcola en Zaragoza". Centro de Investigaciв”ңв”Ӯn y Tecnologв”ңВЎa Agroalimentaria de Aragв”ңв”Ӯn (CITA).', 1930, 1930, 1930, 'Anos 30', 'SAN JOSв”ңГ«', 41.63477000, -0.86770500, '0101000020E6100000F86BB2463DC4EBBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20163476559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20163476559.webp', 'https://www.flickr.com/photos/zaragozaantigua/20163476559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24570, 'La Granja Aв”ңв–’os 30', 'Imagen del camino de entrada a la Granja Agrв”ңВЎcola. El del centro era el edificio de Direcciв”ңв”Ӯn y Laboratorios. A su izquierda, el edificio de habitaciones del personal residente y bodegas. Al otro extremo, la Escuela Regional de Agricultura. La ordenaciв”ңв”Ӯn del espacio es clara, cientв”ңВЎfica, ilustrada. La foto estв”ңГӯ realizada desde el Camino de Cabaldв”ңв”Ӯs Fuente visual: AHPZ, Archivo Mora', 1930, 1930, 1939, 'Anos 30', 'SAN JOSв”ңГ«', 41.63666200, -0.86903500, '0101000020E61000001E8A027D22CFEBBF904DF2237ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20180641350.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20180641350.webp', 'https://www.flickr.com/photos/zaragozaantigua/20180641350/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24571, 'La Granja 1913', 'La Granja Escuela Agrв”ңВЎcola Experimental fue inaugurada en 1884 por impulso de la DPZ. Ocupaba 21,5 hectв”ңГӯreas en Miraflores, partida de "Rabalete", en la antigua "Torre de la Infanta". Alfonso XII puso su primera piedra como centro pionero en investigaciв”ңв”Ӯn agropecuaria que permitiв”ңв”Ӯ, entre otras cosas, el "boom" remolachero del Valle del Ebro. Su centro de operaciones fue construido segв”ңв•‘n proyecto de Fв”ңВ®lix Navarro, con entrada principal por el Camino del Bajo Aragв”ңв”Ӯn. Para llegar al punto que ilustra la imagen habв”ңВЎa que cruzar las vв”ңВЎas que conectaban la Estaciв”ңв”Ӯn de Utrillas con la de Miraflores. El jovencito que nos ha traв”ңВЎdo hasta aquв”ңВЎ, 102 aв”ңв–’os despuв”ңВ®s, estв”ңГӯ parado en la entrada al complejo central para dejarnos contemplar el fabuloso lugar. Mientras, el fotв”ңв”Ӯgrafo enfoca con tranquilidad desde el Camino de Cabaldв”ңв”Ӯs. Al fondo, en el centro, el edificio de Direcciв”ңв”Ӯn y Laboratorios, y los cuidados jardines que flanquean el acceso. En la pequeв”ңв–’a glorieta central del fondo se instalarв”ңГӯ, un par de aв”ңв–’os despuв”ңВ®s, un busto en homenaje a Manuel Rodrв”ңВЎguez Ayuso, Director de la instituciв”ңв”Ӯn de 1891 a 1908. A su izquierda, edificio de habitaciones del personal residente y bodegas. Al otro extremo, Escuela Regional de Agricultura y edificio de los establos. La ordenaciв”ңв”Ӯn del espacio es clara, higiв”ңВ®nica, cientв”ңВЎfica. Los resultados, invaluables. Asв”ңВЎ fue hasta la guerra de 1936-1939. Hoy no queda nada. Fuente visual: Juan Chicoy Arreceigor (1873-1959) www.flickr.com/photos/ricardosanzcortiella/12388250753/in...', 1913, 1913, 1913, 'Anos 10', 'SAN JOSв”ңГ«', 41.63666200, -0.86903500, '0101000020E61000001E8A027D22CFEBBF904DF2237ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20221011172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20221011172.webp', 'https://www.flickr.com/photos/zaragozaantigua/20221011172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24577, 'Granja Agrв”ңВЎcola 1930', 'Imagen del importante Campo de Demostraciв”ңв”Ӯn de la Granja Agrв”ңВЎcola de Zaragoza. Aquв”ңВЎ, desde 1886, se llevaron a cabo las principales investigaciones prв”ңГӯcticas, experimentaciones y actividades docentes relacionadas con la introducciв”ңв”Ӯn en el agro regional de la remolacha azucarera, ademв”ңГӯs de otros cereales y plantas forrajeras, asв”ңВЎ como de novedades tв”ңВ®cnicas para mejorar la productividad agrв”ңВЎcola en в”ңГӯreas diversas. En la imagen, las parcelas del Campo de Demostraciв”ңв”Ӯn quedan localizadas entre la zona de los pabellones principales de la Granja Agrв”ңВЎcola, a la izquierda, junto al camino de Cabaldв”ңв”Ӯs, y el empalme ferroviario de Miraflores, a la derecha. Al fondo, emergiendo del arbolado camino principal de acceso a la Granja desde Miguel Servet, las torres del Pilar y la Seo de la vieja ciudad, y el inmediato gran complejo de la estaciв”ңв”Ӯn de Utrillas y el cocherв”ңв”Ӯn de los Tranvв”ңВЎas. Fuente visual: exposiciв”ңв”Ӯn Г”ГҮВЈLa investigaciв”ңв”Ӯn agroalimentaria en Aragв”ңв”Ӯn. Sus inicios con Rodrв”ңВЎguez AyusoГ”ГҮГҳ/Panel "Los inicios de la Granja Agrв”ңВЎcola en Zaragoza". Centro de Investigaciв”ңв”Ӯn y Tecnologв”ңВЎa Agroalimentaria de Aragв”ңв”Ӯn (CITA).', 1930, 1930, 1930, 'Anos 30', 'SAN JOSв”ңГ«', 41.63477000, -0.86770500, '0101000020E6100000F86BB2463DC4EBBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33816735593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33816735593.webp', 'https://www.flickr.com/photos/zaragozaantigua/33816735593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24578, 'La Granja 1930', 'Imagen que recoge "las prв”ңГӯcticas por los alumnos becarios de la Inspecciв”ңв”Ӯn General de Emigraciв”ңв”Ӯn" en la Granja Agrв”ңВЎcola de Zaragoza, en este caso atando fajos de heno de alfalfa que luego serв”ңГӯn recogidos en el carro. La referencia visual, al fondo, de la que fuera casa de Larrinaga nos sitв”ңв•‘a en el campo de cultivo experimental que limitaba con el camino de la Granja (el paseo arbolado de la izquierda), y con el camino del Bajo Aragв”ңв”Ӯn. El camino de la Granja conectaba el camino del Bajo Aragв”ңв”Ӯn (al fondo) con los edificios principales de la Granja, atravesando campos agrв”ңВЎcolas de experimentaciв”ңв”Ӯn y cruzando las vв”ңВЎas del ferrocarril a Utrillas y el empalme a la estaciв”ңв”Ӯn de Miraflores, junto a la carbonera y fв”ңГӯbrica de briquetas de Minas y Ferrocarriles de Utrillas. Fuente visual: "Granja Agrв”ңВЎcola de Zaragoza. Su cincuentenario. Homenaje y gratitud."', 1930, 1930, 1930, 'Anos 30', 'SAN JOSв”ңГ«', 41.63666200, -0.86903500, '0101000020E61000001E8A027D22CFEBBF904DF2237ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33824637663.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33824637663.webp', 'https://www.flickr.com/photos/zaragozaantigua/33824637663/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24581, 'La Granja 1930', 'Pausa para posado colectivo en la demostraciв”ңв”Ӯn prв”ңГӯctica de trilla mecв”ңГӯnica en terrenos de la Granja Agrв”ңВЎcola durante un cursillo impartido a un grupo de maestros. La trilla mecв”ңГӯnica suponв”ңВЎa un notable avance en las labores de cosecha en el campo, pues con unos pocos obreros encargados de proporcionar y retirar los sacos, la mв”ңГӯquina regulaba la carga y los llenaba de una forma rв”ңГӯpida. Esta fue otra de las mumerosas experimentaciones llevadas a cabo en los campos de cultivo de la Granja, incluyendo maquinaria como nunca se habв”ңВЎa visto por los alrededores. Esta imagen se ha capturado en el Campo de Demostraciв”ңв”Ӯn entre el camino de Cabaldв”ңв”Ӯs y el empalme a la estaciв”ңв”Ӯn de Miraflores desde la de Utrillas, cuya carbonera, fв”ңГӯbrica de briquetas y chimenea MFU (Minas y Ferrocarriles de Utrillas) destacan al fondo. Fuente visual: "Granja Agrв”ңВЎcola de Zaragoza. Su cincuentenario. Homenaje y gratitud."', 1930, 1930, 1930, 'Anos 30', 'SAN JOSв”ңГ«', 41.63477000, -0.86770500, '0101000020E6100000F86BB2463DC4EBBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34523567451.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34523567451.webp', 'https://www.flickr.com/photos/zaragozaantigua/34523567451/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24582, 'La Granja 1929', '"Una lecciв”ңв”Ӯn prв”ңГӯctica en el Campo de Demostraciв”ңв”Ӯn" de la Granja Agrв”ңВЎcola de Zaragoza, durante la Semana Social Agraria, o demostraciв”ңв”Ӯn sobre cв”ңв”Ӯmo un arado mecв”ңГӯnico puede resultar mв”ңГӯs provechoso, en tв”ңВ®rminos productivos, que uno romano (asв”ңВЎ era llamado el de uso tradicional, aunque su procedencia era prehistв”ңв”Ӯrica). En la imagen, y tras el moderno artefacto mecв”ңГӯnico, la fв”ңГӯbrica de briquetas de Minas y Ferrocarriles de Utrillas, y los postes de madera junto a la lв”ңВЎnea fв”ңВ®rrea del empalme a la estaciв”ңв”Ӯn de Miraflores. Un par de estos postes superviven, todavв”ңВЎa, a la masiva extinciв”ңв”Ӯn ferroviaria, y siguen en su sitio junto a la ruinosa Torre del camino del Junco. Fuente visual: foto Alejandro de la Barrera, en "Homenaje y testimonio de gratitud que dedican a la Granja Agrв”ңВЎcola de Zaragoza en el Cincuentenario de su fundaciв”ңв”Ӯn, los representantes de la Agricultura e Industrias, agradecidas a su benв”ңВ®fico influjo en el resurgimiento de la economв”ңВЎa general aragonesa", 1931.', 1929, 1929, 1929, 'Anos 20', 'SAN JOSв”ңГ«', 41.63477000, -0.86770500, '0101000020E6100000F86BB2463DC4EBBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34532197071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34532197071.webp', 'https://www.flickr.com/photos/zaragozaantigua/34532197071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24699, 'Miguel Servet 1982', 'Imagen en altura de la calle Miguel Servet (izquierda) y lo que luego serв”ңГӯ la prolongaciв”ңв”Ӯn de Cesв”ңГӯreo Alierta (derecha). En medio, la mole del nв”¬в•‘ 174 de Miguel Servet. A sus pies, las antiguas cocheras de los tranvв”ңВЎas habilitadas como primeras cocheras de los autobuses urbanos. A su derecha, restos de las antiguas carboneras de la estaciв”ңв”Ӯn. A la izquierda, los muros de GIESA, y un trozo de Larrinaga. Al fondo, a la derecha, las instalaciones de Viguetas PITAY, S.A., ademв”ңГӯs de los antiguos campos de La Granja, y las chimeneas de la antigua fв”ңГӯbrica de cementos de Miraflores. La imagen estв”ңГӯ capturada desde el nuevo bloque de viviendas con entrada por la plaza de Utrillas, construido sobre uno de los antiguos edificios para vivienda de trabajadores de la estaciв”ңв”Ӯn de Cappa-Utrillas. Fuente visual: www.facebook.com/photo.php?fbid=10203301013461247&set...', 1982, 1982, 1982, 'Anos 80', 'SAN JOSв”ңГ«', 41.63853000, -0.86592400, '0101000020E6100000C3499A3FA6B5EBBFE8C1DD59BBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20474151602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20474151602.webp', 'https://www.flickr.com/photos/zaragozaantigua/20474151602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24704, 'Calle de las Minas 1930', 'El barrio de Utrillas se extendв”ңВЎa desde la calle de Miguel Servet, que era a la vez calle y carretera nacional, en el tramo comprendido entre el matadero municipal y la emblemв”ңГӯtica Villa Asunciв”ңв”Ӯn, y se vertebraba en seis calles transversales: Escuelas, Utrillas, Minas, Higuera, Belchite y Fillas. Su privilegiada situaciв”ңв”Ӯn, entre la estaciв”ңв”Ӯn de ferrocarril minero de Utrillas, el macelo, varias industrias, unas escuelas nacionales, y buenos accesos viales, elevв”ңв”Ӯ el vecindario a cerca de 1.500 personas, pero su natural expansiв”ңв”Ӯn topaba con un cinturв”ңв”Ӯn de propiedades particulares que la impedв”ңВЎan. De hecho, las antes referidas calles eran realmente callejones a los que se entraba por Miguel Servet y terminaban en un fondo de saco. La prolongaciв”ңв”Ӯn hacia la inmediata y enorme huerta de las Fuentes, de momento, estaba vetada por los propietarios de esos terrenos. Esta circunstancia llevв”ңв”Ӯ a redenominar coloquialmente el barrio como "el de las obstrucciones". La imagen ilustra esta situaciв”ңв”Ӯn en la calle de las Minas, en una captura realizada desde su emboque por la de Miguel Servet. A la izquierda, las parcelas de los nв”ңв•‘meros 3, 5 y 7. A la derecha, el nв”¬в•‘ 6. Al fondo, la parcela que truncaba la continuidad de la calle. A ambos lados, el soleado y el umbrв”ңВЎo, riegos al aire abastecв”ңВЎan los huertos parcelarios.', 1930, 1930, 1930, 'Anos 30', 'SAN JOSв”ңГ«', 41.64293200, -0.86833800, '0101000020E610000034F8FBC56CC9EBBFA4C684984BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25894157414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25894157414.webp', 'https://www.flickr.com/photos/zaragozaantigua/25894157414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24848, 'Miguel Servet 1978', 'Captura de Miguel Servet desde el arranque de la calle de Minas, hasta la difuminaciв”ңв”Ӯn al fondo de la actual calle Francisco de Quevedo (ex-Fillas y Camino de Fillas). Aв”ңв•‘n quedaban mв”ңГӯs de 300 metros para llegar a la entrada a la antigua Estaciв”ңв”Ӯn de Utrillas, pero su absoluta trascendencia para esta parte de la ciudad era tal que la denominaciв”ңв”Ӯn de bastantes calles de la zona tuvo su raв”ңВЎz en la Lв”ңВЎnea minera que desde 1904 se estableciв”ңв”Ӯ entre Zaragoza y Utrillas, y cuya estaciв”ңв”Ӯn terminal se localizв”ңв”Ӯ en la anterior Estaciв”ңв”Ӯn de Cappa. Asв”ңВЎ, ya a la izquierda de la imagen quedaba la calle "Utrillas", y la calle "Minas" se referв”ңВЎa, precisamente, a las minas turolenses de lignito de esa localidad. Un poco mв”ңГӯs adelante, la calle "Belchite" hacв”ңВЎa referencia al municipio entonces mв”ңГӯs importante de la lв”ңВЎnea Zaragoza-Utrillas. Bien es cierto que se trataba de calles que nacв”ңВЎan en Miguel Servet, y que desembocaban en la nada, en el "campo", como se decв”ңВЎa entonces, pero es que al actual Barrio de las Fuentes aв”ңв•‘n le faltaban unas buenas dв”ңВ®cadas para ser tal cosa. Esto formaba parte de la denominada "barriada de Montemolв”ңВЎn", que a finales de los aв”ңв–’os 60 del pasado siglo en un pleno municipal de los de entonces fue repartida entre los pujantes barrios de Las Fuentes y S. Josв”ңВ®. En la imagen, de izquierda a derecha, el nв”¬в•‘ 2 de la calle Minas, de 1949. A continuaciв”ңв”Ӯn, el nв”¬в•‘ 71 de Miguel Servet (1949), el nв”¬в•‘ 73 en plena construcciв”ңв”Ӯn (1979), el nв”¬в•‘ 73 Dpdo. (1964), el nв”¬в•‘ 75-77 (1971), y el nв”¬в•‘ 79 (1939). Despuв”ңВ®s de la calle Tomв”ңГӯs Higuera, el nв”¬в•‘ 81 y el nв”¬в•‘ 81 Dpdo. (ambos de 1940). Todas las parcelas que continв”ңв•‘an hasta la calle Belchite serв”ңГӯn luego derribadas, y sobre su solar se levantarв”ңГӯ el nв”¬в•‘ 83-85 (2007), el nв”¬в•‘ 87 (1999), y el nв”¬в•‘ 1 de la calle Belchite (2003). A continuaciв”ңв”Ӯn, las obras del nв”¬в•‘ 2-4 de la calle Belchite (1979), y los edificios del principio de la calle Francisco de Quevedo (nв”¬в•‘ 1, de 1965, y nв”¬в•‘ 2, de 1969). Esta calle empezв”ңв”Ӯ a ser denominada asв”ңВЎ en 1969, ya que antes era la', 1978, 1978, 1978, 'Anos 70', 'SAN JOSв”ңГ«', 41.64257100, -0.86848800, '0101000020E610000087FD9E58A7CAEBBFD32D3BC43FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20245220822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20245220822.webp', 'https://www.flickr.com/photos/zaragozaantigua/20245220822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24860, 'Miguel Servet 1981', 'Imagen parcial de la zona de salida de las cocheras, en la calle de Miguel Servet, del servicio de los autobuses urbanos gestionados por una empresa concesionaria. Esta ubicaciв”ңв”Ӯn fue establecida en las antiguas cocheras de los tranvв”ңВЎas de la ciudad, en servicio hasta enero de 1976, cuando se consumв”ңв”Ӯ su progresiva y estudiada sustituciв”ңв”Ӯn por lв”ңВЎneas de autobuses que, en lo fundamental, heredaron sus recorridos y rutas. Asв”ңВЎ, en la imagen, una unidad de la lв”ңВЎnea 30 "Las Fuentes-Casablanca", que sustituyв”ңв”Ӯ a la tranviaria lв”ңВЎnea 15 "Casablanca" (tambiв”ңВ®n "Bajo Aragв”ңв”Ӯn-Casablanca"); y una unidad de la lв”ңВЎnea 31 "Torrero-Avda. Goya-Delicias", una de las sustitutivas de la tranviaria lв”ңВЎnea 5 "Venecia-Delicias". Fuente visual: "Andalв”ңГӯn, periв”ңв”Ӯdico quincenal aragonв”ңВ®s".', 1981, 1981, 1981, 'Anos 80', 'SAN JOSв”ңГ«', 41.63979900, -0.86618000, '0101000020E610000080608E1EBFB7EBBFBA8102EFE4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32544728292.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32544728292.webp', 'https://www.flickr.com/photos/zaragozaantigua/32544728292/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24862, 'Calle del Hermano Adolfo c.1988', 'Inв”ңВ®dita imagen capturada en el desolado entorno de la estaciв”ңв”Ӯn de Utrillas, y centrada en tres maltratados Pegaso de la flota de autobuses urbanos durmiendo el sueв”ңв–’o eterno. Carrozados en la factorв”ңВЎa de Icarsa, estuvieron en servicio desde principios de los aв”ңв–’os 70 hasta mediados de los aв”ңв–’os 80, siendo sustituidos por nuevos vehв”ңВЎculos Renault. La vida media в”ңв•‘til de los autobuses urbanos, comparada con la de los denostados tranvв”ңВЎas histв”ңв”Ӯricos, era incomparablemente inferior. Tras el muro perimetral de la estaciв”ңв”Ӯn y a la derecha, el inmueble del nв”¬в•‘ 4 de la calle del Hermano Adolfo, medianero con el solar del nв”¬в•‘ 6, que serв”ңГӯ construido poco despuв”ңВ®s. A la izquierda, la plaza del PIntor Fermв”ңВЎn Aguayo y la calle del Monasterio de Poblet, que comienza al fondo, en la del Monasterio de Samos.', 1988, 1988, 1988, 'Anos 80', 'SAN JOSв”ңГ«', 41.64119200, -0.86844500, '0101000020E6100000B5FD2B2B4DCAEBBF793A579412D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32708080337.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32708080337.webp', 'https://www.flickr.com/photos/zaragozaantigua/32708080337/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24956, 'Cabezo de Buenavista 1925', 'Imagen de la singular terraza del "restaurant" Las Palmeras sito en el cabezo de Buenavista, en el homв”ңв”Ӯnimo parque. Gestionado por su propietario, Antonio de Cabo, se convirtiв”ңв”Ӯ en uno de los espacios mв”ңГӯs atractivos en los que la "buena sociedad zaragozana" buscaba el "fresco" durante la dura temporada veraniega. El aterrazado entorno, a escasos metros del reciente monumento al rey Alfonso I "El Batallador" (hacia la izquierda de la imagen) presenta una balaustrada que delimita la terraza y el ingreso al restaurante desde un pequeв”ңв–’o paseo arbolado que en primer tв”ңВ®rmino conectaba con los empinados accesos al cabezo desde la entrada al parque por el sureste, junto al Canal Imperial de Aragв”ңв”Ӯn y el chalet Buenavista.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63342300, -0.89280000, '0101000020E610000036CD3B4ED191ECBF61C43E0114D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51346057461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51346057461.webp', 'https://www.flickr.com/photos/zaragozaantigua/51346057461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25724, 'Miraflores 1984', 'Tirado por una locomotora elв”ңВ®ctrica de la serie 269 (denominadas las "japonesas" por haber sido ideadas por la Mitsubishi), un tren convencional de pasajeros pasa por la Estaciв”ңв”Ӯn de Miraflores en direcciв”ңв”Ӯn a la novв”ңВЎsima Estaciв”ңв”Ӯn del Portillo. A la izquierda, el modesto pero digno pequeв”ңв–’o edificio de la estaciв”ңв”Ӯn, los andenes de espera con algunos viajeros ocasionales, y con otros tancredos locales, y el mar de vв”ңВЎas encima del balasto. Al fondo, la pasarela peatonal para salvar las vв”ңВЎas, pero que no era muy utilizada al estar las vв”ңВЎas a ras de suelo, y no en trinchera. La electrificaciв”ңв”Ӯn ferroviaria llevada a cabo en los aв”ңв–’os setenta, con sus metros y metros de tendidos aв”ңВ®reos, queda bien patente en la imagen. En la actualidad, el Tercer Cinturв”ңв”Ӯn pasa por donde la pasarela peatonal. La original Estaciв”ңв”Ӯn fue derribada y levantado otro nuevo edificio que estв”ңГӯ colgado y, a la vez, enterrado. Y todo estв”ңГӯ dentro de un cajв”ңв”Ӯn de cemento por encima del cual deberв”ңВЎa llegar Tenor Fleta hasta el Tercer Cinturв”ңв”Ӯn, pero no es asв”ңВЎ. Tan cerca del centro de la ciudad (tres minutos hasta la Estaciв”ңв”Ӯn de Goya), y tan lejos. Todavв”ңВЎa, y han pasado 40 aв”ңв–’os. Fuente visual: AVV San Josв”ңВ®', 1984, 1984, 1984, 'Anos 80', 'SAN JOSв”ңГ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20063440780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20063440780.webp', 'https://www.flickr.com/photos/zaragozaantigua/20063440780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25726, 'Cementera Miraflores 1976', 'A la derecha de las vв”ңВЎas del ferrocarril a Barcelona, casi metiendo los zancos en la acequia del Plano, vista crepuscular de cв”ңв”Ӯmo estaban las cosas por la Estaciв”ңв”Ӯn de Miraflores, cuando la mole de la fв”ңГӯbrica de cementos Portand de Miraflores, cerrada apenas tres aв”ңв–’os antes, seguв”ңВЎa hegemonizando el horizonte con sus chimeneas, ya silenciadas, y los silos, vacв”ңВЎos. Cuando fue dinamitada dejв”ңв”Ӯ un solar que aв”ңв•‘n perdura, como los crв”ңГӯteres lunares tras un impacto de meteorito. La metв”ңГӯlica pasarela peatonal sobre las vв”ңВЎas no es que tuviera demasiado uso, que cruzar las vв”ңВЎas a pelo era prв”ңГӯctica deportiva local, pero no se tiene constancia de que fuera reutilizada en otra ubicaciв”ңв”Ӯn cuando en 2002 fue desmantelada para dejar paso al Tercer Cinturв”ңв”Ӯn de Ronda. A la original Estaciв”ңв”Ӯn de Miraflores le habв”ңВЎan aв”ңв–’adido un cuerpo extra (puerta y ventana de la izquierda), seв”ңв–’al de un aumento de funciones que mostraba su buena salud como transiciв”ңв”Ӯn de apeadero a Estaciв”ңв”Ӯn. En la actualidad esta zona estв”ңГӯ encofrada, alberga una Estaciв”ңв”Ӯn de Cercanв”ңВЎas, y pasa el Tercer Cinturв”ңв”Ӯn, pero la degradaciв”ңв”Ӯn y marasmo urbanв”ңВЎstico de los alrededores son mayв”ңв•‘sculos. Ah, y no busquen este edificio de la Estaciв”ңв”Ӯn: hay otro, colgado, pendiente, suspendido, y muy moderno. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/11123084636/in...', 1976, 1976, 1976, 'Anos 70', 'SAN JOSв”ңГ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20091039328.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20091039328.webp', 'https://www.flickr.com/photos/zaragozaantigua/20091039328/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24994, 'San Juan Bosco 1968', 'Imagen capturada en el recinto del Real de la Feria durante la celebraciв”ңв”Ӯn de una dominical prueba incluida en el VI Trofeo Federaciв”ңв”Ӯn Aragonesa de Ciclismo. Tres ciclistas del equipo Club Aragonв”ңВ®s (Carmelo Blasco, Mario в”ңГјlvarez y Juan Cofrades) aparecen junto con Jesв”ңв•‘s Salavera en el circuito que junto a la calle de San Juan Bosco se habilitaba por las calles del recinto donde en las fiestas del Pilar se instalaban las ferias de atracciones. De fondo, la Escuela de Magisterio y el colosal Edificio Torresol en la esquina entre la calle de Tomв”ңГӯs Bretв”ңв”Ӯn y la avenida de Valencia. Sobre este espacio se construirв”ңВЎa poco despuв”ңВ®s el Hospital Clв”ңВЎnico.', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.64285200, -0.90320700, '0101000020E6100000AF95D05D12E7ECBF87156EF948D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52496413294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52496413294.webp', 'https://www.flickr.com/photos/zaragozaantigua/52496413294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25728, 'Estaciв”ңв”Ӯn de Miraflores 1975', 'Vista del mar de vв”ңВЎas de Miraflores desde la considerable altura del silo de la antigua y vecina fв”ңГӯbrica de cementos Portland. Al fondo, el puente del Camino de Cabaldв”ңв”Ӯs. Luego, enormes campos de cultivo de herbв”ңГӯceas, a la izquierda. Una locomotora diв”ңВ®sel elв”ңВ®ctrica 333 de Renfe tirando de un convoy de mercancв”ңВЎas hacia Barcelona, navegando por el ancho mar de vв”ңВЎas de Miraflores. La pasarela peatonal, por encima. El viejito edificio de la estaciв”ңв”Ӯn de Miraflores, y la vв”ңВЎa muerta del empalme del ferrocarril de Utrillas. A los pies, inmediato, el gigante recinto de la fв”ңГӯbrica de cemento. En la actualidad, el panorama estв”ңГӯ mucho mв”ңГӯs simplificado: la Ronda de Hispanidad, o Tercer Cinturв”ңв”Ӯn de Ronda cruza y corta por donde la pasarela peatonal. Los campos de cultivo siguen en barbecho expectante de construcciв”ңв”Ӯn, a ver si se rehincha la burbuja esa. El mar de vв”ңВЎas, canalizado en seco por un sarcв”ңв”Ӯfago de cemento que espera ser, alguna vez del presente siglo, parte de Tenor Fleta. La Estaciв”ңв”Ӯn de Miraflores, tambiв”ңВ®n para Cercanв”ңВЎas, transfigurada sin el viejito edificio, con unas puertas que cuelgan en la nada inaccesible, y unos provisionales accesos alucinantes. Y el solar de la cementera para aparcar, jugar al fв”ңв•‘tbol, y subir y bajar por piedras. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9665677277/in/...', 1975, 1975, 1975, 'Anos 70', 'SAN JOSв”ңГ«', 41.63175500, -0.86579500, '0101000020E61000004D4A41B797B4EBBFD00A0C59DDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20122225378.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20122225378.webp', 'https://www.flickr.com/photos/zaragozaantigua/20122225378/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25729, 'Estaciв”ңв”Ӯn de Utrillas 1968', 'La imagen ilustra un momento del proceso de desmantelamiento de la vв”ңВЎa fв”ңВ®rrea Zaragoza-Utrillas, tras el desecamiento del mar de vв”ңВЎas por el que las locomotoras accedв”ңВЎan a los depв”ңв”Ӯsitos en que eran guardadas. Esta acciв”ңв”Ӯn fue realizada muy poco tiempo despuв”ңВ®s del cierre de la lв”ңВЎnea. Fue tan rв”ңГӯpido, que se tuvo que "apartar" al material rodante situado en ellas, que quedв”ңв”Ӯ varado como tren fuera de riel, hasta que le llegв”ңв”Ӯ su hora. algв”ңв•‘n tiempo despuв”ңВ®s. El abandono y la degradaciв”ңв”Ӯn acabarв”ңГӯn reduciendo a esta estructura, tres dв”ңВ®cadas despuв”ңВ®s, a sus elementos mв”ңГӯs resistentes: los arcos de acceso a los depв”ңв”Ӯsitos. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSв”ңГ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20152008289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20152008289.webp', 'https://www.flickr.com/photos/zaragozaantigua/20152008289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25732, 'C. Alierta prolongado 1990', 'Foto aв”ңВ®rea de la reciente urbanizaciв”ңв”Ӯn del entorno del "Pabellв”ңв”Ӯn P. Felipe" y de la prolongaciв”ңв”Ӯn de la avenida de Cesв”ңГӯreo Alierta. Falta la conexiв”ңв”Ӯn directa por la calle de Cartagena, al fondo, como consecuencia de la demora por el polв”ңВ®mico proceso de expropiaciones de las viviendas de los nв”ңв•‘meros impares de la calle. El Pabellв”ңв”Ӯn municipal de deportes (a la izquierda, fuera de plano) ya habв”ңВЎa sido inaugurado el 17 de abril, y era utilizado como sede de importantes eventos deportivos, como la "Final Four Zaragoza 1990" o final del campeonato de baloncesto de Europa, en la que el equipo KK Jugoplastika Split se proclamв”ңв”Ӯ campeв”ңв”Ӯn continental. Aв”ңв•‘n no se ha iniciado, a la derecha, la construcciв”ңв”Ӯn de las viviendas y del polв”ңВ®mico Gran Centro Comercial sobre los terrenos de la antigua Estaciв”ңв”Ӯn de Utrillas. A la izquierda, las instalaciones deportivas del CDM "La Granja". Fuente visual: FCC', 1990, 1990, 1990, 'Anos 90', 'SAN JOSв”ңГ«', 41.63740800, -0.86800500, '0101000020E61000009F76F86BB2C6EBBFB91AD99596D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20205077096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20205077096.webp', 'https://www.flickr.com/photos/zaragozaantigua/20205077096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25747, 'Cocheras Tranvв”ңВЎa 1945', 'Imagen en altura de las cocheras de los Tranvв”ңВЎas en Miguel Servet. Allв”ңВЎ se ubicaron desde 1885, y hasta 1976. La inmediatez a la Estaciв”ңв”Ӯn de Cappa (luego de Utrillas), hizo que se les conociera al principio, tambiв”ңВ®n, como "Cocheras de Cappa". A la izquierda, el original cocherв”ңв”Ӯn de 1885 que albergв”ңв”Ӯ las primeras unidades tranviarias de la ciudad. Lo que comenzв”ңв”Ӯ siendo una sencilla playa de tres vв”ңВЎas y una placa giratoria para maniobrar, fue sucesivamente ampliada hasta configurar unas enormes instalaciones en las que dar cobijo y reparaciв”ңв”Ӯn tranviaria a todas las lв”ңВЎneas, hasta la demoliciв”ңв”Ӯn programada de este fundamental, sostenible e impagable servicio pв”ңв•‘blico. La lв”ңВЎnea del cielo urbana de la в”ңВ®poca incluye, al fondo a la izquierda, una visual de la neoclв”ңГӯsica cв”ңв•‘pula de San Fernando, y del mausoleo a los fascistas italianos caв”ңВЎdos durante "la Cruzada". Justo detrв”ңГӯs de las cocheras, imagen parcial del depв”ңв”Ӯsito de locomotoras de la Estaciв”ңв”Ӯn de Utrillas, y la chimenea de la Estaciв”ңв”Ӯn, un poco mв”ңГӯs a la derecha. Este lugar serв”ңГӯ luego la primera ubicaciв”ңв”Ӯn de los autobuses urbanos de la ciudad, hasta que la zona sea urbanizada, resultando la construcciв”ңв”Ӯn de algunos nuevos bloques de viviendas, y el Colegio Pв”ңв•‘blico "Tomв”ңГӯs Alvira". Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ)', 1945, 1945, 1945, 'Anos 40', 'SAN JOSв”ңГ«', 41.63947700, -0.86637400, '0101000020E6100000BC5983F755B9EBBFA8C5E061DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20393387742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20393387742.webp', 'https://www.flickr.com/photos/zaragozaantigua/20393387742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25753, 'Fв”ңГӯbrica de Briquetas 1976', 'Imagen capturada junto a las ruinas de la antigua Fв”ңГӯbrica de Briquetas y conglomerados de la MFU (Minas y Ferrocarriles de Utrillas). Al fondo, el desarrollo urbanв”ңВЎstico mediante grandes bloques habitacionales en el entorno de la calle Castelar, Camino de Cabaldв”ңв”Ӯs, y Cartagena. Por aquв”ңВЎ pasaba el ramal de Utrillas que enlazaba con Miraflores y la fв”ңГӯbrica de cementos. Hoy, esta es la calle Ducado de Atenas, junto al CDM "La Granja". Fuente visual: Archivo Pв”ңв•‘blico Municipal, Gerardo Sancho Ramo, 1976.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSв”ңГ«', 41.63488200, -0.86691100, '0101000020E6100000705D3123BCBDEBBFD76839D043D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20870290524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20870290524.webp', 'https://www.flickr.com/photos/zaragozaantigua/20870290524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25763, 'Miguel Servet 1969', 'Luminosa imagen con el posado de un cobrador tranviario (Pablo Rodrв”ңВЎguez), en el acceso a las cocheras del tranvв”ңВЎa de la calle Miguel Servet. Al fondo, en leve penumbra, y de izquierda a derecha, una unidad de la serie 200, en la lв”ңВЎnea 11 "Parque-San Josв”ңВ®"; la unidad 105 de la lв”ңВЎnea 5 "Venecia-Delicias"; y la unidad 162 de la lв”ңВЎnea 1 "Plaza de San Miguel-Bajo Aragв”ңв”Ӯn". Estas cocheras estaban ubicadas cerca de la plaza de Utrillas (en la imagen, hacia la derecha), y la estaciв”ңв”Ӯn de ferrocarril de Utrillas (clausurada pocos aв”ңв–’os antes), cuyo mar de vв”ңВЎas y depв”ңв”Ӯsito de locomotoras quedaban detrв”ңГӯs. Fuente visual: Foto John Scragg, a travв”ңВ®s de www.forotrenes.com/', 1969, 1969, 1969, 'Anos 60', 'SAN JOSв”ңГ«', 41.63947700, -0.86637400, '0101000020E6100000BC5983F755B9EBBFA8C5E061DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31211239165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31211239165.webp', 'https://www.flickr.com/photos/zaragozaantigua/31211239165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25911, 'Tranvв”ңВЎa Bajo Aragв”ңв”Ӯn 1903', 'Unidad 2 del tranvв”ңВЎa elв”ңВ®ctrico de la lв”ңВЎnea del Bajo Aragв”ңв”Ӯn, con posado del dueв”ңв–’o de la empresa, Manuel Escoriaza y Fabro. Fuente: Foto para postal de Comercial Josan. Cesiв”ңв”Ӯn de la familia de Josв”ңВ® Marв”ңВЎa Sanz Gonzв”ңГӯlez a Rafael Castillejo. Dataciв”ңв”Ӯn y procesado:', 1903, 1903, 1903, 'Anos 1900', 'SAN JOSв”ңГ«', 41.63947700, -0.86637400, '0101000020E6100000BC5983F755B9EBBFA8C5E061DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27403753255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27403753255.webp', 'https://www.flickr.com/photos/zaragozaantigua/27403753255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25987, 'Miguel Servet 1956', 'Archivo Josв”ңВ® Mв”¬В¬ Borobio. 1956. Imagen aв”ңВ®rea del entorno de la calle Miguel Servet con vistas de la enorme fв”ңГӯbrica GIESA, del Colegio Santa Marв”ңВЎa del Pilar (Marianistas) y del palacio de Larrinaga. Al otro lado de la calle, aspecto parcial del descargadero de carbones del ferrocarril de Utrillas, y muros y verja de entrada a la Granja Agrв”ңВЎcola (extremo inferior, a la izquierda). Son visibles las vв”ңВЎas que conectaban a GIESA con la red ferroviaria. Un par de tranvв”ңВЎas, uno por direcciв”ңв”Ӯn, avanzan por Miguel Servet. Fuente visual: www.facebook.com/photo.php?fbid=398835526947784&set=p...', 1956, 1956, 1956, 'Anos 50', 'SAN JOSв”ңГ«', 41.63810900, -0.86501200, '0101000020E6100000BFB854A52DAEEBBF4224438EADD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15767299712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15767299712.webp', 'https://www.flickr.com/photos/zaragozaantigua/15767299712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26075, 'Vista aв”ңВ®rea San Josв”ңВ® c.1992', 'Vista aв”ңВ®rea capturada en la zona frontera entre los barrios de Las Fuentes y San Josв”ңВ®, sobrevolando el gran solar de la que fuera estaciв”ңв”Ӯn de ferrocarril de Utrillas hasta 1966, delimitada entre la calle de Miguel Servet, el camino de Cabaldв”ңв”Ӯs y el esbozo de lo que poco despuв”ңВ®s serв”ңВЎa la calle del Hermano Adolfo, que conecta ambos viales. En primer tв”ңВ®rmino, el gran solar resultante del derribo de casi todas las instalaciones ferroviarias, con los restos del semicircular depв”ңв”Ӯsito de locomotoras, la referencial chimenea y los dos grandes pabellones intactos y recayentes a la plaza de Utrillas. Aв”ңв•‘n habrв”ңВЎan de pasar unos aв”ңв–’os antes de la impactante intrusiв”ңв”Ӯn de una gran superficie comercial incrustada gracias al urbanismo a la carta de la в”ңВ®poca.', 1992, 1992, 1992, 'Anos 90', 'SAN JOSв”ңГ«', 41.63970900, -0.86789800, '0101000020E61000001D71C806D2C5EBBF7BFA08FCE1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52040773202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52040773202.webp', 'https://www.flickr.com/photos/zaragozaantigua/52040773202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22276, 'Calle del Brigadier Gasca 1961', 'Imagen parcial de las afecciones de la riada del Ebro en el barrio de la Ortilla capturada en la calle del Brigadier Gasca cerca de su confluencia con la calle del Almutazafe. Al fondo, el camino de Ranillas con la torre de Helios y la chimenea de la antigua fв”ңГӯbrica de tratamiento de lanas que emerge entre edificios de vivienda. Fuente visual: AMZ.', 1961, 1961, 1961, 'Anos 60', 'ACTUR-REY FERNANDO', 41.66126400, -0.88339000, '0101000020E61000004DA1F31ABB44ECBFD6027B4CA4D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14962404722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14962404722.webp', 'https://www.flickr.com/photos/zaragozaantigua/14962404722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22497, 'Barrio de la Ortilla 1961', 'Imagen capturada durante la antolв”ңв”Ӯgica salida de madre o riada del Ebro de enero de 1961, centrada en una barcaza que a fuerza de remo navega por una inundada zona de huerta del barrio de la Ortilla, entre el camino de Ranillas (a la derecha y fuera de plano), la calle de Buenos Aires (donde las parcelas y bloque de viviendas del frente), y las calles de Garcв”ңВЎa Gil y de Paraguay (a espaldas del fotв”ңв”Ӯgrafo). Sobre la original calle de Valero Ripoll emerge la chimenea de la antigua fabrica de "Manufacturas de lanas de Morв”ңв”Ӯn y Anв”ңв”Ӯs". Ya en la margen derecha y al fondo se siluetea el templo del Pilar, con la ribereв”ңв–’a torre de Santa Leonor en proceso de terminaciв”ңв”Ӯn, mв”ңГӯs tardana que la de San Francisco de Borja, ya finalizada.', 1961, 1961, 1961, 'Anos 60', 'ACTUR-REY FERNANDO', 41.66353400, -0.88545000, '0101000020E61000004BC8073D9B55ECBF5CE49EAEEED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48962578108.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48962578108.webp', 'https://www.flickr.com/photos/zaragozaantigua/48962578108/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22848, 'Calle Brigadier Gasca 1985', 'El barrio de La Ortilla estaba delimitado, en la margen izquierda, por la vв”ңВЎa fв”ңВ®rrea que enlazaba la estaciв”ңв”Ӯn del Norte con la de Campo Sepulcro, a travв”ңВ®s del Puente del Ferrocarril. El Camino de Ranillas, paralelo al rв”ңВЎo, vertebraba las calles que de в”ңВ®l nacieron: Hortilla, Buenos Aires, Almutazafe. En torno a ellas, se extendieron otras callecitas con parcelas de una y dos alturas mв”ңГӯximo: Escultor Lasuв”ңВ®n, Gв”ңв”Ӯmez de Butrв”ңв”Ӯn, Los Paisanos, y Brigadier Gasca. Las grandes inundaciones del Ebro afectaban mucho a esta zona, apenas unos metros por encima del nivel medio del rв”ңВЎo. El crecimiento de la Margen Izquierda, sobre todo a partir de la construcciв”ңв”Ӯn del Puente de Santiago y la apertura de la Avenida de los Pirineos, junto con la urbanizaciв”ңв”Ӯn ACTUR, fueron dejando como algo residual este antiguo barrio, cuyos alrededores se fueron poblando de nuevos y grandes bloques de viviendas. A mediados de los aв”ңв–’os 80 del pasado siglo, se consumв”ңв”Ӯ la desapariciв”ңв”Ӯn del barrio, con el piqueteo de las viejas construcciones, la desapariciв”ңв”Ӯn, incluso en el nomenclв”ңГӯtor, de sus calles, y la apertura de nuevos viales sobre la zona, que no conserva ningв”ңв•‘n vestigio de este pasado. En la imagen, в”ңв•‘ltimas viviendas en pie de la calle Brigadier Gasca. Al fondo, los bloques de las nuevas calles "Andador Rafaela Aparicio", y la plaza Ortilla (sin hache). mв”ңГӯs al fondo, los grandes bloques de Valle de Broto.', 1985, 1985, 1985, 'Anos 80', 'ACTUR-REY FERNANDO', 41.66336600, -0.88532200, '0101000020E6100000EDBC8DCD8E54ECBFA1A3552DE9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15213554628.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15213554628.webp', 'https://www.flickr.com/photos/zaragozaantigua/15213554628/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22985, 'George Clooney y Arnold Schwarzenegger 1997', 'Los dos actores estadounidenses, en la inauguraciв”ңв”Ӯn de los cines Warner Lusomundo en el centro comercial Grancasa del barrio del Actur de Zaragoza, en 1997. Fuente: www.elperiodicodearagon.com/', 1997, 1997, 1997, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66939200, -0.88964600, '0101000020E6100000098D60E3FA77ECBF1E1A16A3AED54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19666380770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19666380770.webp', 'https://www.flickr.com/photos/zaragozaantigua/19666380770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23024, 'Actur 1992', 'Imagen capturada desde la altura de los bloques de viviendas de la calle de Marв”ңВЎa Montessori y vertebrada por la perspectiva del alabeado eje central del barrio del Actur, popularmente denominado "la salchicha", flanqueado por las calles de Marв”ңВЎa Zambrano a la derecha, y Gertrudis Gв”ңв”Ӯmez de Avellaneda a la izquierda, reservado para servicios y que en el momento de realizar esta fotografв”ңВЎa ya contaba con una gran superficie comercial inaugurada en 1990, en el tramo al norte de la calle de Pablo Ruiz Picasso. En 1992 la Diputaciв”ңв”Ӯn General de Aragв”ңв”Ӯn gobernada por la coaliciв”ңв”Ӯn PAR-PP aprobв”ңв”Ӯ el proyecto presentado por pequeв”ңв–’os y medianos comerciantes organizados en la sociedad "Grandes в”ңГјreas Comerciales de Aragв”ңв”Ӯn, S.A.", para construir un gran centro comercial que se ubicarв”ңВЎa al fondo de la imagen, en en tramo de "la salchicha" comprendido entre las calles de Mariana Pineda/Nicolв”ңГӯs Guillв”ңВ®n y la referida de Pablo Ruiz Picasso, y que serв”ңВЎa inaugurado en marzo de 1997.', 1992, 1992, 1992, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66496100, -0.88497800, '0101000020E61000005EBEF561BD51ECBFC70E2A711DD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50201661306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50201661306.webp', 'https://www.flickr.com/photos/zaragozaantigua/50201661306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23044, 'Calle de Marв”ңВЎa Zambrano 1991', 'Imagen capturada desde el bloque de viviendas del nв”¬в•‘ 49 de la calle de Gertrudis Gв”ңв”Ӯmez de Avellaneda y centrada parcialmente en el espacio denominado de forma coloquial "la salchicha", delimitado entre esta calle, la paralela de la Poetisa Marв”ңВЎa Zambrano, y la perpendicular de Pablo Ruiz Picasso (a la izquierda, fuera de plano), y la avenida del Valle de Broto, al fondo. A esta altura se destacan, en una zona donde seguв”ңВЎan creciendo bloques, los inmuebles del nв”¬в•‘ 16 de la Poetisa Marв”ңВЎa Zambrano, el nв”¬в•‘ 4 de la calle del Poeta Pablo Neruda, y el nв”¬в•‘ 2 de la calle del Poeta Leв”ңв”Ӯn Felipe, ademв”ңГӯs de la Urbanizaciв”ңв”Ӯn Kasв”ңГӯn. En 1992 la Diputaciв”ңв”Ӯn General de Aragв”ңв”Ӯn gobernada por la coaliciв”ңв”Ӯn PAR-PP aprobв”ңв”Ӯ el proyecto presentado por pequeв”ңв–’os y medianos comerciantes organizados en la sociedad "Grandes в”ңГјreas Comerciales de Aragв”ңв”Ӯn, S.A.", para construir un gran centro comercial que se habrв”ңВЎa de ubicar aquв”ңВЎ, siendo inaugurado en marzo de 1997. En primer tв”ңВ®rmino, farolas con carteles publicitarios de los candidatos del PSOE a la alcaldв”ңВЎa del Ayuntamiento y a la presidencia de la Diputaciв”ңв”Ӯn General en las elecciones de mayo de 1991.', 1991, 1991, 1991, 'Anos 90', 'ACTUR-REY FERNANDO', 41.67000200, -0.88984900, '0101000020E6100000111B2C9CA479ECBF962023A0C2D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50431784766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50431784766.webp', 'https://www.flickr.com/photos/zaragozaantigua/50431784766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24733, 'Polв”ңВЎgono de Santiago 1976', 'Aв”ңВ®rea vista del Polв”ңВЎgono de Santiago en 1976, en proceso de delimitaciв”ңв”Ӯn urbanв”ңВЎstica de solares y viales, previa a su construcciв”ңв”Ӯn. En primer plano, el antiguo puente sobre el Ebro ya desmantelado de sus funciones ferroviarias (como la lв”ңВЎnea que venв”ңВЎa desde la Estaciв”ңв”Ӯn del Norte). A la derecha, campos de cultivo y parcelas del Arrabal, y un pedazo de la urbanizaciв”ңв”Ӯn Puente de Santiago. Esta enorme pastilla ya tenв”ңВЎa dos residentes: el Colegio del Sagrado Corazв”ңв”Ӯn, al fondo, trasladado hacв”ңВЎa poco desde el Paseo Mola, y su vecino el Colegio El Pilar (Maristas), en pleno frenesв”ңВЎ constructivo.', 1976, 1976, 1976, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66500600, -0.89047500, '0101000020E6100000ADFA5C6DC57EECBF67D2A6EA1ED54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866791147.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866791147.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866791147/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24734, 'ACTUR 1976', 'Vista del polв”ңВЎgono Actur, al fondo, luego denominado del Rey Fernando. En primer tв”ңВ®rmino, instalaciones deportivas del Club Nataciв”ңв”Ӯn Helios. Al fondo y a la izquierda, la urbanizaciв”ңв”Ӯn Kasan, todavв”ңВЎa desacompaв”ңв–’ada de otros edificios. En el centro, el antiguo barrio de La Ortilla-Ranillas vertebrado por el camino de Ranillas, con sus campos de cultivo. Cruza en la parte superior la avenida de los Pirineos, que prosigue luego como carretera de Huesca.', 1976, 1976, 1976, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66270100, -0.88391300, '0101000020E6100000C24B70EA0349ECBF6403E962D3D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14959278361.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14959278361.webp', 'https://www.flickr.com/photos/zaragozaantigua/14959278361/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24957, 'Parque de Primo de Rivera 1970', 'Imagen capturada desde la altura del cabezo de Buenavista y centrada en el paseo de San Sebastiв”ңГӯn del parque de Primo de Rivera, donde en primer tв”ңВ®rmino circula el famoso "tren del parque" por el espacio donde en enero de 1974 se instalв”ңв”Ӯ la famosa fuente luminosa proveniente de la plaza de Basilio Paraв”ңВЎso. Al fondo, la referente torre-mirador de la Feria de Muestras, la plaza del Emperador Carlos V y el tramo final del paseo de Fernando el Catв”ңв”Ӯlico.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63458500, -0.89451600, '0101000020E6100000A5F5B704E09FECBF1EC4CE143AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51680986266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51680986266.webp', 'https://www.flickr.com/photos/zaragozaantigua/51680986266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24779, 'Ortilla-Ranillas 1977', 'Desde las alturas del novв”ңВЎsimo edificio Kasв”ңГӯn, excepcional vista panorв”ңГӯmica de los antiguos, y desaparecidos, barrios de la Ortilla, y de Ranillas, en la margen izquierda del Ebro. El de la Ortilla, a la izquierda, y centro, en el entorno de la carretera de Huesca, y parte del trazado del bucle ferroviario que provenв”ңВЎa de la estaciв”ңв”Ӯn del Norte. Tras su desmantelamiento en 1976, junto con el paso a nivel que cruzaba la avenida de los Pirineos, este antiguo camino de hierro aparece en la imagen convertido en un ancho (y temporal) camino viario. Junto a в”ңВ®l, las calles Brigadier Gasca, Almutazafe, Antillв”ңв”Ӯn, Gв”ңв”Ӯmez Butrв”ңв”Ӯn. Otra zona del barrio, mв”ңГӯs central, frente a Helios, junto a la chimenea fabril de "Manufacturas de lanas de Morв”ңв”Ӯn y Anв”ңв”Ӯs", con las calles Escultor Lasuв”ңВ®n, Valerio Ripoll, Ortilla, Buenos Aires. El barrio de Ranillas, hacia la derecha, era mв”ңГӯs vecino del puente del ferrocarril. Entre ambos, se articulaba un difuso entorno periurbano de parcelas, campos de cultivos, riegos, y calles de tierra. Al fondo, tras el Ebro, Zaragoza, tan cerca, y tan lejos. Fuente visual: Josв”ңВ® Manuel Larroy Calvo, en www.facebook.com/photo.php?fbid=10204683358395723&set...', 1977, 1977, 1977, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66352000, -0.88366800, '0101000020E6100000FFB1101D0247ECBFF71E2E39EED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26568717311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26568717311.webp', 'https://www.flickr.com/photos/zaragozaantigua/26568717311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24812, 'Cocheras Parque Goya 2011', 'Foto: Asier Alcorta. Vista del inicio de la construcciв”ңв”Ӯn de las cocheras del tranvв”ңВЎa en Parque Goya, en mayo de 2011. En 2013 se pondrв”ңГӯ en servicio la segunda fase de la lв”ңВЎnea 1, habilitв”ңГӯndose este espacio como aparcamiento y taller de los convoyes, ademв”ңГӯs del preexistente en Valdespartera. Tras la Ronda de Boltaв”ңв–’a y, mв”ңГӯs allв”ңГӯ, la avenida de la Majas de Goya, se ven edificios del Campus Rв”ңВЎo Ebro y jalones lejanos como la Estaciв”ңв”Ӯn Delicias, el puente del Tercer Milenio y la Torre del Agua. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2011, 2011, 2011, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.68897900, -0.88435600, '0101000020E61000001DAF40F4A44CECBFBE50C07630D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36969643034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36969643034.webp', 'https://www.flickr.com/photos/zaragozaantigua/36969643034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24993, 'Campo de Ranillas c.1995', 'Imagen del "campo de fв”ңв•‘tbol" de Ranillas habilitado sin grandes inversiones en la esquinera pastilla entre la avenida de Ranillas y la calle del Valle de Broto. Un par de porterв”ңВЎas sin red, una pelota, y a jugar. En primer tв”ңВ®rmino, usuarios de este campo posan junto a su entrenador. Al fondo, bloques inmediatos a la calle del Ebro Viejo, tras la de Valle de Broto. Al fondo y a la derecha, la moderna iglesia parroquial de San Andrв”ңВ®s Apв”ңв”Ӯstol y bloques recayentes a la plaza de la Ortilla. En este espacio se reubicarв”ңВЎa, aв”ңв–’os despuв”ңВ®s, el Pabellв”ңв”Ӯn de Aragв”ңв”Ӯn de la Expo 1992, adquirido en 1998 al precio de una peseta por la Confederaciв”ңв”Ӯn Regional de Empresarios de Aragв”ңв”Ӯn, y desde 2003 su sede social. Poco despuв”ңВ®s entrarв”ңВЎa en funcionamiento el campo municipal de fв”ңв•‘tbol "Nuevo Ranillas" en unas mв”ңГӯs norteв”ңв–’as, occidentales y adecuadas instalaciones junto a la avenida de Ranillas.', 1995, 1995, 1995, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66260500, -0.88725300, '0101000020E610000075E448676064ECBF42959A3DD0D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50431546053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50431546053.webp', 'https://www.flickr.com/photos/zaragozaantigua/50431546053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26008, 'La Ortilla 1984', 'Foto: Josв”ңВ® Manuel Larroy. Panorв”ңГӯmica del antiguo barrio de La Ortilla el 11 de septiembre de 1984. En el centro, la calle de Marв”ңВЎa Zambrano. Sobre el conjunto de casas aв”ңв•‘n sin derruir, se levanta hoy la Corporaciв”ңв”Ӯn Aragonesa de Radio y Televisiв”ңв”Ӯn. Al fondo, manifestaciв”ңв”Ӯn contra la construcciв”ңв”Ӯn de barracones para gitanos. Fuente: www.facebook.com/photo.php?fbid=10204678161265798&set...', 1984, 1984, 1984, 'Anos 80', 'ACTUR-REY FERNANDO', 41.66270100, -0.88391300, '0101000020E6100000C24B70EA0349ECBF6403E962D3D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22283164118.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22283164118.webp', 'https://www.flickr.com/photos/zaragozaantigua/22283164118/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23086, 'Acuario fluvial 2007', 'Construcciв”ңв”Ӯn del acuario fluvial de Zaragoza, proyecto de в”ңГјlvaro Planchuelo para el recinto de la Expo 2008. Fuente: picasaweb.google.com/CHELUYS', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66917500, -0.89874400, '0101000020E61000003A3DEFC682C2ECBF8126C286A7D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19778397710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19778397710.webp', 'https://www.flickr.com/photos/zaragozaantigua/19778397710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23089, 'Pabellв”ңв”Ӯn de Aragв”ңв”Ӯn 2007', 'Construcciв”ңв”Ӯn del Pabellв”ңв”Ӯn de Aragв”ңв”Ӯn de la Expo 2008, obra de Daniel Olano. Fuente: picasaweb.google.com/CHELUYS', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67066500, -0.89804800, '0101000020E6100000669FC728CFBCECBF32C9C859D8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19971953411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19971953411.webp', 'https://www.flickr.com/photos/zaragozaantigua/19971953411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23134, 'Expo 2008, 2007', 'Foto: Oliver Duch. Vista aв”ңВ®rea de las obras de construcciв”ңв”Ӯn de la Expo 2008 en el meandro de Ranillas del rв”ңВЎo Ebro, en octubre de 2007. A la izquierda, el Actur, con el puente de La Almozara y la pasarela del Voluntariado en construcciв”ңв”Ӯn. Arriba, La Almozara y Las Delicias. A la derecha, el Pabellв”ңв”Ӯn Puente en construcciв”ңв”Ӯn. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66915400, -0.90079700, '0101000020E610000099B7EA3A54D3ECBF69FE98D6A6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31711700393.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31711700393.webp', 'https://www.flickr.com/photos/zaragozaantigua/31711700393/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23143, 'Centro de visitantes 2006', 'Foto: Juan Carlos Arcos. Obras de construcciв”ңв”Ӯn del Centro de visitanes de la Expo 2008, en mayo de 2006. Serв”ңГӯ inaugurado al mes siguiente. Se encuentra en la confluencia de la avenida de Raniiilas con la calle Pablo Ruiz Picasso. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67234700, -0.89678200, '0101000020E6100000F086342A70B2ECBF28486C770FD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31940157065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31940157065.webp', 'https://www.flickr.com/photos/zaragozaantigua/31940157065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23163, 'Apartotel Acqua 2007', 'Foto: в”ңГјlvaro Calvo. Obras de construcciв”ңв”Ӯn del apartotel Acqua, en diciembre de 2007, cuando ya se sabв”ңВЎa que no estarв”ңВЎa listo para la inauguraciв”ңв”Ӯn de la Expo 2008, que le daba supuesta razв”ңв”Ӯn de ser. Era uno de los dos establecimientos hoteleros previstos en el meandro de Ranillas, con el faraв”ңв”Ӯnico Hiberus. Nunca fue terminado. En 2011, se vendiв”ңв”Ӯ al Banco Espirito Santo, que quebrв”ңв”Ӯ en 2014. Su estructura degradada permanece varada en el parque del Agua Luis Buв”ңв–’uel. En 2017 se acondiciona como residencia de ancianos. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67241900, -0.90008700, '0101000020E610000087C0914083CDECBFC11A67D311D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32614536515.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32614536515.webp', 'https://www.flickr.com/photos/zaragozaantigua/32614536515/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23416, 'Plataforma Logв”ңВЎstica 2006', 'Ortofoto de la Plataforma Logв”ңВЎstica de Zaragoza obtenida el 6 de febrero de 2006. Arriba, Canal Imperial de Aragв”ңв”Ӯn. A la derecha, Autovв”ңВЎa del Nordeste. Fuente: Gobierno de Aragв”ңв”Ӯn. Departamento de Presidencia y Relaciones Institucionales. Centro de Documentaciв”ңв”Ӯn e Informaciв”ңв”Ӯn Territorial de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.64633800, -0.97668400, '0101000020E6100000CBD8D0CDFE40EFBFBE141E34BBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31256847764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31256847764.webp', 'https://www.flickr.com/photos/zaragozaantigua/31256847764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24754, 'Exposiciв”ңв”Ӯn Internacional 2008', 'Mapa oficial del recinto de la Exposiciв”ңв”Ӯn Internacional "Agua y desarrollo sostenible", celebrada en el Meandro de Ranillas de Zaragoza, del 14 de junio al 14 de septiembre de 2008. Realizado por Expo Agua Zaragoza 2008 S. A. En la ciudad se habв”ңВЎan celebrado anteriormente la Exposiciв”ңв”Ӯn Aragonesa de 1868 (en el Salв”ңв”Ӯn de Pignatelli, actual plaza de Aragв”ңв”Ӯn); la Exposiciв”ңв”Ӯn Aragonesa de 1885 (en el luego Matadero Municipal); y la Exposiciв”ңв”Ӯn Hispano Francesa de 1908 (en la Huerta de Santa Engracia, hoy plaza de Los Sitios). Tras la muestra de 2008, se pretendiв”ңв”Ӯ realizar Expo Paisajes (plan B de 2008), de mayo a octubre de 2014 en la Huerta de las Fuentes, pero este proyecto no se llevв”ңв”Ӯ a cabo, salvando asв”ңВЎ de momento una tercera zona de huertas que se habrв”ңВЎa suprimido. Posteriormente se propuso sin в”ңВ®xito como ubicaciв”ңв”Ӯn la desembocadura del rв”ңВЎo Gв”ңГӯllego. La Expo 2008 supuso la creaciв”ңв”Ӯn de edificios que permanecen en la antigua Huerta de Ranillas, como el Pabellв”ңв”Ӯn Puente, los de Espaв”ңв–’a y Aragв”ңв”Ӯn, la Torre del Agua, el Acuario fluvial, el Palacio de Congresos y los pabellones de los 108 paв”ңВЎses participantes, estos в”ңв•‘ltimos reconvertidos en oficinas. El grueso de los visitantes, en contra de lo previsto, provino de la propia ciudad.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66991200, -0.90143800, '0101000020E61000008AE42B8194D8ECBF569929ADBFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19291702714.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19291702714.webp', 'https://www.flickr.com/photos/zaragozaantigua/19291702714/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24790, 'Mijaв”ңВЎl Gorbachov 2008', 'Mijaв”ңВЎl Gorbachov, mв”ңГӯximo dirigente de la Uniв”ңв”Ӯn Soviв”ңВ®tica desde 1985 hasta su disoluciв”ңв”Ӯn en 1991, da una conferencia el 9 de septiembre en la Tribuna del Agua de la Expo 2008. Tras в”ңВ®l, una reproducciв”ңв”Ӯn de Fluvi, mascota oficial de la muestra, diseв”ңв–’ada por Sergi Lв”ңв”Ӯpez Jordana. Fuente: www.gozazaragoza.com/', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66960600, -0.90194300, '0101000020E61000006765FB90B7DCECBF4A9A3FA6B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31993100644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31993100644.webp', 'https://www.flickr.com/photos/zaragozaantigua/31993100644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24795, 'Noria siria 2008', 'Estructura diseв”ңв–’ada por Juan Antonio Ros, que soportarв”ңГӯ la noria situada en la cabecera del parque del Agua Luis Buв”ңв–’uel. Fue construida por artesanos de Hama, ciudad de Siria, segв”ңв•‘n una idea de Nicolas Camoisson y Marion Coudert, que la bautizaron como Noria de la Paz. Constaba de 24 brazos y 96 cangilones de madera, que fueron sustituidos por acero corten tres aв”ңв–’os despuв”ңВ®s, debido a su deterioro. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67625000, -0.89982900, '0101000020E61000009CC1DF2F66CBECBFC3F5285C8FD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32710571126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32710571126.webp', 'https://www.flickr.com/photos/zaragozaantigua/32710571126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24828, 'Gorbachov en la Expo 2008', 'Imagen de Mijaв”ңВЎl Serguв”ңВ®yevich Gorbachov (1931-2022) capturada durante su visita el dв”ңВЎa 9 de septiembre al recinto de la Expo 2008. Personaje central en la historia mundial de finales del siglo XX, fue secretario general del Comitв”ңВ® Central del Partido Comunista de la Uniв”ңв”Ӯn Soviв”ңВ®tica (1985-1991) y jefe de Estado de la Uniв”ңв”Ӯn Soviв”ңВ®tica (1988-1991). En esta visita se paseв”ңв”Ӯ por la Tribuna del Agua y el pabellв”ңв”Ӯn de Rusia, antes de subir a Huesca a presentar su libro "Agua para la Paz". Pocos dв”ңВЎas despuв”ңВ®s (19 de septiembre) recibiв”ңв”Ӯ la Medalla de la Libertad de Filadelfia 2008, otorgada por el Centro Nacional de la Constituciв”ңв”Ӯn de los Estados Unidos de norteamв”ңВ®rica, presidido por el expresidente George H.W. Bush.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66915400, -0.90079700, '0101000020E610000099B7EA3A54D3ECBF69FE98D6A6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52474352209.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52474352209.webp', 'https://www.flickr.com/photos/zaragozaantigua/52474352209/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26060, 'Juslibol 1939', 'Imagen capturada en vuelo y centrada en un bombardero He-111 de в”ңв•‘ltima generaciв”ңв”Ӯn (serie E-1, numeral 25-98) que se dirige al aerв”ңв”Ӯdromo Sanjurjo de Zaragoza, mientras sobrevuela el norte de Ranillas y el sur del monte de Juslibol, cuyos verticales Cortados delimitan perfectamente la ubв”ңВ®rrima huerta cercana al rв”ңВЎo Ebro, que fluye por el antiguo cauce que lamв”ңВЎa los Cortados en la zona del Soto del Cabildo. Este aparato, que posiblemente regresa de una misiв”ңв”Ӯn en el frente de Cataluв”ңв–’a, formaba parte del Kampfgruppe 88 de la Legiв”ңв”Ӯn Cв”ңв”Ӯndor instalado en Zaragoza desde 1937. Casi 100 unidades de este modelo, en tres distintas series, formaron parte del contingente de unos 600 aviones y 16000 soldados que llegaron desde la Alemania nazi para apoyar de forma decisiva el esfuerzo de guerra de los nacionalistas espaв”ңв–’oles durante la guerra de 1936-39. El de Zaragoza fue uno de sus aerв”ңв”Ӯdromos mв”ңГӯs significados. Fuente visual: foto Francisco Andreu, en www.aviationcorner.net/', 1939, 1939, 1939, 'Anos 30', 'ACTUR-REY FERNANDO', 41.68997900, -0.89803600, '0101000020E6100000552E54FEB5BCECBFA1F65B3B51D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35097343246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35097343246.webp', 'https://www.flickr.com/photos/zaragozaantigua/35097343246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22263, 'Enlace ferroviario 1966', 'El enlace ferroviario de la margen izquierda fue construido a mediados del siglo XIX para unir las lв”ңВЎneas de Barcelona y Pamplona, mediante una gran curva trazada por la arboleda de Macanaz, sobre el camino de Ranillas y la huerta de la Ortilla. Con el tiempo, esta zona apenas poblada fue poco a poco siendo urbanizada, dando lugar al barrio de la Ortilla, que esta vista aв”ңВ®rea aparece delimitado en un espacio mayoritariamente agrв”ңВЎcola, con la presencia de alguna instalaciв”ңв”Ӯn industrial. Entre el puente de Piedra, al fondo, y el puente del Ferrocarril, en primer tв”ңВ®rmino, destaca la obra del puente de Santiago, cuyo acceso por la avenida de los Pirineos requiriв”ңв”Ӯ instalar un nuevo paso a nivel. En 1973 circulв”ңв”Ӯ el в”ңв•‘ltimo tren de pasajeros, y en 1975 se cerrв”ңв”Ӯ tambiв”ңВ®n al trв”ңГӯfico de mercancв”ңВЎas. En 1976 este enlace fue desmantelado, mientras esta perifв”ңВ®rica zona fue intensamente urbanizada.', 1966, 1966, 1966, 'Anos 60', 'ACTUR-REY FERNANDO', 41.66144100, -0.88240400, '0101000020E6100000B6813B50A73CECBFE59D4319AAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14795533619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14795533619.webp', 'https://www.flickr.com/photos/zaragozaantigua/14795533619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22575, 'Paso a nivel Av. Pirineos 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 10/03/1974. Como forma de enlazar las estaciones del Norte (ferrocarriles a Barcelona), y la de Campo Sepulcro (ferrocarril a Madrid), se construyв”ңв”Ӯ un enlace por la margen izquierda, a travв”ңВ®s de la arboleda de Macanaz, y cruzando el Ebro por el Puente del Ferrocarril (1870). Cuando desde Campo Sepulcro, a travв”ңВ®s de Miraflores, se pudo hacer directo el trayecto hacia Barcelona, este enlace fue quedando en progresivo desuso. A mediados de los aв”ңв–’os 70 del pasado siglo circulв”ңв”Ӯ el в”ңв•‘ltimo tren de pasajeros, y a principios de los 80 se cerrв”ңв”Ӯ tambiв”ңВ®n al trв”ңГӯfico de mercancв”ңВЎas. Mientras tanto, la Margen Izquierda, antes poco poblada, se estaba llenando de edificios de viviendas, y ya se habв”ңВЎa tenido que habilitar un paso a nivel sobre la nueva Avenida de los Pirineos. En la imagen, una de las в”ңв•‘ltimas "vaporosas" por este paso a nivel, camino de la Estaciв”ңв”Ӯn del Norte. Al fondo, los montes de Juslibol.', 1974, 1974, 1974, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66194700, -0.88091200, '0101000020E61000002DEDD45C6E30ECBFB857E6ADBAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15415413991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15415413991.webp', 'https://www.flickr.com/photos/zaragozaantigua/15415413991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22629, 'Calle del Almutazafe 1974', 'Imagen de la calle "Almutazafe" del antiguo barrio de "La Ortilla". En torno al lavadero de lanas conocido como "Manufacturas de lanas de Morв”ңв”Ӯn y Anв”ңв”Ӯs", de finales de la dв”ңВ®cada de 1910, fueron apareciendo viviendas articuladas en nuevas calles que poco a poco se definieron en la nueva barriada de la Ortilla, a la derecha de la Arboleda o Soto de Macanaz, con entrada por la calle de Garcв”ңВЎa Arista, y hasta la lв”ңВЎnea del ferrocarril de los Enlaces. Al otro lado del Camino de Ranillas, en los aв”ңв–’os 20 se estableciв”ңв”Ӯ el Centro Naturista Helios, y a mediados de los aв”ңв–’os 30 el barrio se afirma con calles como Nicolв”ңГӯs Lomba, Gimв”ңВ®nez, Vicente Arnal, y Sebastiв”ңГӯn Banzo. Tras el 18 de julio de 1936, la redenominaciв”ңв”Ӯn impuesta de viales tambiв”ңВ®n alcanzarв”ңГӯ a esta barriada: ya en 1941, Sebastiв”ңГӯn Banzo serв”ңГӯ "Buenos Aires", y desde 1943 Nicolв”ңГӯs Lomba serв”ңГӯ "Valero Ripoll", Gimв”ңВ®nez, "Los Paisanos", y Vicente Arnal, "Ortilla". El crecimiento urbano propiciв”ңв”Ӯ luego la apariciв”ңв”Ӯn de nuevos viales como Brigadier Gasca, Escultor Lasuв”ңВ®n, Gв”ңв”Ӯmez de Butrв”ңв”Ӯn, y esta de la imagen, "Almutazafe", en referencia al antiguo AlmuГҹВ©Г‘tasв”ңГӯb, responsable municipal de asegurar que la actividad de los mercados se ceв”ңв–’в”ңВЎa a las ordenanzas establecidas en lo referido a pesos, medidas y precios. El crecimiento de la Margen Izquierda, sobre todo a partir de la construcciв”ңв”Ӯn del Puente de Santiago y la apertura de la Avenida de los Pirineos, junto con la urbanizaciв”ңв”Ӯn de la ACTUR, dejв”ңв”Ӯ a este antiguo barrio como algo viejo y residual, comparado con los modernos y grandes bloques de viviendas que anunciaban la epifanв”ңВЎa del futuro. A mediados de los aв”ңв–’os 80 del pasado siglo, con la urbanizaciв”ңв”Ӯn de las в”ңГјreas 15, 16 y 17 de la ACTUR, se consumв”ңв”Ӯ la desapariciв”ңв”Ӯn por derribo del barrio, de las viejas construcciones, y de su nomenclв”ңГӯtor. Lo que ha venido despuв”ңВ®s no conserva ningв”ңв•‘n vestigio de este pasado, salvo la circunstancial chimenea del lavadero de lanas. En la imagen, la calle Almutazafe junto al curso de la acequia del Brazal', 1974, 1974, 1974, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66199500, -0.88267200, '0101000020E61000008509A359D93EECBFC98E8D40BCD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20163631575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20163631575.webp', 'https://www.flickr.com/photos/zaragozaantigua/20163631575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22724, 'Vista paso a nivel 1973', 'Desde el Edificio de Kasan, una vista en altura de la margen izquierda. Al fondo, y tras la arboleda de Macanaz, vista de la fachada ribereв”ңв–’a de la ciudad de la que destacan las torres de la Seo y el Pilar, y entre las que sobresale casualmente la torre de viviendas Hв”ңГӯbitat Don 2000, levantada junto al rв”ңВЎo Huerva en 1973. La avenida de los Pirineos, en el centro, es cruzada mediante un paso a anivel por la lв”ңВЎnea ferroviaria procedente de la estaciв”ңв”Ӯn del Arrabal, y con continuidad luego sobre el puente del Ferrocarril hasta la estaciв”ңв”Ӯn de Caminreal. A la derecha, el puente de Santiago, proyectado como cruce sobre el Ebro para dar salida a la Vв”ңВЎa Imperial hacia el norte. Se ofrece tambiв”ңВ®n un aspecto parcial del barrio de La Ortilla, en primer tв”ңВ®rmino. El cierre, poco despuв”ңВ®s, del citado paso a nivel, acelerarв”ңГӯ la radical transformaciв”ңв”Ӯn de este entorno.', 1973, 1973, 1973, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66141200, -0.88116300, '0101000020E6100000793F6EBF7C32ECBF4A97FE25A9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30471849780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30471849780.webp', 'https://www.flickr.com/photos/zaragozaantigua/30471849780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23045, 'Av. de los Pirineos 1992', 'Imagen de la entrada a Zaragoza a travв”ңВ®s de la avenida de los Pirineos (antigua carretera de Huesca) que conduce al puente de Santiago, con el tradicional telв”ңв”Ӯn de fondo del templo del Pilar. Un poco mв”ңГӯs adelante se abre la gran rotonda donde confluye el trв”ңГӯfico desde la calle del Valle de Broto y hacia la derecha da acceso hacia el puente de La Almozara. Esta tв”ңВЎpica vista para los usuarios de esta carretera se verв”ңВЎa eclipsada cuando a finales de la dв”ңВ®cada comenzв”ңв”Ӯ la construcciв”ңв”Ӯn de dos grandes bloques de viviendas en sendos solares de la calle de Palencia, y otros algo mв”ңГӯs tarde en la de Fernando Gracia Gazulla, en parte recayentes al parque del Tв”ңВЎo Jorge.', 1992, 1992, 1992, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66824700, -0.88017200, '0101000020E6100000705B5B785E2AECBF3753211E89D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50432582352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50432582352.webp', 'https://www.flickr.com/photos/zaragozaantigua/50432582352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23233, 'Parque Che Guevara 2021', 'Desde 1988 el comandante Ernesto "Che" Guevara daba nombre a un parque y una calle en el barrio del Actur, en la esquinera ubicaciв”ңв”Ӯn entre las calles de Pablo Ruiz Picasso, Pablo Neruda y la avenida de los Pirineos, junto al colegio del Sagrado Corazв”ңв”Ӯn. La entrada en el Ayuntamiento y en 2019 del partido polв”ңВЎtico de extrema derecha VOX supuso el inicio de una campaв”ңв–’a para erradicar esta denominaciв”ңв”Ӯn que, finalmente y con el respaldo de PP y Ciudadanos, ha sido aprobada a espaldas del movimiento vecinal del barrio. En la imagen, aspecto del antiguo parque del Che Guevara desde su ingreso por la calle de Pablo Neruda a la altura de la parroquia de San Andrв”ңВ®s Apв”ңв”Ӯstol. Hacia el fondo y a la derecha, bloques de viviendas de la calle del Polв”ңВЎtico Augusto Bebel.', 2021, 2021, 2021, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67053900, -0.88243600, '0101000020E61000008E041A6CEA3CECBFA5D8D138D4D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51392689503.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51392689503.webp', 'https://www.flickr.com/photos/zaragozaantigua/51392689503/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24057, 'La Ortilla 1984', 'Foto: Juan Gonzв”ңГӯlez Misis. Despliegue policial en el barrio de la Ortilla, con motivo de las protestas vecinales ante el plan de instalaciв”ңв”Ӯn de 36 viviendas prefabricadas para alojar a poblaciв”ңв”Ӯn gitana chabolista. Al fondo, edificio Kasan. Fuente: Heraldo de Aragв”ңв”Ӯn.', 1984, 1984, 1984, 'Anos 80', 'ACTUR-REY FERNANDO', 41.66458600, -0.88240800, '0101000020E61000001152B7B3AF3CECBF92B06F2711D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31727004246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31727004246.webp', 'https://www.flickr.com/photos/zaragozaantigua/31727004246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24730, 'Colegio del Sagrado Corazв”ңв”Ӯn 1976', '"El 21 de Noviembre de 1800, Magdalena Sofв”ңВЎa Barat, funda en Francia la Congregaciв”ңв”Ӯn de Religiosas del Sagrado Corazв”ңв”Ӯn de Jesв”ңв•‘s. En Octubre de 1875 abre sus puertas en Zaragoza el Colegio del Sagrado Corazв”ңв”Ӯn, que cien aв”ңв–’os despuв”ңВ®s, en 1976 se traslada a su actual emplazamiento." Fuente: Fundaciв”ңв”Ӯn Sofв”ңВЎa Barat. En la foto, el edificio reciв”ңВ®n construido, con la actual calle Pablo Neruda en primer tв”ңВ®rmino y la avenida de los Pirineos tras el colegio, atravesada por el puente de la calle Pablo Ruiz Picasso.', 1976, 1976, 1976, 'Anos 70', 'ACTUR-REY FERNANDO', 41.67147700, -0.88287500, '0101000020E61000008D976E128340ECBF138255F5F2D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14758643307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14758643307.webp', 'https://www.flickr.com/photos/zaragozaantigua/14758643307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24753, 'Barrio de Ranillas 1977', 'Con el tв”ңВЎtulo de Niв”ңв–’o y perro, esta fotografв”ңВЎa expresionista muestra una de las infraviviendas del barrio de la Ortilla, en la margen izquierda del rв”ңВЎo Ebro. Como contraste, sobresalen al fondo las torres de la Seo y del Pilar. Este entorno, tan lejos y tan cerca del centro urbano, aunaba asentamientos como el que centra la imagen, con edificaciones de tipologв”ңВЎa rural, y estaba в”ңВЎntimamente relacionado con el paso del tendido ferroviario en amplia curva, procedente de la estaciв”ңв”Ӯn del Arrabal. La urbanizaciв”ңв”Ӯn de la zona acabв”ңв”Ӯ con todos estos hitos, desplazв”ңГӯndolos a otras latitudes mв”ңГӯs perifв”ңВ®ricas, donde el chabolismo continв”ңв•‘a siendo una realidad social. Perduran como в”ңв•‘nicos recuerdos de este entorno la chimenea de la Lanera Aragonesa y la denominaciв”ңв”Ӯn de la actual plaza de la Ortilla, en el extremo occidental del barrio del Arrabal, lindando ya con el Actur.', 1977, 1977, 1977, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66350900, -0.88120300, '0101000020E6100000066344A2D032ECBF03CDE7DCEDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19071830190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19071830190.webp', 'https://www.flickr.com/photos/zaragozaantigua/19071830190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24763, 'La Ortilla 1976', 'Foto Peв”ңв–’a Ramos, 1976. Vista desde el edificio Kasв”ңГӯn del barrio de La Ortilla de Zaragoza nevado, en la margen izquierda del Ebro, hoy desaparecido. Fuente: www.facebook.com/photo.php?fbid=789703231085642&set=g...', 1976, 1976, 1976, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66228100, -0.88195500, '0101000020E6100000D46531B1F938ECBF8FE1B19FC5D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20382873708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20382873708.webp', 'https://www.flickr.com/photos/zaragozaantigua/20382873708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24777, 'Padre de Huв”ңВ®rfanos 1977', 'Inв”ңВ®dita imagen de la desaparecida calle "Padre de Huв”ңВ®rfanos", vial del antiguo barrio de la Ortilla, entre las calles "Marв”ңВЎa de Luna", inmediata, y la de "Antillв”ңв”Ӯn" (al fondo). La captura se habrв”ңВЎa realizado desde cerca de la avenida de los Pirineos. El trazado ferroviario que provenв”ңВЎa de la estaciв”ңв”Ӯn del Norte, quedarв”ңВЎa a la izquierda, y la moderna mole de Kasв”ңГӯn, a la derecha. Este espacio urbano perdido sв”ңв”Ӯlo perdura en imв”ңГӯgenes como esta, y en la memoria de quienes lo conocieron. Fuente visual: amable aportaciв”ңв”Ӯn personal de Pablo Valdв”ңВ®s.', 1977, 1977, 1977, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66338400, -0.88175800, '0101000020E610000054909F8D5C37ECBF475854C4E9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26364883130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26364883130.webp', 'https://www.flickr.com/photos/zaragozaantigua/26364883130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24818, 'Avenida de Ranillas 1992', 'Imagen centrada en el pabellв”ңв”Ӯn municipal de festejos "La Chimenea", que tomв”ңв”Ӯ su nombre de la chimenea de la instalaciв”ңв”Ӯn industrial de в”ңГјngel Anos y Antonio Morв”ңв”Ӯn dedicada al lavado y secado de lana, ampliada luego al curtido de pieles, aquв”ңВЎ ubicada en 1917, entre el antiguo camino de Ranillas y la arboleda de Macanaz. Tras el derribo de la fв”ңГӯbrica y urbanizaciв”ңв”Ӯn de la zona, se preservв”ңв”Ӯ la chimenea en un espacioso solar que en 1991 fue habilitado para dar continuidad a los eventos festivos que hasta entonces se realizaban en el Pabellв”ңв”Ӯn Francв”ңВ®s de la antigua Feria de Muestras. Aquв”ңВЎ perdurв”ңв”Ӯ hasta que en 1994 fue inaugurado el recinto Multiusos junto al nuevo Auditorio Municipal, de forma que el Ayuntamiento desestimв”ңв”Ӯ la continuidad de este itinerante pabellв”ңв”Ӯn que acogiв”ңв”Ӯ festejos y conciertos. Al fondo de la imagen, inmuebles que jalonan la calle del Arquitecto de La Figuera.', 1992, 1992, 1992, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66095300, -0.88255400, '0101000020E61000000987DEE2E13DECBFB7989F1B9AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50199527818.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50199527818.webp', 'https://www.flickr.com/photos/zaragozaantigua/50199527818/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24823, 'La Chimenea 1992', 'Imagen capturada en el recinto que albergaba el pabellв”ңв”Ӯn municipal de festejos "La Chimenea", montado al calor de la chimenea de las antiguas instalaciones de в”ңГјngel Anos y Antonio Morв”ңв”Ӯn dedicadas al lavado y secado de lana y curtido de pieles. Desde 1991 fue el espacio festivo que sustituyв”ңв”Ӯ al Pabellв”ңв”Ӯn Francв”ңВ®s de la antigua Feria de Muestras, y estuvo en activo hasta que en 1994 fue inaugurado el recinto Multiusos junto al nuevo Auditorio Municipal. Centra la escena el pabellв”ңв”Ӯn y la referida chimenea, ademв”ңГӯs de las tradicionales casetas que albergan las barras de bebidas espirituosas. Al fondo y a la derecha, el templo del Pilar.', 1992, 1992, 1992, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66088900, -0.88261800, '0101000020E6100000B98C9B1A683EECBFA0A4C00298D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50379633621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50379633621.webp', 'https://www.flickr.com/photos/zaragozaantigua/50379633621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25974, 'Avenida de los Pirineos 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 27/07/1975. "Ciclismo. VII clв”ңГӯsica Zaragoza-Sabiв”ңв–’в”ңГӯnigo." En la imagen, la prueba en lв”ңВЎnea de salida, en la Avenida de los Pirineos/N-123. Al fondo, panorв”ңГӯmica de la ciudad, de izquierda a derecha, el Pilar, la arboleda de Macanaz, la barrera levantada del paso a nivel del ferrocarril, San Juan de los Panetes, La Zuda, la iglesia de los Escolapios...', 1975, 1975, 1975, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66259700, -0.88091200, '0101000020E61000002DEDD45C6E30ECBFBFB67EFACFD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15115541239.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15115541239.webp', 'https://www.flickr.com/photos/zaragozaantigua/15115541239/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20979, 'Rв”ңВЎo Gв”ңГӯllego 1820', '"Plano topogrв”ңГӯfico que manifiesta el curso y madre del Rв”ңВЎo Gв”ңГӯllego desde el Soto de Cogullada hasta el Puente de Madera inclusive propio de S. M., las obras y plantaciones hechas por la Administraciв”ңв”Ӯn para evitar mayores extravв”ңВЎos del Rв”ңВЎo, las tierras en cultivo a las orillas del mismo y algunos de sus dueв”ңв–’os, las ramblas con matorral y arbustos y sin ellos, y los cauces por donde ha corrido el Rв”ңВЎo y corre en sus crecientes. Zaragoza, 3 de mayo de 1806. Adiciones puestas a este Plan tomadas sobre el terreno en febrero de 1820 por el delineador de los Canales, Juan Mendoza." Fuente: DARA/AHPZ.', 1820, 1820, 1820, 'Siglo XIX', 'ACTUR-REY FERNANDO', 41.68329200, -0.84444900, '0101000020E6100000187AC4E8B905EBBF29CFBC1C76D74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20462095576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20462095576.webp', 'https://www.flickr.com/photos/zaragozaantigua/20462095576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21932, 'Monasterio de Cogullada 1943', 'Foto: Cв”ңВ®sar Gracia Jarque El Monasterio de Nuestra Seв”ңв–’ora de Cogullada se encuentra en el camino (hoy carretera) de Cogullada 127 del barrio del mismo nombre de Zaragoza. Convento capuchino de 1657, expulsados sus ocupantes en 1835 y rehabilitado por la Caja de Ahorros en 1943 para Casa de Economв”ңВЎa Rural para la formaciв”ңв”Ӯn de Labradores Diplomados. Sus sucesivos cambios de nombre: Escuela de Capacitaciв”ңв”Ӯn Agraria y Centro de Formaciв”ңв”Ӯn para la Empresa, dan una pista sobre la evoluciв”ңв”Ӯn econв”ңв”Ӯmica de los в”ңв•‘ltimos 70 aв”ңв–’os. Fuente: Ibercaja.', 1943, 1943, 1943, 'Anos 40', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15018798555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15018798555.webp', 'https://www.flickr.com/photos/zaragozaantigua/15018798555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21996, 'San Gregorio c.1944', 'Inв”ңВ®dita imagen del ascendente y arbolado ingreso al Campo de Tiro y Maniobras de Alfonso XIII desde la carretera de Huesca. Este terreno formaba parte de los primeros 23 kilв”ңв”Ӯmetros cuadrados que el Ramo de Guerra adquiriв”ңв”Ӯ en este entorno, en 1910-11, por 250.000 pesetas. Destacan las representaciones de "Los Leones" que sobre pedestal flanquean la entrada al Cuartel del General Luque, que por ello tambiв”ңВ®n era denominado cuartel de Los Leones. En sus inmediaciones fue construida una subestaciв”ңв”Ӯn de transformaciв”ңв”Ӯn elв”ңВ®ctrica que recibiв”ңв”Ӯ la denominaciв”ңв”Ӯn de "Los Leones", y en los aв”ңв–’os 60 fueron construidos unos depв”ңв”Ӯsitos de agua que recibieron la denominaciв”ңв”Ӯn de "Depв”ңв”Ӯsitos de Los Leones". Este cuartel fue abandonado en 1990 y los leones, desaparecidos. En 2003 el alcalde Josв”ңВ® Atarв”ңВ®s, durante la colocaciв”ңв”Ӯn de la primera piedra de la urbanizaciв”ңв”Ӯn de Valdespartera, anunciв”ңв”Ӯ un principio de acuerdo con el Ministerio de Defensa para la construcciв”ңв”Ӯn de mв”ңГӯs de 3200 nuevas viviendas en los suelos de este cuartel ya desaparecido, de las cuales la mitad serв”ңВЎa propiedad municipal. A fecha de hoy, todavв”ңВЎa no se ha firmado el convenio urbanв”ңВЎstico para desarrollar estos suelos, propiedad de la Administraciв”ңв”Ӯn General del Estado y adscritos al Ministerio de Defensa.', 1944, 1944, 1944, 'Anos 40', 'ACTUR-REY FERNANDO', 41.69178900, -0.87104200, '0101000020E61000006728EE7893DFEBBFC45DBD8A8CD84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32565134687.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32565134687.webp', 'https://www.flickr.com/photos/zaragozaantigua/32565134687/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22299, 'Dr. Barnard 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Mayo 1968. Con motivo del Aniversario XXV de la IFC (Instituciв”ңв”Ӯn "Fernando el Catв”ңв”Ӯlico"), se organizв”ңв”Ӯ el I Congreso de Medicina Aragonesa (25-28 de mayo). Con ese motivo, se invitв”ңв”Ӯ al doctor Christian Barnard para dar una conferencia titulada "Trasplante de corazв”ңв”Ӯn", en el auditorio de la Casa de Economв”ңВЎa Rural de Cogullada. La Caja pagaba los gastos, por eso se hizo allв”ңВЎ. Barnard era un mв”ңВ®dico cirujano sudafricano que pasв”ңв”Ӯ a la historia por realizar el primer trasplante de corazв”ңв”Ӯn humano del que se tiene constancia.', 1968, 1968, 1968, 'Anos 60', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15546858207.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15546858207.webp', 'https://www.flickr.com/photos/zaragozaantigua/15546858207/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23124, 'Parque Goya 2006', 'Foto: Miriam Martв”ңВЎnez. En el aв”ңв–’o 2000 comenzв”ңв”Ӯ a poblarse el nuevo barrio zaragozano Parque Goya, constituido por viviendas de protecciв”ңв”Ӯn oficial promovidas por el Gobierno de Aragв”ңв”Ӯn. Estв”ңГӯ dividido en dos por la autovв”ңВЎa de Huesca. Parque Goya 1 al este, y Parque Goya 2 al oeste. Esta segunda fase fue habitada a partir de 2003. En la foto de junio de 2006, vecinos del barrio en la calle El Globo, ante el solar donde se construirв”ңГӯ la parroquia de Santa Marв”ңВЎa Reina de los Mв”ңГӯrtires, inaugurada en 2013. Al fondo, tras la autovв”ңВЎa, bloques de los impares de la avenida Majas de Goya, en Parque Goya 2. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.68420700, -0.87321100, '0101000020E6100000143DF03158F1EBBFDE58501894D74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31170801583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31170801583.webp', 'https://www.flickr.com/photos/zaragozaantigua/31170801583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23227, 'Camino de los Molinos 2018', 'Vista de mayo de 2018 de la harinera sita en el camino de los Molinos 160-166, frente a la calle de Bernardo Ramazzini. Se trataba del molino harinero "del Papel" o "del Papelillo", que fuera antiguo molino de papel (posiblemente denominado "de las Cavallerias") y luego una fв”ңГӯbrica de tejidos, hasta que a principios del siglo XX se construyera un molino de harina propiedad de Marraco. Fue adquirido a Julio Balena por Antonio Espona en 1946 y se mantuvo en funcionamiento hasta el cambio de siglo. La construcciв”ңв”Ӯn permaneciв”ңв”Ӯ abandonada, hasta su derribo tras un incendio del 23 de marzo de 2019.', 2018, 2018, 2018, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.68351300, -0.86691100, '0101000020E6100000705D3123BCBDEBBF07B29E5A7DD74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54379892346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54379892346.webp', 'https://www.flickr.com/photos/zaragozaantigua/54379892346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24082, 'Cogullada 1943', 'Imagen capturada en el Salв”ңв”Ӯn de Actos del antiguo monasterio benedictino de Nuestra Seв”ңв–’ora de Cogullada durante la inauguraciв”ңв”Ӯn de la moderna Casa de Economв”ңВЎa Rural allв”ңВЎ ubicada, impulsada por la Caja de Ahorros y Monte de Piedad de Zaragoza. En pie, el ministro de Educaciв”ңв”Ӯn Nacional, el turolense Josв”ңВ® Ibв”ңГӯв”ңв–’ez Martв”ңВЎn, discursea sobre el apoyo del rв”ңВ®gimen de Franco a esta iniciativa. A la izquierda, Josв”ңВ® Sinuв”ңВ®s Urbiola, presidente de la entidad de ahorro local, junto a otros jerarcas locales. Al fondo, diversos sв”ңВЎmbolos e iconos institucionales de la Espaв”ңв–’a salida del 18 de julio de 1936. Fuente visual: www.todocoleccion.net/', 1943, 1943, 1943, 'Anos 40', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39517001694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39517001694.webp', 'https://www.flickr.com/photos/zaragozaantigua/39517001694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24367, 'Monasterio de Cogullada aв”ңв–’os 20', 'AHPZ. Gabriel Faci. Aв”ңв–’os 20. "Fachada de una iglesia con pв”ңв”Ӯrtico de cinco arcos y torres (sic) de estilo mudв”ңВ®jar." El monasterio capuchino de Ntra. Sra. de Cogullada fue fundado en 1657, junto a la ermita de la Virgen de Cogullada. Tras la exclaustraciв”ңв”Ӯn de 1835, se acabaron los capuchinos. En 1896 unos franceses benedictinos se instalaron aquв”ңВЎ, e insuflaron al edificio un aire mв”ңГӯs francв”ңВ®s. En 1934, consumido ya todo ese aire francв”ңВ®s, vendieron la propiedad, que fue adquirida en 1940 por una entidad de ahorro local. En la imagen, despejada fachada del Monasterio junto al camino de Cogullada, en su etapa de ocupaciв”ңв”Ӯn francesa, sin verja, vallas, carteles de no pasar.', 1920, 1920, 1929, 'Anos 20', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15439252801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15439252801.webp', 'https://www.flickr.com/photos/zaragozaantigua/15439252801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24368, 'Monasterio de Cogullada 1913', '"Zaragoza. Nuestra Seв”ңв–’ora de Cogullada (Monasterio de Benedictinos)". Vista general y entrada al antiguo Convento de Capuchinos, restaurado en 1896 y desde entonces, de Benedictinos franceses. A la izquierda: porterв”ңВЎa, locutorio y hospederв”ңВЎa. Arriba: celdas. En el centro: Biblioteca e Iglesia. A la derecha escuelas y casas de los colonos. Imagen incluida en una serie postal sobre este Monasterio. Fuente visual: www.delcampe.es/', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68948800, -0.84665000, '0101000020E61000009D11A5BDC117EBBF027E8D2441D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15459058976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15459058976.webp', 'https://www.flickr.com/photos/zaragozaantigua/15459058976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24379, 'Monasterio de Cogullada 1913', '"Zaragoza. Nв”¬В¬ Sв”¬В¬ de Cogullada (Monasterio de Benedictinos). Vista desde Noroeste. Abajo: Sacristв”ңВЎa, camarв”ңВЎn, sala capitular, sala de los Hermanos y cocina. Arriiba: Escritorio, celdas y Biblioteca." El monasterio capuchino de Nuestra. Seв”ңв–’ora de Cogullada fue fundado en 1657, junto a la ermita de la Virgen de Cogullada, cuya imagen fue descubierta por una humilde mujer guiada por el canto de una "cogujada", ave que en la zona se denominaba "cogulada", segв”ңв•‘n una tradiciв”ңв”Ӯn confesional de la zona. Fue levantado en formas y aires barrocos segв”ңв•‘n diseв”ңв–’o de Felipe Busiв”ңв–’ac y Borbв”ңв”Ӯn entre 1658 y 1663. Tras la exclaustraciв”ңв”Ӯn de 1835, los capuchinos se marcharon, y en 1896 llegaron unos franceses benedictinos que se instalaron, e insuflaron al edificio un aire mв”ңГӯs francв”ңВ®s. Asв”ңВЎ, la imagen de esta postal captura las traseras del monasterio antes de las grandes reformas francesas, que entre 1913 y 1916 incluyeron una nueva y caracterв”ңВЎstica torre neomudв”ңВ®jar que aquв”ңВЎ no aparece, a la izquierda de la espadaв”ңв–’a, junto a la puerta principal de acceso. En la fotografв”ңВЎa, ademв”ңГӯs, parte de las grandes extensiones de herbв”ңГӯceas que la vega del Gв”ңГӯllego permitв”ңВЎa, antes de dejar de ser el rв”ңВЎo que fue. Imagen incluida en una serie postal sobre este Monasterio. Esta imagen ha sido luego amablemente utilizada en el libro "El monasterio de Cogullada", firmado por Mв”¬В¬ Isabel Olivв”ңГӯn Jarque (2017. Fuente visual de la imagen: www.delcampe.net/, comentada para el Gran Archivo Zaragoza Antigua.', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68948800, -0.84665000, '0101000020E61000009D11A5BDC117EBBF027E8D2441D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20621450646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20621450646.webp', 'https://www.flickr.com/photos/zaragozaantigua/20621450646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24996, 'P.в”¬в•‘ de los Ruiseв”ңв–’ores 1931', 'Inв”ңВ®dita imagen capturada en el interior del nв”ңв•‘mero 23 del paseo de los Ruiseв”ңв–’ores, junto a la verja que daba a ese paseo y que se abrв”ңВЎa en ocasiones contadas para dar acceso al Jardв”ңВЎn Botв”ңГӯnico de la ciudad, allв”ңВЎ ubicado desde 1923. Al fondo, escalerillas que comunicaban con el edificio central de la Residencia de Estudiantes o Colegio Mayor de Cerbuna de la Universidad de Zaragoza.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63570000, -0.88984900, '0101000020E6100000111B2C9CA479ECBF9A081B9E5ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53174662519.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53174662519.webp', 'https://www.flickr.com/photos/zaragozaantigua/53174662519/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24383, 'Zaragoza desde Cogullada 1913', 'El monasterio capuchino de Nuestra Seв”ңв–’ora de Cogullada fue fundado en 1657, junto a la ermita de la Virgen de Cogullada, cuyo icono representativo fue descubierto por unos pв”ңГӯjaros, segв”ңв•‘n mitos y leyendas del folclore local. El conjunto monacal fue construido en formas y pensamiento barroco, segв”ңв•‘n diseв”ңв–’o de Felipe Busiв”ңв–’ac. Tras la exclaustraciв”ңв”Ӯn de 1835, los capuchinos se marcharon, y en 1896 llegaron unos benedictinos que se instalaron e insuflaron al edificio un aire mв”ңГӯs francв”ңВ®s. Entre 1913 y 1916 aв”ңв–’adieron al conjunto una nueva torre neomudв”ңВ®jar que se convirtiв”ңв”Ӯ en su referente visual mв”ңГӯs representativo. Antes de eso, un poderoso torreв”ңв”Ӯn cuadrangular o mirador de la hospederв”ңВЎa, venв”ңВЎa siendo la atalaya mв”ңГӯs alta del monasterio. Desde allв”ңВЎ, precisamente, se capturв”ңв”Ӯ la imagen de esta entrada, con visual del antiguo camino de Cogullada, y de la feraz vega del Gв”ңГӯllego. A lo lejos, a unos 4,5 kilв”ңв”Ӯmetros en lв”ңВЎnea recta, las dos torres y la cв”ңв•‘pula central del Pilar nos seв”ңв–’alan dв”ңв”Ӯnde queda Zaragoza. Esta imagen ha sido luego amablemente utilizada en el libro "El monasterio de Cogullada", firmado por Mв”¬В¬ Isabel Olivв”ңГӯn Jarque (2017. Fuente visual: www.delcampe.net/ comentada para el Gran Archivo Zaragoza Antigua.', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22795080787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22795080787.webp', 'https://www.flickr.com/photos/zaragozaantigua/22795080787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24389, 'Monasterio de Cogullada 1913', '"Zaragoza. Nuestra Seв”ңв–’ora de Cogullada (Monasterio de Benedictinos)". Vista y entrada al antiguo convento de Capuchinos, restaurado en 1896 y desde entonces, de Benedictinos franceses. A la izquierda: porterв”ңВЎa, locutorio y hospederв”ңВЎa. Arriba: celdas. En el centro: Biblioteca e Iglesia. A la derecha: camino de Cogullada. Imagen incluida en una serie postal sobre este Monasterio. Esta imagen ha sido luego amablemente utilizada en el libro "El monasterio de Cogullada", firmado por Mв”¬В¬ Isabel Olivв”ңГӯn Jarque (2017. Fuente visual de la imagen: www.delcampe.es/, comentada para el Gran Archivo Zaragoza Antigua.', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24669705150.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24669705150.webp', 'https://www.flickr.com/photos/zaragozaantigua/24669705150/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24391, 'Monasterio Cogullada 1933', 'Imagen del antiguo monasterio capuchino de Nв”¬В¬. Sв”¬В¬. de Cogullada, usufructuado desde 1896 por monjes franceses benedictinos, poco antes de abandonarlo y ponerlo en venta. En 1940 serв”ңГӯ adquirido por una entidad de ahorro local, para usos varios, incluyendo el de residencia oficial de destacadas personalidades y jefes del Estado, como Franco, y Juan Carlos I. La vista se ha capturado desde el plurisecular camino de Cogullada. Fuente visual: Revista "Mundo Grв”ңГӯfico".', 1933, 1933, 1933, 'Anos 30', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24937412506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24937412506.webp', 'https://www.flickr.com/photos/zaragozaantigua/24937412506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24408, 'Cogullada 1970', 'Imagen de Cristina, Felipe, y Elena, infantes de Espaв”ңв–’a, hijos de los prв”ңВЎncipes de Espaв”ңв–’a, Juan Carlos, y Sofв”ңВЎa, capturada en el monasterio de Cogullada a raв”ңВЎz de su estadв”ңВЎa con motivo de las fiestas mayores de la ciudad. Por eso van disfrazados como algunos indв”ңВЎgenas. Este antiguo convento de Capuchinos, ahora propiedad de una local entidad de ahorro, era utilizado como tradicional residencia del Jefe del Estado, general Francisco Franco, durante sus visitas a Zaragoza. Fuente visual: foto Jalв”ңв”Ӯn в”ңГјngel, en "Andalв”ңГӯn, periв”ңв”Ӯdico quincenal aragonв”ңВ®s".', 1970, 1970, 1970, 'Anos 70', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31828373244.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31828373244.webp', 'https://www.flickr.com/photos/zaragozaantigua/31828373244/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24425, 'Monasterio de Cogullada 1913', 'Imagen capturada en el interior de la iglesia del monasterio de Nuestra Seв”ңв–’ora de Cogullada edificado entre 1658 y 1663 y ocupado originalmente por la Orden de los capuchinos. De estilo barroco, contaba con claustro y cripta, lugar de enterramiento de los miembros de la Cofradв”ңВЎa de Nuestra Seв”ңв–’ora de Cogullada, y carneario de capuchinos. En la fotografв”ңВЎa, aspecto de la iglesia, con la imagen de la Virgen de Cogullada centrando el retablo del altar mayor, bajo baldaquino. A la izquierda, el antiguo pв”ңв•‘lpito de madera. Completan la escena un par de monjes de la Orden de San Benito, venidos de Solesmes (Francia), a los que les habв”ңВЎa sido cedido el monasterio en 1896 en rв”ңВ®gimen de usufructo. Posteriores reformas, impulsadas por la entidad de ahorro local que adquiriв”ңв”Ӯ el monasterio en 1940, le han dado a esta iglesia su aspecto actual, incluyendo desde el 22 de febrero de 2014 una imagen en bronce de San Josemarв”ңВЎa Escrivв”ңГӯ de Balaguer, realizada en forma de altorrelieve y colocada en una de las capillas laterales.', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68923400, -0.84681600, '0101000020E61000005C5837DE1D19EBBF48A5D8D138D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48355687817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48355687817.webp', 'https://www.flickr.com/photos/zaragozaantigua/48355687817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24487, 'Mercazaragoza 1993', 'Vista aв”ңВ®rea de Mercazaragoza, complejo de mercados mayoristas inaugurado en 1972 en la carretera de Cogullada, junto al barrio de San Gregorio. Al fondo, la autovв”ңВЎa del Nordeste. Fuente: "Un dв”ңВЎa en Mercazaragoza". Diputaciв”ңв”Ӯn General de Aragв”ңв”Ӯn, 1993.', 1993, 1993, 1993, 'Anos 90', 'ACTUR-REY FERNANDO', 41.68518200, -0.85243100, '0101000020E6100000271763601D47EBBF68E7340BB4D74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24696068697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24696068697.webp', 'https://www.flickr.com/photos/zaragozaantigua/24696068697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23084, 'Palacio de Congresos 2007', 'Construcciв”ңв”Ӯn del Palacio de Congresos, segв”ңв•‘n proyecto de Enrique Sobejano y Fuensanta Nieto para el recinto de la Expo 2008 de Zaragoza. Fuente: picasaweb.google.com/CHELUYS', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66867700, -0.90658800, '0101000020E610000006465ED6C402EDBF304B3B3597D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19345513783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19345513783.webp', 'https://www.flickr.com/photos/zaragozaantigua/19345513783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23088, 'Hotel Hiberus 2007', 'Construcciв”ңв”Ӯn del Hotel Hiberus, de Josв”ңВ® Antonio Martв”ңВЎnez y Elв”ңВЎas Torres, junto al recinto de la Expo 2008 de Zaragoza. Fuente: picasaweb.google.com/CHELUYS', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66811600, -0.90800400, '0101000020E6100000D06394675E0EEDBF98F738D384D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19940365516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19940365516.webp', 'https://www.flickr.com/photos/zaragozaantigua/19940365516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23090, 'Torre del Agua 2007', 'Construcciв”ңв”Ӯn de la Torre del Agua, edificio de la Expo 2008 de Zaragoza diseв”ңв–’ado por Enrique de Teresa. Fuente: picasaweb.google.com/CHELUYS', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67036200, -0.90763900, '0101000020E6100000635FB2F1600BEDBF963D096CCED54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19972177521.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19972177521.webp', 'https://www.flickr.com/photos/zaragozaantigua/19972177521/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23095, 'Torre Bergua c.2000', 'Aspecto de la Torre Bergua en el Meandro de Ranillas de Zaragoza, antes de ser derribada. El proyecto de Parque Metropolitano del Agua Luis Buв”ңв–’uel (2008) contemplaba su salvaciв”ңв”Ӯn como ejemplo de este tipo de arquitectura en la zona, pero la iniciativa no prosperв”ңв”Ӯ. En su solar se encuentra la Escuela Hв”ңВЎpica Parque del Agua. En la foto, al fondo a la izquierda, destaca el edificio que se levanta en la Vв”ңВЎa Hispanidad 152, esquina con la avenida de Navarra.', 2000, 2000, 2000, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67039200, -0.91416300, '0101000020E6100000EDD286C3D240EDBF01C0B167CFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22194127380.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22194127380.webp', 'https://www.flickr.com/photos/zaragozaantigua/22194127380/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23096, 'Torre Castillo c.2000', 'Vista de la Torre Castillo, en el Meandro de Ranillas de Zaragoza. Fue destruida cuando se construyв”ңв”Ӯ en la zona el Parque Metropolitano del Agua Luis Buв”ңв–’uel, en 2008. Se hallaba en las inmediaciones del actual embarcadero del Canal de Aguas Bravas, junto a la Torre del Agua. Fuente: apudepa.blogia.com/2008/071501-apudepa-descubre-escandali...', 2000, 2000, 2000, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67064900, -0.90931300, '0101000020E6100000187C9A931719EDBF2C0C91D3D7D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22371953662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22371953662.webp', 'https://www.flickr.com/photos/zaragozaantigua/22371953662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23109, 'Ranillas 2004', 'Vista aв”ңВ®rea del meandro de Ranillas del rв”ңВЎo Ebro, donde cuatro aв”ңв–’os despuв”ңВ®s se instalarв”ңГӯ la Expo 2008. En primer tв”ңВ®rmino, la estaciв”ңв”Ӯn ferroviaria Zaragoza-Delicias. Fuente: Agencia EFE.', 2004, 2004, 2004, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66832700, -0.91400000, '0101000020E6100000736891ED7C3FEDBF530438BD8BD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24631905442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24631905442.webp', 'https://www.flickr.com/photos/zaragozaantigua/24631905442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23176, 'Parque del Agua 2009', 'Imagen del Canal de Aguas Bravas del Parque Metropolitano del Agua Luis Buв”ңв–’uel, una de las estupendas instalaciones lв”ңв•‘dicas puestas en marcha con motivo de la Exposiciв”ңв”Ӯn Internacional в”¬ВҪAgua y desarrollo sostenibleв”¬в•— de 2008. Sus dimensiones fueron diseв”ңв–’adas para poder albergar competiciones internacionales e incluso actuar como subsede olв”ңВЎmpica, y el canal puede ser utilizado tanto por deportistas profesionales como por usuarios ocasionales. Varias empresas se han encargado desde entonces de su explotaciв”ңв”Ӯn, que se estimaba de unos 100.000 potenciales usuarios anuales entre practicantes del rв”ңГӯfting, piragв”ңв•қismo, hidrospeed, cano-raft, hot-dogГ”ГҮВӘ tanto en las modalidades de descenso, estilo libre y slalom. En marzo de 2017 estas instalaciones, cuya construcciв”ңв”Ӯn costв”ңв”Ӯ unos 5 millones de euros, han sido cerradas por abandono de la empresa concesionaria, pues el ejercicio de 2016 se cerrв”ңв”Ӯ con el trв”ңГӯnsito de 2000 personas, y el negocio no parece viable en esas condiciones. En la imagen, a la izquierda, el Puente del Tercer Milenio. De fondo, al otro lado del Ebro, la Estaciв”ңв”Ӯn de Zaragoza-Delicias. Fuente visual: foto Isabel Pardo, en www.chebro.es/', 2009, 2009, 2009, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66959500, -0.90928900, '0101000020E6100000F699B33EE518EDBF5648F949B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34770349561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34770349561.webp', 'https://www.flickr.com/photos/zaragozaantigua/34770349561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24756, 'Zaragoza Oeste 2008', 'Vista aв”ңВ®rea del Oeste de Zaragoza en 2008. De abajo arriba, la Torre del Agua y el Canal de Aguas Bravas del Parque Metropolitano del Agua Luis Buв”ңв–’uel; el Palacio de Congresos y el Hotel Hiberus; el Pabellв”ңв”Ӯn Puente, el Auditorio de la Plaza de Inspiraciones Acuв”ңГӯticas (desaparecido); el Puente del Tercer Milenio: el barrio de La Almozara, el Parking Sur de la Expo; la Estaciв”ңв”Ӯn Delicias y el barrio de Las Delicias. Fuente: Atlas de la ciudad. Zaragoza, 2009.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66811600, -0.90800400, '0101000020E6100000D06394675E0EEDBF98F738D384D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19431730943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19431730943.webp', 'https://www.flickr.com/photos/zaragozaantigua/19431730943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24758, 'Parque Luis Buв”ңв–’uel 2008', 'Vista desde la Torre del Agua del Canal de Aguas Bravas del Parque Metropolitano del Agua Luis Buв”ңв–’uel de Zaragoza, unos meses antes de la inauguraciв”ңв”Ӯn de la Expo 2008. El parque fue diseв”ңв–’ado por Margarita Jover, Iв”ңв–’aki Alday y Christine Dalnoki. Fuente: picasaweb.google.com/CHELUYS', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66915800, -0.91012900, '0101000020E6100000948444DAC61FEDBFABED26F8A6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19779353900.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19779353900.webp', 'https://www.flickr.com/photos/zaragozaantigua/19779353900/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24761, 'Alma del Ebro 2008', 'El escultor Jaume Plensa instalв”ңв”Ӯ una de sus esculturas de personajes formados por letras en el recinto de la Expo 2008 de Zaragoza. La hizo llamar Alma del Ebro y aquв”ңВЎ la vemos reciв”ңВ®n colocada y aв”ңв•‘n protegida por andamios, frente a la entrada del palacio de Congresos. Fuente: picasaweb.google.com/CHELUYS', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66885400, -0.90596600, '0101000020E6100000C636A968ACFDECBF3FE603029DD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19967452225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19967452225.webp', 'https://www.flickr.com/photos/zaragozaantigua/19967452225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24791, 'Torre Montaв”ңв–’в”ңВ®s 1965', 'La Torre Montaв”ңв–’в”ңВ®s era una de las construcciones de carв”ңГӯcter rural en la huerta de Ranillas. Fue derribada, junto con el resto, en 2007, para construir allв”ңВЎ el parque del Agua Luis Buв”ңв–’uel, en el marco de la Expo 2008. Fuente: Colecciв”ңв”Ӯn particular.', 1965, 1965, 1965, 'Anos 60', 'ACTUR-REY FERNANDO', 41.66903900, -0.91531500, '0101000020E61000004339D1AE424AEDBFD05FE811A3D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32247935084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32247935084.webp', 'https://www.flickr.com/photos/zaragozaantigua/32247935084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24800, 'Mario Vargas Llosa 2008', 'Foto: J. C. Leв”ңв”Ӯn. Visita a la Expo 2008, el 19 de agosto, del escritor peruano Mario Vargas Llosa, Premio Nobel de Literatura 2010. Al fondo, la escultura de Jaume Plensa El alma del Ebro. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66898100, -0.90573000, '0101000020E6100000CF31207BBDFBECBF9C525E2BA1D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32941029443.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32941029443.webp', 'https://www.flickr.com/photos/zaragozaantigua/32941029443/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25983, 'Expo 2008. 2006', 'Vicente Modesto Locual. Febrero 2006 Imagen aв”ңВ®rea del estado de las obras de la Expo 2008 en el meandro de Ranillas, en sus primeros estadios: la prolongaciв”ңв”Ӯn de la calle Pablo Ruiz Picasso, y el seв”ңв–’alamiento del perв”ңВЎmetro del espacio de la Expo, y de los futuros puentes del Tercer Milenio y el Pabellв”ңв”Ӯn-Puente. La productiva huerta de Ranillas mengua conforme la obra avanza.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66919300, -0.90814300, '0101000020E610000029ECA2E8810FEDBF27DBC01DA8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15332296306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15332296306.webp', 'https://www.flickr.com/photos/zaragozaantigua/15332296306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25988, 'Meandro de Ranillas 2007', 'Imagen de la evoluciв”ңв”Ӯn del meandro de Ranillas con motivo de las obras previas a la Expo 2008: Parque del Agua "Luis Buв”ңв–’uel" (perfecto homenaje absurdo al maestro), recinto ferial, y los puentes asociados al proyecto. Fuente: EXPOAGUA.', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66832700, -0.91400000, '0101000020E6100000736891ED7C3FEDBF530438BD8BD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16488559618.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16488559618.webp', 'https://www.flickr.com/photos/zaragozaantigua/16488559618/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26033, 'Ronda del Rabal 2006', 'Vista parcial del Meandro de Ranillas en febrero de 2006, con la avenida de Ranillas abajo, y la Ronda del Rabal en construcciв”ңв”Ӯn. Este vial, que forma parte del Tercer Cinturв”ңв”Ӯn de Ronda de la ciudad, arrancaba de la rotonda de intersecciв”ңв”Ӯn de la calle Pablo Ruiz Picasso con la avenida de Ranillas y llegaba hasta la avenida Pablo Gargallo, atravesando el rв”ңВЎo Ebro por el puente del Tercer Milenio. Fue construido entre 2005 y 2006, y puesto en uso en 2007. Su nombre desapareciв”ңв”Ӯ despuв”ңВ®s del callejero, pasando a considerarse un nuevo tramo de la calle Picasso. El solar de la derecha, ya explanado para ubicar ahв”ңВЎ la Expo 2008. El puente del Tercer Milenio, al fondo, en construcciв”ңв”Ӯn. Las huertas de arriba, a punto de desaparecer. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66984400, -0.90328600, '0101000020E6100000B4E89D0AB8E7ECBFFEB5BC72BDD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31087505643.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31087505643.webp', 'https://www.flickr.com/photos/zaragozaantigua/31087505643/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26041, 'Meandro de Ranillas 2006', 'Ortofoto obtenida el 1 de agosto de 2006. Muestra los terrenos abrazados por el meandro de Ranillas, durante la construcciв”ңв”Ӯn de la Expo 2008 y sus obras de acompaв”ңв–’amiento. Fuente: Gobierno de Aragв”ңв”Ӯn. Departamento de Presidencia y Relaciones Institucionales. Centro de Documentaciв”ңв”Ӯn e Informaciв”ңв”Ӯn Territorial de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66898800, -0.91230200, '0101000020E61000009C69C2F69331EDBF4EB51666A1D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31257263634.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31257263634.webp', 'https://www.flickr.com/photos/zaragozaantigua/31257263634/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26056, 'Meandro de Ranillas 2006', 'Aв”ңВ®rea visual del meandro de Ranillas ya impactado por las obras de urbanizaciв”ңв”Ӯn previas a la Expo 2008 (avenida de Ranillas, Ronda del Rabal, y puente del Tercer Milenio). La zona que ocuparв”ңГӯ la Expo 2008 ya se encuentra explanada, y en ejecuciв”ңв”Ӯn. La antigua zona de huerta de primer plano serв”ңГӯ pronto sustituida por unos diversos y singulares espacios de acompaв”ңв–’amiento que incluyen huertas posmodernas. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 2006, 2006, 2006, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66832700, -0.91400000, '0101000020E6100000736891ED7C3FEDBF530438BD8BD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32998995143.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32998995143.webp', 'https://www.flickr.com/photos/zaragozaantigua/32998995143/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21133, 'Vista 1889', 'Como si de las dos caras de Jano, esta vista de Zaragoza se complementa con la subida hace un par de dв”ңВЎas, porque confronta con ella. De esta forma, posiblemente habrв”ңВЎa sido capturada desde la altura de la fв”ңГӯbrica de harinas de Almech, sobre una terraza natural esquinera entre el final de los caminos de Torrero y de las Torres, y el principio de Cuв”ңВ®llar, permitiendo por ello una insв”ңв”Ӯlita vista panorв”ңГӯmica de la ciudad desde el sur En primer tв”ңВ®rmino destacan las instalaciones de la Fв”ңГӯbrica de sombreros al por mayor de Felipe Conesa sita en el 293 de la Subida de Cuв”ңВ®llar, donde el camino de las Alcachoferas angula con el camino de las Torres. A finales de agosto de 1889 esta fв”ңГӯbrica fue asolada por un incendio, tras lo que fue reubicada donde "las cuatro esquinas", en el camino de Montemolв”ңВЎn a Torrero o camino de San Josв”ңВ®. donde este empresario fue asesinado de forma truculenta el 30 de diciembre de 1890, tras lo que se convirtiв”ңв”Ӯ en un mediв”ңГӯtico y popular evento muy seguido desde su comisiв”ңв”Ӯn y hasta la concesiв”ңв”Ӯn de indulto a los reos de muerte casi un aв”ңв–’o despuв”ңВ®s: su mujer, su amante, y su asesino. Hemingway incluso sugiriв”ңв”Ӯ mв”ңГӯs tarde que este caso habrв”ңВЎa servido de referente a la novela "La piedra angular" de Emilia Pardo Bazв”ңГӯn. La despejada zona central de torres y almacenes dispersos estarв”ңВЎa delimitada entre el camino de Torrero, a la izquierda, el reciente paseo de las Damas, a la derecha, y el camino de las Torres. La gran estructura del colegio del Sagrado Corazв”ңв”Ӯn, y la mв”ңГӯs grande aв”ңв•‘n del colegio del Salvador, justo detrв”ңГӯs, seв”ңв–’alan el comienzo de la ciudad consolidada. A su izquierda, la torre de San Pablo Apв”ңв”Ӯstol y la cв”ңв•‘pula y gran nave central del antiguo convento de San Ildefonso. A su derecha emerge la desmochada Torre Nueva de su triple chapitel. A continuaciв”ңв”Ӯn, la torre de la iglesia de Santa Engracia, el templo del Pilar con la inacabada torre de Santiago. Mв”ңГӯs hacia la derecha, la torre de San Gil Abad, la de San Juan y San Pedro, y cierra el panorama la to', 1889, 1889, 1889, 'Siglo XIX', 'UNIVERSIDAD', 41.64123200, -0.88551500, '0101000020E610000012C2A38D2356ECBF0893E2E313D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49016943013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49016943013.webp', 'https://www.flickr.com/photos/zaragozaantigua/49016943013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21148, 'Litografв”ңВЎa Portabella 1898', '"Litografв”ңВЎa Portabella" fue construida segв”ңв•‘n diseв”ңв–’o de Fв”ңВ®lix Navarro Pв”ңВ®rez en 1897 en el camino de Torrero nв”¬в•‘ 30. El taller de la imagen, primero en procesar los fotolitos preparados en Zaragoza por Ramв”ңв”Ӯn y Cajal, era uno de los mejores ejemplos de arquitectura industrial de la Zaragoza del momento, en estilo eclecticista fin de siglo. En la imagen, el lado largo de la fachada da al paseo de Sagasta, y el corto, al paseo de Ruiseв”ңв–’ores. El tranvв”ңВЎa de propulsiв”ңв”Ӯn a sangre estв”ңГӯ subiendo a la playa de Torrero. El negocio se mantuvo, primero como litografв”ңВЎa, luego como cartonaje, hasta la dв”ңВ®cada prodigiosa de los aв”ңв–’os 60.', 1898, 1898, 1898, 'Siglo XIX', 'UNIVERSIDAD', 41.63899700, -0.88636900, '0101000020E6100000EE056685225DECBFFE9E58A7CAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15330292408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15330292408.webp', 'https://www.flickr.com/photos/zaragozaantigua/15330292408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21165, 'Torre Buil 1898', '"Lejв”ңВЎsimos" de Zaragoza, imagen de 1898 de la torre de Buil, elegante, airosa y amplia finca de recreo sobre parte de la mв”ңГӯs antigua Torre de Blancas y luego de Jв”ңв•‘dez, donde la selecta "crв”ңВҝme" de la "gente guapa" de la ciudad festejaba y tomaba aires mв”ңГӯs puros que los de abajo, pues estaba ubicada sobre una de las elevadas terrazas naturales que caracterizan la zona. Su propietario, Pablo Buil, se opuso con fervor a ser desalojado para que el ayuntamiento realizara, en ese lugar, un pequeв”ңв–’o parque "raquв”ңВЎtico y mezquino". Aв”ңв–’os despuв”ңВ®s, tras la explanaciв”ңв”Ӯn de la zona, comenzarв”ңВЎa la historia del parque de Pignatelli de Zaragoza, vinculado con el proyecto mв”ңГӯs global de ensanche burguв”ңВ®s hacia el sur. En octubre de 1904 serв”ңВЎa reinstalada la estatua de Pignatelli, referencial elemento, desde entonces, de este peculiar y escaleno parque. Fuente visual: recopilaciв”ңв”Ӯn de reportajes "в”¬ГӯAqui... Zaragoza! ", Josв”ңВ® Blasco Ijazo.', 1898, 1898, 1898, 'Siglo XIX', 'UNIVERSIDAD', 41.63726900, -0.88515200, '0101000020E6100000D3A57F492A53ECBF98E0D40792D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21181953212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21181953212.webp', 'https://www.flickr.com/photos/zaragozaantigua/21181953212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21297, 'P.в”¬в•‘ de Sagasta 1908', 'Vista del andador central del paseo de Sagasta en 1908, con el tranvв”ңВЎa circulando entre los frondosos в”ңГӯrboles. A la derecha, edificios que dan entrada a la calle de La Paz. Fuente visual: Colecciв”ңв”Ӯn particular.', 1908, 1908, 1908, 'Anos 1900', 'UNIVERSIDAD', 41.64264800, -0.88616100, '0101000020E610000074B33F506E5BECBF7F6B274A42D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32193721206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32193721206.webp', 'https://www.flickr.com/photos/zaragozaantigua/32193721206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23399, 'Valdegurriana 2008', 'Vista aв”ңВ®rea centrada en las esclusas y parque de Valdegurriana reciв”ңВ®n concluida la intervenciв”ңв”Ӯn comprendida en la unidad U 29 de las obras de acompaв”ңв–’amiento Expo 2008 para habilitar aquв”ңВЎ un в”ңГӯrea recreativa y de descanso en el corredor verde del Canal Imperial de Aragв”ңв”Ӯn. A la derecha y aguas arriba, la urbanizaciв”ңв”Ӯn Pinarcanal. Al fondo y de izquierda a derecha, Puerto Venecia, el nuevo barrio de Valdespartera, el cementerio municipal, el barrio de Casablanca y el distrito Universidad.', 2008, 2008, 2008, 'Siglo XXI', NULL, 41.61116500, -0.85628000, '0101000020E610000011018750A566EBBFDCBA9BA73ACE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54210136734.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54210136734.webp', 'https://www.flickr.com/photos/zaragozaantigua/54210136734/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21408, 'Caballitos zaragozanos 1913', 'Son apenas unos pocos metros de distancia los que separan este apacible lugar del endomingado paseo de Sagasta. En un rinconcillo de "Villa Florida", desocupados y expectantes, y coloristas versiв”ңв”Ӯn autocromo, estos caballitos de cartв”ңв”Ӯn-piedra fueron fotografiados en 1913 cuando estaban soв”ңв–’ando con peques. Onв”ңВЎricos infantes que luego tomarв”ңВЎan la forma de в”ңГјgueda, Teresa, Pepito, Federico, Pilar, y Concha. Mientras la espera, y sin pestaв”ңв–’ear, sus grandes ojos no perdв”ңВЎan detalle, escrutando el panorama, aunque sв”ңв”Ӯlo brillarв”ңВЎan y destilarв”ңВЎan vida cuando el sueв”ңв–’o se esfumara, y sв”ңв•‘bitamente comenzara el zarandeo y el jineteo, entre una turbamulta de travesuras, sonoras emociones y correveidiles infinitos. Tres coloristas y dispares caballerв”ңВЎas, tres, a la espera de la irrupciв”ңв”Ӯn de la chiquillerв”ңВЎa de los Chicoy, y los de Castro. Llegarв”ңВЎan, seguro, mв”ңГӯs pronto, que tarde. Ellos lo saben, y lo esperan. Son estos caballitos zaragozanos un resorte que nos trae, algo mв”ңГӯs de un siglo despuв”ңВ®s, una emocional imagen de otra ciudad interior, que fue esta misma, aunque no lo pareciera. Inmediata al ensanche alto-burguв”ңВ®s hacia el montaraz sur, esta privilegiada zona, tanto la interior, como la exterior, mutв”ңв”Ӯ luego a otra cosa, a otra realidad. Asв”ңВЎ, de la perdida calle del Mediodв”ңВЎa apenas perduran contados fogonazos del pasado. Como este. Fuente visual: foto de Juan Chicoy Arreceigor (Stereoscopic Autochrome Lumiв”ңВҝre glass plate) www.flickr.com/photos/ricardosanzcortiella/12388790783/in...', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64348800, -0.88669400, '0101000020E6100000CDE67118CC5FECBF29AF95D05DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26741774722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26741774722.webp', 'https://www.flickr.com/photos/zaragozaantigua/26741774722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21409, 'Gil de Jasa 1913', 'Autocroma, tranquila y luminosa imagen con el posado de в”ңГјgueda de Castro Chicoy, en los jardines del entorno de "Villa Florida". Al fondo, acristaladas traseras edilicias del paseo de Sagasta, recayentes a la calle Gil de Jasa, posiblemente, del modernista hotelito de Pedro Marcolaв”ңВЎn, una muestra, a su pesar, de arquitectura efв”ңВЎmera zaragozana, como casi todo lo que habв”ңВЎa por esta zona. La pelota, una singular maravilla multicolor casualmente invitada a la foto, intenta comerse la escena, y casi que lo consigue. Fuente visual: foto de Juan Chicoy Arreceigor (Stereoscopic Autochrome Lumiв”ңВҝre glass plate) www.flickr.com/photos/ricardosanzcortiella/12388617045/in...', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64348800, -0.88669400, '0101000020E6100000CDE67118CC5FECBF29AF95D05DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26747661151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26747661151.webp', 'https://www.flickr.com/photos/zaragozaantigua/26747661151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21410, 'Gil de Jasa 1913', 'Imagen con el posado de Concha Chicoy Arreceigor y Federico de Castro Delgado, en los jardines que envolvв”ңВЎan "Villa Florida". Al fondo, acristaladas traseras recayentes a la calle Gil de Jasa del robusto y clasicista hotelito de Nicolв”ңГӯs Escoriaza, esquinero entre la calle Cervantes y el paseo de Sagasta. Fuente visual: foto de Juan Chicoy Arreceigor (Stereoscopic Autochrome Lumiв”ңВҝre glass plate) www.flickr.com/photos/ricardosanzcortiella/12388782753/in...', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64348800, -0.88669400, '0101000020E6100000CDE67118CC5FECBF29AF95D05DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26813241965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26813241965.webp', 'https://www.flickr.com/photos/zaragozaantigua/26813241965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21413, 'Gil de Jasa 1913', 'Imagen capturada en los jardines perimetrales que envolvв”ңВЎan la desaparecida Villa Florida (a espaldas del fotв”ңв”Ӯgrafo) con un grupal y entraв”ңв–’able posado de Teresa, Pepe, Charo, Rafael y Pilar, hijos de Teresa Dabв”ңГӯn Vallejo y Rafael Chicoy Arreceigor. Al fondo, la calle Gil de Jasa y las monumentales traseras edilicias del paseo de Sagasta en el tramo entre la calle de Cervantes y la calle del Mediodв”ңВЎa. Destacaban, a la izquierda, la mв”ңГӯs clasicista, cuadrangular y robusta casa de Nicolв”ңГӯs Escoriaza, mientras que la de Pedro Marcolaв”ңВЎn, de aires mв”ңГӯs modernistas, quedaba a su vera. En todas ellas sobresalв”ңВЎan luminosas sus extensas balconadas acristaladas orientadas al oeste, de elaborada tracerв”ңВЎa, sus jardines y zonas verdes.', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64348800, -0.88669400, '0101000020E6100000CDE67118CC5FECBF29AF95D05DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28355877799.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28355877799.webp', 'https://www.flickr.com/photos/zaragozaantigua/28355877799/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21415, 'P.в”¬в•‘ de Ruiseв”ңв–’ores 1915', 'Dibujo de la fachada principal de "Villa Laura", o casa de Fernando Taberner proyectada en eclв”ңВ®cticas y sinuosas formas por el arquitecto Miguel в”ңГјngel Navarro en una propiedad del exclusivo paseo de Ruiseв”ңв–’ores delimitada por este paseo, la calle del Porvenir, el cauce al aire de la acequia de las Adulas y la lindera finca de Victoriano Zorraquino. La introducciв”ңв”Ӯn por el Ayuntamiento en 1913 de la obligatoriedad de presentar proyectos y planos constructivos de las nuevas edificaciones en la ciudad nos permite al menos (y hasta que aparezca algв”ңв•‘n testimonio fotogrв”ңГӯfico, ojalв”ңГӯ) siquiera una visual de lo que fuera el proyecto de este singular hotelito de dos alturas, construido junto al cauce de la acequia de las Adulas o de San Josв”ңВ®, y con una amplia zona de jardines escalonados, fuente, dos bancos y una pequeв”ңв–’a construcciв”ңв”Ӯn auxiliar. Dв”ңВ®cadas mв”ңГӯs tarde la casa serв”ңВЎa derribada y sobre su solar se construirв”ңВЎan dos edificios de vivienda independientes y bien distintos, uno a finales de los aв”ңв–’os sesenta, esquinero y con ingreso principal por la calle del Doctor Alcay, y otro ya entrado el siglo XXI, esquinero entre el paseo de Ruiseв”ңв–’ores y la calle del Porvenir. Fuente visual: "Zaragoza. Arquitectura. Siglo XX", Jesв”ңв•‘s Martв”ңВЎnez Verв”ңв”Ӯn.', 1915, 1915, 1915, 'Anos 10', 'UNIVERSIDAD', 41.63813100, -0.88758400, '0101000020E6100000DD7D8E8F1667ECBF2AC8CF46AED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30290658887.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30290658887.webp', 'https://www.flickr.com/photos/zaragozaantigua/30290658887/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21453, 'Villa Florida 1915', 'Las hermanas в”ңГјgueda y Concha de Castro Chicoy posan junto a un cachorro de Mastв”ңВЎn del Pirineo en esta tierna e inв”ңВ®dita imagen capturada en el exterior de Villa Florida, hotelito esquinero entre la avenida Central y la calle de Gil de Jasa.', 1915, 1915, 1915, 'Anos 10', 'UNIVERSIDAD', 41.64354200, -0.88692000, '0101000020E6100000E162450DA661ECBF1CCD91955FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51749001055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51749001055.webp', 'https://www.flickr.com/photos/zaragozaantigua/51749001055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21454, 'Villa Florida 1913', 'Cuatro nietos de Josв”ңВ® Chicoy Ferrer, general Auditor de guerra e Inspector mв”ңВ®dico de primera clase de sanidad militar, contemplan absortos la cajita de mв”ңв•‘sica en acciв”ңв”Ӯn que sostiene impasible una "tata" en el exterior del "hotelito" denominado "Villa Florida" y situado entre la avenida Central y la calle de Gil de Jasa.', 1913, 1913, 1913, 'Anos 10', 'UNIVERSIDAD', 41.64351000, -0.88689900, '0101000020E6100000035DFB027A61ECBF115322895ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51750902750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51750902750.webp', 'https://www.flickr.com/photos/zaragozaantigua/51750902750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23403, 'Monasterio de Santa Fe de Huerva 1913', 'Iglesia y restos de los claustros en el interior del recinto amurallado del monasterio de Santa Fe de Huerva, en Zaragoza capital, aunque entre Cuarte y Cadrete. Conjunto del siglo XVIII abandonado en 1835. Aв”ңв•‘n precariamente en pie. Fuente: Delimitaciв”ңв”Ӯn comarcal de Zaragoza. Gobierno de Aragв”ңв”Ӯn, 2011', 1913, 1913, 1913, 'Anos 10', NULL, 41.57758700, -0.94988800, '0101000020E6100000739CDB847B65EEBF21CCED5EEEC94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18615414668.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18615414668.webp', 'https://www.flickr.com/photos/zaragozaantigua/18615414668/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21455, 'Villa Florida 1914', 'Posado de nueve primos endomingados y escalonados por edad, flanqueados por las dos pequeв”ңв–’as en brazos de sus "tatas", en el exterior del "hotelito" denominado "Villa Florida" y situado entre la avenida Central y la calle de Gil de Jasa. Mientras las mв”ңГӯs peques ignoran al fotв”ңв”Ӯgrafo y seguramente miran a sus madres, los demв”ңГӯs muestran una interesante galerв”ңВЎa de actitudes ante el objetivo.', 1914, 1914, 1914, 'Anos 10', 'UNIVERSIDAD', 41.64349300, -0.88688800, '0101000020E610000009E066F16261ECBF3B1A87FA5DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51765752784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51765752784.webp', 'https://www.flickr.com/photos/zaragozaantigua/51765752784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21575, 'P.в”¬в•‘ de Sagasta 1929', 'Imagen de la reciente y caracterв”ңВЎstica "Casa Faci", diseв”ңв–’ada por Regino Borobio Ojeda para el nв”¬в•‘ 39 (antiguo) del paseo de Sagasta, chaflanera con el camino de las Torres, cuando sus bajos comerciales estaban ocupados por el "Garage Ferrer", y el concesionario de vehв”ңВЎculos "Studebaker-Peugeot". Un sencillo surtidor de gasolina, justo en la esquina. A su izquierda, un pedacito del antiguo nв”¬в•‘ 37 del paseo, edificio de viviendas proyectado por Manuel Martв”ңВЎnez de Ubago para el Conde de Montenegrв”ңв”Ӯn, inicialmente de cinco plantas, que en 1950 serв”ңГӯ ampliado tres plantas mas, y un sobreв”ңГӯtico. Al menos, sobreviviв”ңв”Ӯ, que "Casa Faci", no. A la derecha, al otro lado del Camino de las Torres, y tras la canalina acequia de las Adulas, o de San Josв”ңВ®, talleres de la enorme Fв”ңГӯbrica de Acumuladores Tudor S.A. "La Pilar". Fuente visual: Foto "La Ampliadora Moderna", en "Regino y Josв”ңВ® Borobio: arquitectura y fotografв”ңВЎa. Zaragoza, 1923-1969", Iв”ңв–’aki Bergera y Daniel Estabв”ңВ®n, IFC, 2015.', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.64011800, -0.88620700, '0101000020E61000008A8F4FC8CE5BECBF5CCAF962EFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24262679719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24262679719.webp', 'https://www.flickr.com/photos/zaragozaantigua/24262679719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21622, 'P.в”¬в•‘ de Sagasta 1929', 'Imagen capturada, posiblemente, desde las alturas de la modernista Casa Palao, en la avenida del Siglo XX, con una buena visual del aspecto del paseo de Sagasta en su tramo inmediato al arranque del camino de las Torres, tanto a un lado, como al otro. Fuente visual: www.ebay.es/', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33466092996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33466092996.webp', 'https://www.flickr.com/photos/zaragozaantigua/33466092996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21625, 'P.в”¬в•‘ de Sagasta 1927', 'El zaragozano Lorenzo Gradв”ңВ® posa junto a su prototipo de automв”ңв”Ӯvil, aparcado frente al concesionario de las marcas de vehв”ңВЎculos Oakland y Chevrolet (ambas de General Motors), regentado por Josв”ңВ® Marв”ңВЎa Orobitg en el 35 del paseo de Sagasta (hoy 43, albergando una farmacia). Fuente: Colecciв”ңв”Ӯn particular.', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.64059300, -0.88618900, '0101000020E6100000F165A208A95BECBFF58590F3FED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35856209283.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35856209283.webp', 'https://www.flickr.com/photos/zaragozaantigua/35856209283/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21646, 'Pв”¬в•‘. de Sagasta 1926', 'Inв”ңВ®dita imagen centrada en la pescaderв”ңВЎa "La Donostiarra" establecida en el destacado inmueble del nв”¬в•‘ 21 del paseo de Sagasta, esquinero con la calle de la Paz (a la izquierda) y cuyo aspecto definitivo era resultado de la ampliaciв”ңв”Ӯn y reforma proyectadas por el arquitecto Manuel Martв”ңВЎnez Ubago en 1917. En la imagen, el propietario del negocio y el infante aprendiz posan con las cestas utilizadas para el reparto a domicilio del gв”ңВ®nero (pescado fresco y salado, marisco, conservas y escabeches) en los selectas viviendas de este "elegante barrio".', 1926, 1926, 1926, 'Anos 20', 'UNIVERSIDAD', 41.64266000, -0.88599800, '0101000020E6100000F9484A7A185AECBF4339D1AE42D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51278996595.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51278996595.webp', 'https://www.flickr.com/photos/zaragozaantigua/51278996595/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21655, 'Paseo de Sagasta c.1923', 'Maravillosa e inв”ңВ®dita imagen del paseo de Sagasta capturada desde la casa de Abizanda, ubicada entre la de Carlos Palao y la litografв”ңВЎa de la Viuda de Portabella. La destacada altura del edificio nos ofrece una perspectiva muy interesante del tramo del paseo desde la trinchera del ferrocarril de Madrid a Barcelona, al fondo, y hasta la zona donde el paseo levemente curvea en su encuentro, en primer tв”ңВ®rmino, con el final del camino de las Torres, ademв”ңГӯs de con el camino del Sв”ңГӯbado y la calle de Anselmo Gascв”ңв”Ӯn de Gotor. La vista nos ofrece el panorama edilicio de este tramo del paseo, tanto en el lado de los pares, donde a la izquierda destaca aislada "Villa Dolores" o casa del Doctor Arpal (cuyos balcones aparecen engalanados posiblemente siguiendo las instrucciones del Bando municipal dado en diciembre de 1923 ante la visita a Zaragoza de los Reyes de Espaв”ңв–’a), y un poco antes la notable casa de Emerenciano Garcв”ңВЎa, sobre la que despunta la chimenea de la fв”ңГӯbrica de hierro esmaltado de Manuel Viв”ңв–’ado ubicada mв”ңГӯs abajo, entre la trinchera del ferrocarril y el camino de la Cadena. Hacia el fondo, sobre el paseo emerge poderosa la cв”ңв•‘pula de la iglesia parroquial de Santiago. En el centro de la escena, el andador central del paseo se nos muestra muy despejado tras la tala de sus antiguos в”ңГӯrboles, sustituidos por unos nuevos que en la imagen lucen todavв”ңВЎa muy poco. A la derecha y en primer tв”ңВ®rmino, murete inmediato a la fв”ңГӯbrica del acumulador Tudor tras el que fluв”ңВЎa al aire la acequia de san Josв”ңВ® en su descenso hacia el camino de las Torres. Tras este camino, despejado aspecto del tramo edilicio del paseo de los impares desde la coqueta y afrancesada casa de Alberto Carriв”ңв”Ӯn Garmendia, director gerente del Banco de Aragв”ңв”Ӯn, y hasta la alabeada esquina o chaflв”ңГӯn con el camino de las Torres, un tramo en donde poco despuв”ңВ®s se construirв”ңВЎan hasta cuatro notables muestras de la arquitectura de mediados de los aв”ңв–’os veinte: dos para Mariano Baselga Jordв”ңГӯn (la primera ya en obras), ot', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.64003000, -0.88644800, '0101000020E6100000F3583332C85DECBFBD3AC780ECD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52227299323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52227299323.webp', 'https://www.flickr.com/photos/zaragozaantigua/52227299323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21724, 'Av. de la Repв”ңв•‘blica c.1927', 'Imagen editada como postal por la editorial Heliotipia Artв”ңВЎstica Espaв”ңв–’ola, capturada en el tramo final de de la avenida hasta el arranque del camino de las Torres inmediato, hacia la derecha, donde destaca la monumental Casa Faci y su alabeada esquina. Justo al otro lado de la avenida, las tres viviendas unifamiliares que originalmente llevaron la llamativa numeraciв”ңв”Ӯn de 26 Triplicado, Cuadruplicado y Quintuplicado. El solar hasta el nв”¬в•‘ 26 Duplicado serв”ңВЎa edificado pocos aв”ңв–’os despuв”ңВ®s con la moderna casa de J. Sв”ңГӯnchez Ventura. Al fondo destaca el nв”¬в•‘ 26 o casa de Emerenciano Garcв”ңВЎa. Ninguna de las referidas viviendas perdura. En primer tв”ңВ®rmino, una unidad tranviaria posiblemente de la serie 50 en la lв”ңВЎnea 5 o de Torrero transita junto al pasavв”ңВЎas utilizado por el servicio corto que llegaba hasta la avenida del Siglo XX. Fuente visual: Biblioteca Nacional de Espaв”ңв–’a.', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20356110011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20356110011.webp', 'https://www.flickr.com/photos/zaragozaantigua/20356110011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25071, 'Alfonso Guerra 1986', 'Visita al Palacio Municipal de Deportes de Zaragoza del vicepresidente del gobierno espaв”ңв–’ol entre 1982 y 1991, Alfonso Guerra. Le flanquean Antonio Gonzв”ңГӯlez Triviв”ңв–’o (con barba), alcalde de Zaragoza; y Santiago Marraco (puв”ңв–’o en alto), presidente de la Diputaciв”ңв”Ӯn General de Aragв”ңв”Ӯn. Fuente visual: www.zaragoza.es/ciudad/actividades/ficha_Agenda?codigo=13...', 1986, 1986, 1986, 'Anos 80', 'UNIVERSIDAD', 41.63975400, -0.90414900, '0101000020E61000005DC136E2C9EEECBF1BBE8575E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15915755852.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15915755852.webp', 'https://www.flickr.com/photos/zaragozaantigua/15915755852/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21781, 'Colegio Alemв”ңГӯn 1936', '"La fiesta de Navidad de la colonia alemana. Los niв”ңв–’os (sic) que tomaron parte en la fiesta organizada por el Colegio y la Colonia alemanes de nuestra ciudad, el pasado mes de diciembre, para festejar la Natividad del Seв”ңв–’or". A comienzos de los aв”ңв–’os 20 fue abierto un "Kindergarten" en la calle Cervantes para educar a los niв”ңв–’os y niв”ңв–’as alemanas instaladas provisionalmente en la ciudad tras la evacuaciв”ңв”Ӯn de la colonia del II Reich en el Camerв”ңв•‘n, como consecuencia de su derrota militar en la Gran Guerra. Con el tiempo, y la permanencia de un buen nв”ңв•‘mero de familias alemanas, la guarderв”ңВЎa se convirtiв”ңв”Ӯ en "Colegio Alemв”ңГӯn", y junto con el "Hogar Alemв”ңГӯn" y el consulado local, formв”ңв”Ӯ parte de la destacada "Pequeв”ңв–’a Alemania" de Zaragoza. Cuando el partido nazi fue aupado al poder por las в”ңВ®lites econв”ңв”Ӯmicas como forma de acabar con la democracia de la Repв”ңв•‘blica de Weimar, Zaragoza contв”ңв”Ӯ ademв”ңГӯs con un Jefe Provincial del "Ortsgruppe" (Grupo Local) del NSDAP, y una jerarquв”ңВЎa partidaria nazi subordinada, como refuerzo de la labor de propaganda ideolв”ңв”Ӯgica a favor del nuevo rв”ңВ®gimen alemв”ңГӯn, reciв”ңВ®n estrenada la Segunda Repв”ңв•‘blica en Espaв”ңв–’a. Su sede fue establecida tambiв”ңВ®n en los locales de la calle Cervantes. Tras el 18 de julio de 1936, su colaboraciв”ңв”Ӯn con el nuevo rв”ңВ®gimen nacionalista espaв”ңв–’ol fue total. Con la invasiв”ңв”Ӯn alemana de Polonia en setiembre de 1939, y el comienzo de una nueva gran guerra, la colonia alemana en Zaragoza fue militarizada, reclutando para el ejв”ңВ®rcito a los varones aptos para servicio castrense, y utilizando las redes sociales y econв”ңв”Ӯmicas alemanas de la ciudad para respaldo, cobertura y difusiв”ңв”Ӯn de los intereses de guerra del III Reich, de forma especialmente acusada tras la proclamaciв”ңв”Ӯn de la "Totaler Krieg" (Guerra Total) en enero de 1943. Tras la completa derrota militar alemana de 1945, se cerrв”ңв”Ӯ bruscamente esta etapa de la historia de la colonia alemana en Zaragoza.', 1936, 1936, 1936, 'Anos 30', 'UNIVERSIDAD', 41.64397500, -0.88708100, '0101000020E61000002EE57CB1F762ECBF8638D6C56DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22984769261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22984769261.webp', 'https://www.flickr.com/photos/zaragozaantigua/22984769261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21848, 'Gascв”ңв”Ӯn de Gotor 1934', 'Panorв”ңГӯmica imagen del entorno donde fue ubicado el brote psicв”ңв”Ӯtico-mediв”ңГӯtico asociado al denominado &quot;duende de la hornilla&quot;, en el chaflanero edificio entre la calle Gascв”ңв”Ӯn de Gotor y la nueva calle de Juan Pablo Bonet que, hacia la derecha, deberв”ңВЎa conectar la avenida de la Repв”ңв•‘blica y el camino de las Torres con el reciente puente de la vв”ңВЎa Transversal y el ensanche de Miralbueno. Merodeando los alrededores, nutrida congregaciв”ңв”Ӯn de gente curiosa del inane mundo de los espв”ңВЎritus fogoneros. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35693007164.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35693007164.webp', 'https://www.flickr.com/photos/zaragozaantigua/35693007164/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21894, 'La casa del Duende 1934', 'Imagen centrada en el chaflanero edificio entre la calle Gascв”ңв”Ӯn de Gotor (hacia la izquierda) y la nueva calle de Juan Pablo Bonet que, hacia la derecha, conectarв”ңВЎa la avenida de la Repв”ңв•‘blica y el camino de las Torres con el reciente puente de la vв”ңВЎa Transversal y el ensanche de Miralbueno. Aquв”ңВЎ se desatв”ңв”Ӯ a finales de 1934 un brote psicв”ңв”Ӯtico-mediв”ңГӯtico en torno al que ha pasado a la historia como "duende de la hornilla", o "duende de Zaragoza". Merodeando los despejados alrededores, nutrida congregaciв”ңв”Ӯn de gente atraв”ңВЎda por la expectaciв”ңв”Ӯn creada en torno a la pretendida presencia de este fantв”ңГӯstico y juguetв”ңв”Ӯn espв”ңВЎritu fogonero. Esta fotografв”ңВЎa, con la leyenda "El duende de Zaragoza. La casa", y acompaв”ңв–’ada de una fotografв”ңВЎa que muestra el interior de la cocina o "Habitaciв”ңв”Ӯn donde se escucha la voz", forma parte de una tarjeta postal circulada reglamentariamente en la в”ңВ®poca y que se subasta al alucinante precio de 250 euros.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63988500, -0.88716700, '0101000020E6100000D2E4620CAC63ECBFB9196EC0E7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49931719521.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49931719521.webp', 'https://www.flickr.com/photos/zaragozaantigua/49931719521/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21960, 'P.в”¬в•‘ del General Mola 1944', 'Las alturas del alto nв”¬в•‘ 72 del Paseo de Mola, desde su construcciв”ңв”Ӯn en 1942, siempre han sido muy propicias para capturar buenas vistas en altura, aunque esta tan poco usual parece realizada mв”ңГӯs bien desde el nв”¬в•‘ 2 de la calle Gascв”ңв”Ӯn y Gotor, bautizada por el sensacionalismo burlesco como "Casa del Duende". Asв”ңВЎ, enfoca hacia el antiguo "Camino del Gas", por conducir a la "Fв”ңГӯbrica de Gas", al Gasв”ңв”Ӯmetro, aunque su denominaciв”ңв”Ӯn mв”ңГӯs habitual es Camino de las Torres. A la izquierda, el caracterв”ңВЎstico edificio "Casa Faci" con su fantв”ңГӯstica torre neomudв”ңВ®jar, otro de los no oficiales "Palomares" de la ciudad, в”ңВ®ste menos publicitado por menos cв”ңВ®ntrico. Tras su derribo en 1971, las palomas se mudarв”ңГӯn a la plaza del Pilar, y en 1974 en su solar se construirв”ңГӯ el actual nв”¬в•‘ 47 del Paseo, que lleva impresa en una vidriera su castiza denominaciв”ңв”Ӯn de "General Mola". Al fondo, los ladrillos y tejas que, juntos, forman el colegio de los PP. Agustinos, junto a la trinchera del ferrocarril de los directos. Antes, visual de los в”ңГӯrboles del Camino de las Alcachoferas y su acequia al aire. A la derecha del Camino de las Torres, la ancha acequia de las Adulas, tambiв”ңВ®n conocida como "de S. Josв”ңВ®", que recorrв”ңВЎa al aire todo el Camino. Junto a ella aв”ңв•‘n permanece en pie la enorme instalaciв”ңв”Ӯn de la Fв”ңГӯbrica de Acumuladores Tudor "La Pilar", que apenas un par de aв”ңв–’os despuв”ңВ®s se mudarв”ңГӯ a lejanв”ңВЎsima carretera de Navarra. Toda la manzana que ocupaba la fв”ңГӯbrica comenzarв”ңГӯ a urbanizarse con nuevos edificios de viviendas, a partir de 1958. Mв”ңГӯs al fondo, campos de cultivos y huertos de Miraflores. Desciende como una exhalaciв”ңв”Ӯn desde las terrazas de Cuв”ңВ®llar una unidad con remolque de la serie 50 de la Lв”ңВЎnea 3/5 (Torrero-Delicias) del tranvв”ңВЎa de Zaragoza. Los entendidos dicen que iba pintado en amarillo. Lo que estв”ңГӯ claro es que no hay conflicto con el carretero que se le aproxima sin pestaв”ңв–’ear. Nadie saliв”ңв”Ӯ herido. Fuente visual: Imв”ңГӯgenes Antiguas de Zaragoza.', 1944, 1944, 1944, 'Anos 40', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20251541252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20251541252.webp', 'https://www.flickr.com/photos/zaragozaantigua/20251541252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21975, 'P.в”¬в•‘ del General Mola c.1940', 'Nв”¬в•‘ 64 del antiguo paseo de Sagasta, hotelito de Sв”ңГӯnchez Ventura diseв”ңв–’ado en 1927 por Josв”ңВ® y Regino Borobio con el sello de su particular interpretaciв”ңв”Ӯn regionalista del racionalismo arquitectв”ңв”Ӯnico de la в”ңВ®poca. A finales de la dв”ңВ®cada de los aв”ңв–’os 60, esta casa, a la derecha de la imagen, serв”ңГӯ derribada y sustituidas por un edificio residencial. A la derecha, su vecina del nв”¬в•‘ 62 del paseo, antigua Villa Dolores, correrв”ңГӯ igual suerte en los aв”ңв–’os 70. Fuente visual: foto Miguel Marв”ңВЎn Chivite, en "Regino y Josв”ңВ® Borobio: arquitectura y fotografв”ңВЎa. Zaragoza, 1923-1969", Iв”ңв–’aki Bergera y Daniel Estabв”ңВ®n, IFC, 2015.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.64051100, -0.88657200, '0101000020E6100000F793313ECC5EECBF37DDB243FCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24645864255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24645864255.webp', 'https://www.flickr.com/photos/zaragozaantigua/24645864255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22032, 'P.в”¬в•‘ de Ruiseв”ңв–’ores 1946', 'Inв”ңВ®dita imagen del Sanatorio neuro-psiquiв”ңГӯtrico de Santa Isabel reciв”ңВ®n inaugurado en el nв”¬в•‘ 3 del paseo de Ruiseв”ңв–’ores, que bajo la direcciв”ңв”Ӯn del prestigioso doctor Josв”ңВ® Marв”ңВЎa Juliв”ңГӯn Gil y la asistencia de las Hermanas de la Caridad de Santa Ana, tenв”ңВЎa capacidad para 30 enfermos "nerviosos y mentales". Este "magnв”ңВЎfico establecimiento mв”ңВ®dico" se ubicaba en el inmueble construido a principios de la dв”ңВ®cada para albergar el nuevo Colegio Alemв”ңГӯn que la completa derrota militar del rв”ңВ®gimen nazi en mayo de 1945 dejв”ңв”Ӯ sin ese uso, siendo "reciclado" como sanatorio un aв”ңв–’o despuв”ңВ®s. Al fondo y a la derecha, fachada del reciente inmueble del nв”¬в•‘ 9-11 del paseo de Cuв”ңВ®llar.', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63778500, -0.88653400, '0101000020E61000009758198D7C5EECBF8F705AF0A2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51793078755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51793078755.webp', 'https://www.flickr.com/photos/zaragozaantigua/51793078755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22194, 'Parroquia Perpetuo Socorro aв”ңв–’os 50', 'Foto: Miguel Marв”ңВЎn Chivite. Convento y parroquia de Nuestra Seв”ңв–’ora del Perpetuo Socorro, de la congregaciв”ңв”Ӯn del Santв”ңВЎsimo Redentor. Levantado en 1950 segв”ңв•‘n proyecto de Joaquв”ңВЎn Maggioni de 1947. Frente a ella, la trinchera del ferrocarril desde la estaciв”ңв”Ӯn Campo Sepulcro, cubierta a partir de 1960 para transformarse en avenida de Goya. Fuente: www.facebook.com/photo.php?fbid=10208803741877479&set...', 1950, 1950, 1959, 'Anos 50', 'UNIVERSIDAD', 41.64258400, -0.88730900, '0101000020E61000006F490ED8D564ECBF6877483140D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32807467093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32807467093.webp', 'https://www.flickr.com/photos/zaragozaantigua/32807467093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25083, 'Calle Domingo Miral 1964', 'Imagen capturada durante la ceremonia de colocaciв”ңв”Ӯn de la primera piedra de la Residencia de Estudiantes en el campus universitario de la plaza de San Francisco. En primer plano, el joven jefe nacional del oficial Sindicato Espaв”ңв–’ol Universitario, Rodolfo Martв”ңВЎn Villa. Aв”ңв–’os despuв”ңВ®s, serв”ңВЎa ministro en los gobiernos de Carlos Arias Navarro y Adolfo Suв”ңГӯrez, y vicepresidente en el de Leopoldo Calvo Sotelo. Posteriormente, continuв”ңв”Ӯ centrado en la tarea de hacer polв”ңВЎtica de alto nivel, por la vв”ңВЎa empresarial, a travв”ңВ®s de diversas corporaciones multinacionales. Al fondo de la imagen, la calle Domingo Miral, y el cuartel de Palafox. Dos sacerdotes garantizan la adecuada ortodoxia confesional del ceremonial. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.64056900, -0.90031900, '0101000020E610000023F59ECA69CFECBF6CEA3C2AFED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30642722294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30642722294.webp', 'https://www.flickr.com/photos/zaragozaantigua/30642722294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22218, 'Paseo de Cuв”ңВ®llar c.1951', 'Imagen capturada desde la altura del antiguo inmueble del nв”¬в•‘ 35 del paseo de Cuв”ңВ®llar, luego derribado y sustituido por un moderno bloque de viviendas, con una vista centrada en el Sacrario Militare Italiano, o "Torre Funeraria, Iglesia y Convento de Capuchinos en Zaragoza para Panteв”ңв”Ӯn de italianos muertos en la cruzada espaв”ңв–’ola y servicios de culto". La demediada torre (30 metros de altura de los previstos 60) e iglesia en el centro; el convento, a la derecha. A la izquierda e inmediato, tejado a doble altura del inmueble del 55-59 del paseo, donde estaban ubicadas las Escuelas de La Milagrosa, esquineras con la antigua cabaв”ңв–’era, moderna Vв”ңВЎa de San Fernando. Sobre el paseo maniobra una composiciв”ңв”Ӯn tranviaria de la lв”ңВЎnea 5. Torrero-Delicias (con unidad motor de la serie 60), posiblemente realizando un servicio corto entre la plaza de Aragв”ңв”Ӯn y la Playa de Torrero, de regreso hacia su norteв”ңв–’a terminal. Al fondo y a la izquierda, tras el puente de Amв”ңВ®rica destaca el veterano inmueble del nв”¬в•‘ 1 de la Vв”ңВЎa de Pignatelli, esquinero con el arranque de la avenida de Amв”ңВ®rica, por encima de las parcelas que caracterizaban la barriada de Venecia. En primer tв”ңВ®rmino, un carro tirado por caballerв”ңВЎa asciende hacia Torrero, calmo y sin agobios circulatorios.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.63543500, -0.88482800, '0101000020E61000000AB952CF8250ECBFECDD1FEF55D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48279199596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48279199596.webp', 'https://www.flickr.com/photos/zaragozaantigua/48279199596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
